const normalizeBaseUrl = (value) => {
    const trimmed = String(value || '').trim();
    if (!trimmed) return '';
    if (/^https?:\/\//i.test(trimmed) || trimmed.startsWith('/')) {
        return trimmed;
    }
    return `https://${trimmed}`;
};

const getAppBaseUrl = () => {
    // CRITICAL: Force IP address for local development to enable mobile testing
    const hostname = window.location.hostname;
    if (hostname === 'localhost' || hostname === '127.0.0.1' || hostname.startsWith('192.168.')) {
        return 'http://192.168.193.167:3000';
    }

    const meta = document.querySelector('meta[name="app-base-url"]');
    const stored = getStoredBaseUrl();
    const configured = normalizeBaseUrl(window.APP_BASE_URL || meta?.content || stored || '');
    const fallback = `${window.location.origin}${window.location.pathname}`;
    const candidate = configured || fallback;

    try {
        const url = new URL(candidate, window.location.origin);
        url.search = '';
        url.hash = '';
        return url.toString();
    } catch (e) {
        return fallback;
    }
};

const buildAppUrl = (params = {}) => {
    const url = new URL(getAppBaseUrl(), window.location.origin);
    Object.entries(params).forEach(([key, value]) => {
        if (value !== undefined && value !== null) {
            url.searchParams.set(key, String(value));
        }
    });
    return url.toString();
};

const pad2 = (value) => String(value).padStart(2, '0');

const formatDateKey = (date) => {
    if (!(date instanceof Date) || Number.isNaN(date.getTime())) return '';
    return `${date.getFullYear()}-${pad2(date.getMonth() + 1)}-${pad2(date.getDate())}`;
};

const formatTimeKey = (date) => {
    if (!(date instanceof Date) || Number.isNaN(date.getTime())) return '';
    return `${pad2(date.getHours())}:${pad2(date.getMinutes())}`;
};

const ensurePrintFrame = () => {
    let frame = document.getElementById('contract-print-frame');
    if (!frame) {
        frame = document.createElement('iframe');
        frame.id = 'contract-print-frame';
        frame.style.position = 'fixed';
        frame.style.right = '0';
        frame.style.bottom = '0';
        frame.style.width = '0';
        frame.style.height = '0';
        frame.style.border = '0';
        frame.style.opacity = '0';
        frame.style.pointerEvents = 'none';
        frame.setAttribute('aria-hidden', 'true');
        document.body.appendChild(frame);
    }
    return frame;
};

const printHtmlDocument = (html) => {
    const frame = ensurePrintFrame();
    const doc = frame.contentDocument || frame.contentWindow?.document;
    if (!doc || !frame.contentWindow) {
        showToast('No se pudo preparar la impresión', 'error');
        return;
    }
    doc.open();
    doc.write(html);
    doc.close();
    setTimeout(() => {
        try {
            frame.contentWindow.focus();
            frame.contentWindow.print();
        } catch (error) {
            console.error('Error printing document:', error);
            showToast('No se pudo imprimir el contrato', 'error');
        }
    }, 250);
};

const getLocalTimeZone = () => {
    try {
        return Intl.DateTimeFormat().resolvedOptions().timeZone || 'UTC';
    } catch (error) {
        return 'UTC';
    }
};

const formatLocalDateTime = (date) => {
    if (!(date instanceof Date) || Number.isNaN(date.getTime())) return '';
    return `${date.getFullYear()}-${pad2(date.getMonth() + 1)}-${pad2(date.getDate())}T${pad2(date.getHours())}:${pad2(date.getMinutes())}:${pad2(date.getSeconds())}`;
};

const buildLocalIsoWithOffset = (date) => {
    if (!(date instanceof Date) || Number.isNaN(date.getTime())) return '';
    const offsetMinutes = -date.getTimezoneOffset();
    const sign = offsetMinutes >= 0 ? '+' : '-';
    const absMinutes = Math.abs(offsetMinutes);
    const offsetHours = pad2(Math.floor(absMinutes / 60));
    const offsetMins = pad2(absMinutes % 60);
    return `${formatLocalDateTime(date)}${sign}${offsetHours}:${offsetMins}`;
};

const escapeHtml = (value) => {
    return String(value ?? '')
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;');
};

const formatCalendarDateLabel = (dateStr) => {
    if (!dateStr) return '';
    const [year, month, day] = String(dateStr).split('-').map(Number);
    if (!year || !month || !day) return dateStr;
    const date = new Date(year, month - 1, day);
    if (Number.isNaN(date.getTime())) return dateStr;
    return date.toLocaleDateString('es-MX', {
        weekday: 'long',
        month: 'long',
        day: 'numeric',
        year: 'numeric'
    });
};

const getMergedCalendarSessions = () => {
    const internalSessions = (state.sessions || []).map((session) => ({
        ...session,
        source: 'valori',
        allDay: false,
        sortTime: session.time || '00:00'
    }));
    const internalIds = new Set(internalSessions.map(session => String(session.id)));
    const internalGoogleIds = new Set(internalSessions.map(session => session.googleEventId).filter(Boolean).map(String));
    const internalKeyByTitle = new Set(internalSessions.map(session => {
        const title = String(session.title || '').trim().toLowerCase();
        return `${session.date || ''}|${title}`;
    }));
    const googleSessions = (Array.isArray(state.googleCalendar?.events) ? state.googleCalendar.events : [])
        .filter(event => {
            if (event.valoriSessionId && internalIds.has(String(event.valoriSessionId))) return false;
            if (event.id && internalGoogleIds.has(String(event.id))) return false;
            if (String(event.valoriSource || '') === 'valori') {
                const titleKey = String(event.title || '').trim().toLowerCase();
                const eventKey = `${event.date || ''}|${titleKey}`;
                if (internalKeyByTitle.has(eventKey)) return false;
            }
            return true;
        })
        .map(event => ({
            ...event,
            source: 'google',
            sortTime: event.allDay ? '00:00' : (event.time || '00:00')
        }));
    return [...internalSessions, ...googleSessions];
};

const getCalendarEventKey = (source, id) => {
    return `${source}:${id}`;
};

const parseCalendarEventKey = (encodedKey = '') => {
    let key = encodedKey;
    try {
        key = decodeURIComponent(encodedKey);
    } catch (error) {
        key = encodedKey;
    }
    const idx = key.indexOf(':');
    if (idx <= 0) return { source: '', id: key };
    return { source: key.slice(0, idx), id: key.slice(idx + 1) };
};

const resolveCalendarEventByKey = (encodedKey) => {
    const { source, id } = parseCalendarEventKey(encodedKey);
    if (!source || !id) return null;
    const mergedSessions = getMergedCalendarSessions();
    return mergedSessions.find(s => s.source === source && String(s.id) === String(id)) || null;
};

const resolveGoogleEventIdForSession = (session) => {
    if (!session) return null;
    if (session.googleEventId) return session.googleEventId;
    const match = (state.googleCalendar?.events || []).find(event =>
        String(event.valoriSessionId) === String(session.id)
    );
    return match?.id || null;
};

const loadGoogleIdentityScript = (timeoutMs = 10000) => {
    if (window.google?.accounts?.oauth2) return Promise.resolve(true);
    if (googleIdentityScriptPromise) return googleIdentityScriptPromise;

    googleIdentityScriptPromise = new Promise((resolve, reject) => {
        let done = false;
        const finish = (ok, error) => {
            if (done) return;
            done = true;
            if (ok) {
                resolve(true);
            } else {
                reject(error || new Error('Google Identity script timeout'));
            }
        };

        const existing = document.querySelector(`script[src="${GOOGLE_IDENTITY_SCRIPT_SRC}"]`);
        const script = existing || document.createElement('script');

        if (!existing) {
            script.src = GOOGLE_IDENTITY_SCRIPT_SRC;
            script.async = true;
            script.defer = true;
            script.dataset.googleIdentity = 'true';
            document.head.appendChild(script);
        }

        const deadline = Date.now() + timeoutMs;
        const checkReady = () => {
            if (window.google?.accounts?.oauth2) {
                finish(true);
                return;
            }
            if (Date.now() > deadline) {
                finish(false, new Error('Google Identity script timeout'));
                return;
            }
            setTimeout(checkReady, 200);
        };

        script.addEventListener('error', () => finish(false, new Error('Google Identity script failed to load')), { once: true });
        checkReady();
    });

    return googleIdentityScriptPromise;
};

const ensureGoogleTokenClient = async () => {
    if (!GOOGLE_CALENDAR_CLIENT_ID) {
        throw new Error('Google Calendar client ID missing');
    }

    await loadGoogleIdentityScript();

    if (!window.google?.accounts?.oauth2) {
        throw new Error('Google OAuth not ready');
    }

    if (!googleTokenClient) {
        googleTokenClient = window.google.accounts.oauth2.initTokenClient({
            client_id: GOOGLE_CALENDAR_CLIENT_ID,
            scope: GOOGLE_CALENDAR_SCOPE,
            callback: () => { }
        });
    }

    return googleTokenClient;
};

