const getSessionCoacheeOptionValue = (coachee) => {
    if (!coachee) return '';
    return coachee.id || coachee.userId || coachee.email || '';
};

const getSessionCoacheeOptionLabel = (coachee) => {
    if (!coachee) return 'Cliente';
    const name = (coachee.full_name || coachee.name || '').trim();
    const email = (coachee.email || '').trim();
    if (name && email) return `${name} (${email})`;
    return name || email || 'Cliente';
};

const buildSessionCoacheeOptions = (coachees = []) => {
    return (coachees || []).map(coachee => {
        const value = getSessionCoacheeOptionValue(coachee);
        if (!value) return '';
        const label = getSessionCoacheeOptionLabel(coachee);
        return `<option value="${value}">${label}</option>`;
    }).filter(Boolean).join('');
};

const resolveSessionCoacheeValue = (coacheeId) => {
    const key = String(coacheeId || '').trim();
    if (!key) return '';
    const match = (state.coachees || []).find(c => c?.id === key || c?.userId === key || c?.email === key);
    return match ? getSessionCoacheeOptionValue(match) : key;
};

const updateSessionModalOptions = () => {
    const select = document.getElementById('session-coachee-select');
    const bulkInfo = document.getElementById('bulk-contacts-info');
    const bulkList = document.getElementById('bulk-contacts-list');
    const bulkCount = document.getElementById('bulk-count');
    const singleSelect = document.getElementById('single-coachee-select');

    // Check if bulk mode
    if (state.bulkSessionContacts && state.bulkSessionContacts.length > 0) {
        // Show bulk contacts info
        if (bulkInfo) bulkInfo.style.display = 'block';
        if (singleSelect) singleSelect.style.display = 'none';

        // Populate bulk contacts list
        if (bulkList && bulkCount) {
            bulkCount.textContent = state.bulkSessionContacts.length;
            bulkList.innerHTML = state.bulkSessionContacts.map(contact => {
                const name = contact.full_name || contact.name || contact.email || 'Sin nombre';
                return `<li>${name}</li>`;
            }).join('');
        }

        // CRITICAL: Remove 'name' attribute to completely bypass browser validation
        // Disabled fields can still be validated by some browsers when hidden
        if (select) {
            select.removeAttribute('name');
            select.disabled = true;
            select.removeAttribute('required');
        }
    } else {
        // Hide bulk info, show normal select
        if (bulkInfo) bulkInfo.style.display = 'none';
        if (singleSelect) singleSelect.style.display = 'block';

        // Restore 'name' attribute, re-enable and make required
        if (select) {
            select.setAttribute('name', 'coacheeId');
            select.disabled = false;
            select.setAttribute('required', 'required');
        }

        // Populate dropdown options
        if (select) {
            const options = buildSessionCoacheeOptions(state.coachees || []);
            select.innerHTML = '<option value="">Seleccionar Cliente...</option>' + options;
        }
    }
};


