const buildAnnualBudgetGroup = (defaults, existing = []) => {
    const existingByKey = new Map();
    (existing || []).forEach(item => {
        if (item && item.key) existingByKey.set(item.key, item);
    });

    return defaults.map(def => {
        const saved = existingByKey.get(def.key) || (existing || []).find(item => item?.label === def.label);
        return {
            key: def.key,
            label: def.label,
            mxn: Number(saved?.mxn) || 0,
            usd: Number(saved?.usd) || 0
        };
    });
};

const ensureBusinessAnnualBudget = () => {
    if (!state.businessData) state.businessData = {};
    if (!state.businessData.annualBudget) state.businessData.annualBudget = {};

    const annualBudget = state.businessData.annualBudget;
    annualBudget.expenses = buildAnnualBudgetGroup(BUSINESS_ANNUAL_EXPENSE_CATEGORIES, annualBudget.expenses);
    annualBudget.payroll = buildAnnualBudgetGroup(BUSINESS_ANNUAL_PAYROLL_CATEGORIES, annualBudget.payroll);

    return annualBudget;
};

