// --- ESTADO REACTIVO ---
// State is now imported from store.js to ensure singleton pattern
// const state = { ... };

// --- UTILS ---
const getCategorySkipState = (cat) => {
    if (!cat) return { skip: false };
    const intro = cat.introQuestion;
    if (!intro || !intro.options) return { skip: false };
    const selected = state.answers?.[cat.id]?.[intro.id];
    if (typeof selected !== 'number') return { skip: false };
    const opt = intro.options[selected];
    return { skip: !!opt?.triggers_skip_section, selectedOption: opt || null };
};

const getProgress = () => {
    let answeredCount = 0;
    let totalQuestions = 0;
    QUIZ_DATA.forEach(cat => {
        const answers = state.answers[cat.id] || {};
        const intro = cat.introQuestion;
        const { skip } = getCategorySkipState(cat);
        const requiredCount = (intro ? 1 : 0) + (skip ? 0 : cat.questions.length);

        totalQuestions += requiredCount;

        if (intro && answers[intro.id] !== undefined) {
            answeredCount += 1;
        }
        if (!skip) {
            answeredCount += cat.questions.filter((_, qIndex) => answers[qIndex] !== undefined).length;
        }
    });
    return totalQuestions > 0 ? Math.round((answeredCount / totalQuestions) * 100) : 0;
};

const isCategoryComplete = (index) => {
    const cat = QUIZ_DATA[index];
    const answers = state.answers[cat.id];
    if (!answers) return false;
    const intro = cat.introQuestion;
    if (intro && answers[intro.id] === undefined) return false;
    const { skip } = getCategorySkipState(cat);
    if (skip) return true;
    return cat.questions.every((_, qIndex) => answers[qIndex] !== undefined);
};

const calculateScore = () => {
    let total = 0;
    let max = 0;
    QUIZ_DATA.forEach(cat => {
        if (cat.is_scored === false) return;
        cat.questions.forEach((q, qIdx) => {
            const val = state.answers[cat.id]?.[qIdx];
            if (typeof val === 'number') {
                // If it's a money input, we don't add it to the score unless specifically handled
                if (q.type === 'money') return;

                total += val;
                max += 2; // Assuming max points per standard question is 2 (2, 1, 0)
            }
        });
    });
    return max > 0 ? Math.round((total / max) * 10) : 0;
};

const calculateBudgetTotals = () => {
    const totals = { incomes: { m1: 0, m2: 0, m3: 0, avg: 0 }, fixed: { m1: 0, m2: 0, m3: 0, avg: 0 }, variable: { m1: 0, m2: 0, m3: 0, avg: 0 }, debt: { m1: 0, m2: 0, m3: 0, avg: 0 }, savings: { m1: 0, m2: 0, m3: 0, avg: 0 } };

    Object.keys(state.budgetData).forEach(cat => {
        state.budgetData[cat].forEach(item => {
            totals[cat].m1 += Number(item.m1) || 0;
            totals[cat].m2 += Number(item.m2) || 0;
            totals[cat].m3 += Number(item.m3) || 0;
        });
        totals[cat].avg = (totals[cat].m1 + totals[cat].m2 + totals[cat].m3) / 3;
    });

    const totalIncome = totals.incomes.avg || 1; // Avoid division by zero
    const percentages = {
        fixed: (totals.fixed.avg / totalIncome) * 100,
        variable: (totals.variable.avg / totalIncome) * 100,
        debt: (totals.debt.avg / totalIncome) * 100,
        savings: (totals.savings.avg / totalIncome) * 100
    };

    return { totals, percentages };
};

// --- TRANSACTION UTILS ---
const categorizeTransaction = (description) => {
    const desc = description.toLowerCase();
    for (const [categoryName, categoryData] of Object.entries(TRANSACTION_CATEGORIES)) {
        for (const keyword of categoryData.keywords) {
            if (desc.includes(keyword.toLowerCase())) {
                return categoryName;
            }
        }
    }
    return '?? Otros'; // Default category
};

const parseCSVTransactions = (csvText) => {
    return new Promise((resolve, reject) => {
        Papa.parse(csvText, {
            header: true,
            skipEmptyLines: true,
            complete: (results) => {
                const transactions = results.data.map((row, index) => {
                    // Flexible column mapping for BBVA and other banks
                    const fecha = row.Fecha || row.FECHA || row['Fecha Operación'] || row.fecha || '';
                    const descripcion = row.Descripcion || '';
                    const cargo = parseFloat(row.Cargo || row.CARGO || row.Cargos || row.CARGOS || 0);
                    const abono = parseFloat(row.Abono || row.ABONO || row.Abonos || row.ABONOS || 0);

                    const monto = abono > 0 ? abono : -cargo;
                    const tipo = monto > 0 ? 'ingreso' : 'gasto';
                    const category = categorizeTransaction(descripcion);

                    return {
                        id: `txn-${Date.now()}-${index}`,
                        fecha,
                        descripcion,
                        monto,
                        tipo,
                        category,
                        categoryColor: TRANSACTION_CATEGORIES[category]?.color || 'gray-500',
                        categoryIcon: TRANSACTION_CATEGORIES[category]?.icon || 'help-circle'
                    };
                }).filter(t => t.monto !== 0); // Remove zero transactions

                resolve(transactions);
            },
            error: (error) => reject(error)
        });
    });
};

const analyzeSpendingTrends = () => {
    const byCategory = {};
    const byMonth = {};

    state.transactions.forEach(txn => {
        // By category
        if (!byCategory[txn.category]) {
            byCategory[txn.category] = {
                total: 0,
                count: 0,
                transactions: []
            };
        }
        byCategory[txn.category].total += Math.abs(txn.monto);
        byCategory[txn.category].count++;
        byCategory[txn.category].transactions.push(txn);

        // By month
        if (txn.fecha) {
            const month = txn.fecha.substring(0, 7); // YYYY-MM
            if (!byMonth[month]) {
                byMonth[month] = {
                    total: 0,
                    income: 0,
                    expenses: 0
                };
            }
            if (txn.tipo === 'ingreso') {
                byMonth[month].income += txn.monto;
            } else {
                byMonth[month].expenses += Math.abs(txn.monto);
            }
            byMonth[month].total = byMonth[month].income - byMonth[month].expenses;
        }
    });

    return { byCategory, byMonth };
};

const getFilteredTransactions = () => {
    return state.transactions.filter(txn => {
        const matchesCategory = state.transactionFilters.category === 'all' || txn.category === state.transactionFilters.category;
        const matchesSearch = !state.transactionFilters.searchTerm ||
            txn.descripcion.toLowerCase().includes(state.transactionFilters.searchTerm.toLowerCase());
        return matchesCategory && matchesSearch;
    });
};

// Partículas de fondo
let animationId;
const initParticles = () => {
    const canvas = document.getElementById('particle-canvas');
    const ctx = canvas.getContext('2d');
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;

    const particles = [];
    const particleCount = 50;

    class Particle {
        constructor() {
            this.x = Math.random() * canvas.width;
            this.y = Math.random() * canvas.height;
            this.size = Math.random() * 2 + 0.5;
            this.speedX = Math.random() * 0.5 - 0.25;
            this.speedY = Math.random() * 0.5 - 0.25;
            this.color = Math.random() > 0.5 ? '#cde52d' : '#0d85fa'; // Brand colors
        }
        update() {
            this.x += this.speedX;
            this.y += this.speedY;
            if (this.x > canvas.width) this.x = 0;
            if (this.x < 0) this.x = canvas.width;
            if (this.y > canvas.height) this.y = 0;
            if (this.y < 0) this.y = canvas.height;
        }
        draw() {
            ctx.fillStyle = this.color;
            ctx.beginPath();
            ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
            ctx.fill();
        }
    }

    for (let i = 0; i < particleCount; i++) particles.push(new Particle());

    const animate = () => {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        particles.forEach(p => { p.update(); p.draw(); });
        animationId = requestAnimationFrame(animate);
    };
    animate();
};

