const renderPlanAhorroRows = () => {
    const months = [
        'Enero', 'Febrero', 'Marzo', 'Abril', 'Mayo', 'Junio',
        'Julio', 'Agosto', 'Septiembre', 'Octubre', 'Noviembre', 'Diciembre'
    ];

    // Mock Data based on Image 2
    const data = [
        [150, 6465, 21, 1252], // Enero
        [200, 6189, 213, 111], // Febrero
        [55, 234, 250, 451],   // Marzo
        [666, 425, 2322, 215], // Abril
        [546, 0, 150, 5238],   // Mayo
        [500, 0, 25, 0],       // Junio
        [685, 0, 0, 0],        // Julio
        [152, 0, 0, 0],        // Agosto
        [235, 0, 0, 0],        // Septiembre
        [2512, 0, 0, 0],       // Octubre
        [12522, 0, 0, 0],      // Noviembre
        [211, 0, 0, 0]         // Diciembre
    ];

    return months.map((month, i) => {
        const row = data[i] || [0, 0, 0, 0];
        const rowTotal = row.reduce((a, b) => a + b, 0);

        return `
    <tr class="hover:bg-zinc-50 dark:hover:bg-zinc-800/30 transition-colors">
        <td class="p-3 font-medium text-zinc-900 dark:text-white border-r border-zinc-100 dark:border-zinc-800">${month.toUpperCase()}</td>
            ${row.map(val => `
                <td class="p-3 text-right text-zinc-600 dark:text-zinc-400 border-r border-zinc-100 dark:border-zinc-800">
                    ${val > 0 ? '$' + val.toLocaleString('en-US', { minimumFractionDigits: 2 }) : '-'}
                </td>
            `).join('')
            }
<td class="p-3 text-right font-bold text-zinc-900 bg-zinc-900 text-white border-l border-zinc-800">
    $${rowTotal.toLocaleString('en-US', { minimumFractionDigits: 2 })}
</td>
        </tr>
    `;
    }).join('');
};

// Helper for consistent card design
const renderMenuCard = ({ title, desc, icon, color, action }) => {
    const colors = {
        lime: 'text-brand-lime bg-lime-100 dark:bg-brand-lime/10',
        blue: 'text-brand-blue bg-blue-100 dark:bg-brand-blue/10',
        purple: 'text-purple-600 dark:text-purple-400 bg-purple-100 dark:bg-purple-900/20',
        orange: 'text-orange-600 dark:text-orange-400 bg-orange-100 dark:bg-orange-900/20',
        emerald: 'text-emerald-600 dark:text-emerald-400 bg-emerald-100 dark:bg-emerald-900/20',
        sky: 'text-sky-600 dark:text-sky-400 bg-sky-100 dark:bg-sky-900/20',
        indigo: 'text-indigo-600 dark:text-indigo-400 bg-indigo-100 dark:bg-indigo-900/20',
        pink: 'text-pink-600 dark:text-pink-400 bg-pink-100 dark:bg-pink-900/20',
        zinc: 'text-zinc-600 dark:text-zinc-400 bg-zinc-100 dark:bg-zinc-800',
    };

    // Default to zinc if color not found
    const theme = colors[color] || colors.zinc;

    return `
    <div onclick="${action}" class="group bg-white dark:bg-zinc-900/50 backdrop-blur-sm border border-zinc-200 dark:border-zinc-800 p-4 sm:p-6 rounded-xl sm:rounded-2xl hover:border-zinc-300 dark:hover:border-zinc-700 transition-all duration-300 hover:shadow-xl active:scale-[0.98] cursor-pointer flex flex-col h-full relative overflow-hidden">
        <div class="absolute top-0 right-0 p-4 opacity-[0.03] group-hover:opacity-10 transition-opacity transform scale-150 translate-x-4 -translate-y-4 hidden sm:block">
             <i data-lucide="${icon}" width="120" height="120"></i>
        </div>

        <div class="w-10 h-10 sm:w-12 sm:h-12 rounded-lg sm:rounded-xl ${theme} flex items-center justify-center mb-3 sm:mb-4 transition-colors">
            <i data-lucide="${icon}" width="20"></i>
        </div>

        <h3 class="text-sm sm:text-lg font-bold text-zinc-900 dark:text-white mb-1 sm:mb-2 leading-tight">${title}</h3>
        <p class="text-xs sm:text-sm text-zinc-500 dark:text-zinc-400 leading-relaxed mb-3 sm:mb-4 flex-grow hidden sm:block">${desc}</p>

        <div class="flex items-center text-xs font-bold uppercase tracking-wide opacity-0 group-hover:opacity-100 transition-all transform translate-y-2 group-hover:translate-y-0 text-zinc-400 hover:text-brand-blue hidden sm:flex">
            Ingresar <i data-lucide="arrow-right" class="ml-1 w-3 h-3"></i>
        </div>
    </div>
    `;
};
