const evaluateBalanceExpenseRatio = (balanceAnswers = [], balanceQuestions = []) => {
    const incomeIdx = balanceQuestions.findIndex(q => q.id === 'q_ingreso_valor');
    const gastosIdx = balanceQuestions.findIndex(q => q.id === 'q_gastos_v_ingresos');
    if (gastosIdx < 0) return null;

    const rawExpenses = balanceAnswers?.[gastosIdx];
    if (rawExpenses === undefined || rawExpenses === null || rawExpenses === '') return null;

    const expenses = Number(rawExpenses);
    if (!Number.isFinite(expenses) || expenses < 0) return null;

    const rawIncome = incomeIdx >= 0 ? balanceAnswers?.[incomeIdx] : undefined;
    const income = Number(rawIncome);
    if (rawIncome === undefined || rawIncome === null || rawIncome === '' || !Number.isFinite(income) || income <= 0) {
        return {
            expenses,
            income: Number.isFinite(income) ? income : null,
            percent: null,
            points: null,
            feedback: 'Falta registrar tu ingreso mensual para calcular el porcentaje.'
        };
    }

    const percent = (expenses / income) * 100;
    let points = 0;
    let feedback = '';

    if (percent < 50) {
        points = 5;
        feedback = '¡Excelente!';
    } else if (percent <= 70) {
        points = 3;
        feedback = 'Ojo tus gastos estan por encima de lo adecuado';
    } else {
        points = 0;
        feedback = 'Ojo tus gastos son poco saludables para tus finanzas';
    }

    return { expenses, income, percent, points, feedback };
};

const getMonthlyIncomeValue = () => {
    const balanceCat = QUIZ_DATA.find(c => c.id === 'balance');
    if (!balanceCat) return null;
    const incomeIdx = balanceCat.questions.findIndex(q => q.id === 'q_ingreso_valor');
    const rawIncome = state.answers['balance']?.[incomeIdx];
    if (rawIncome === undefined || rawIncome === null || rawIncome === '') return null;
    const income = Number(rawIncome);
    if (!Number.isFinite(income) || income <= 0) return null;
    return income;
};

const evaluateSavingsRatio = (savingsAnswers = [], savingsQuestions = []) => {
    const savingsIdx = savingsQuestions.findIndex(q => q.id === 'q_porcentaje_ahorro');
    if (savingsIdx < 0) return null;

    const rawSavings = savingsAnswers?.[savingsIdx];
    if (rawSavings === undefined || rawSavings === null || rawSavings === '') return null;

    const savings = Number(rawSavings);
    if (!Number.isFinite(savings) || savings < 0) return null;

    const income = getMonthlyIncomeValue();
    if (!income) {
        return {
            savings,
            income: null,
            percent: null,
            points: null,
            feedback: 'Falta registrar tu ingreso mensual para calcular el porcentaje.'
        };
    }

    const percent = (savings / income) * 100;
    let points = 0;
    let feedback = '';

    if (percent >= 20) {
        points = 5;
        feedback = '¡Excelente! tu porcentaje de ahorro es muy bueno';
    } else if (percent >= 10) {
        points = 3;
        feedback = 'Tu % de ahorro es bueno pero puede mejorar';
    } else {
        points = 0;
        feedback = 'Ojo necesitas mejorar tu % de ahorro';
    }

    return { savings, income, percent, points, feedback };
};

const evaluateDebtRatio = (debtAnswers = [], debtQuestions = []) => {
    const debtIdx = debtQuestions.findIndex(q => q.id === 'q_proporcion_deuda');
    if (debtIdx < 0) return null;

    const rawDebt = debtAnswers?.[debtIdx];
    if (rawDebt === undefined || rawDebt === null || rawDebt === '') return null;

    const debt = Number(rawDebt);
    if (!Number.isFinite(debt) || debt < 0) return null;

    const income = getMonthlyIncomeValue();
    if (!income) {
        return {
            debt,
            income: null,
            percent: null,
            points: null,
            feedback: 'Falta registrar tu ingreso mensual para calcular el porcentaje.'
        };
    }

    const percent = (debt / income) * 100;
    let points = 0;
    let feedback = '';

    if (percent <= 30) {
        points = 5;
        feedback = '¡Excelente! tu nivel de deuda esta controlado';
    } else if (percent <= 60) {
        points = 3;
        feedback = 'Ojo tu deuda se categoriza como deuda alarma';
    } else {
        points = 0;
        feedback = 'Ojo tu deuda se categoriza como deuda peligrosa';
    }

    return { debt, income, percent, points, feedback };
};

