                             <div class="flex gap-1 bg-zinc-100 dark:bg-zinc-800 p-1 rounded-lg">
                                <button onclick="actions.setContactsTab('active')" class="px-4 py-1.5 rounded-md text-sm font-bold transition-all ${contactsTab === 'active' ? 'bg-white dark:bg-zinc-700 shadow-sm text-zinc-900 dark:text-white' : 'text-zinc-500 hover:text-zinc-900 dark:hover:text-white'}">Activos</button>
                                <button onclick="actions.setContactsTab('archived')" class="px-4 py-1.5 rounded-md text-sm font-bold transition-all ${contactsTab === 'archived' ? 'bg-white dark:bg-zinc-700 shadow-sm text-zinc-900 dark:text-white' : 'text-zinc-500 hover:text-zinc-900 dark:hover:text-white'}">Archivados</button>
                            </div>
