                            <button onclick="actions.shiftCoachCalendar(1)" class="bg-white dark:bg-zinc-800 p-2 rounded-lg border border-zinc-200 dark:border-zinc-700 hover:bg-zinc-50"><i data-lucide="chevron-right" width="20"></i></button>
