const renderBusinessTransactions = () => {
    // Sort transactions by date desc
    const sortedTxns = [...state.businessData.transactions].sort((a, b) => new Date(b.date) - new Date(a.date));
    const readOnly = isBusinessReadOnly();

    // Ensure config exists and has defaults
    if (!state.businessData.config.costCategories) {
        state.businessData.config.costCategories = ['Mano de Obra Directa', 'Materia Prima Directa', 'Costos de Fabricación'];
    }
    const { config } = state.businessData;

    // --- FILTER LOGIC ---
    const months = ['Enero', 'Febrero', 'Marzo', 'Abril', 'Mayo', 'Junio', 'Julio', 'Agosto', 'Septiembre', 'Octubre', 'Noviembre', 'Diciembre'];
    // Default to current month if not set, or 'all' if user prefers. Let's filter by current month by default as per common UX, or 'all'.
    // User request: "coloca un filtro por meses ... dependiendo del mes que eliga el usuario".
    // Let's interpret "all" as an option too, but maybe default to current month?
    // "Default to 'all'" usually shows everything.
    if (state.businessData.txnMonthFilter === undefined) state.businessData.txnMonthFilter = 'all';

    const currentFilter = state.businessData.txnMonthFilter;

    // Ensure state.businessData.filters exists
    if (!state.businessData.filters) {
        state.businessData.filters = { dateFrom: '', dateTo: '', type: '', category: '', status: '', bank: '' };
    }
    const bFilters = state.businessData.filters;

    const filteredTxns = sortedTxns.filter(t => {
        if (!t.date) return false;

        // Original Month Filter (only applied if we don't have custom date range)
        if (!bFilters.dateFrom && !bFilters.dateTo) {
            if (currentFilter !== 'all') {
                const mIndex = parseInt(t.date.split('-')[1]) - 1;
                if (mIndex !== parseInt(currentFilter)) return false;
            }
        }

        // New Advanced Filters
        // Date Range
        if (bFilters.dateFrom && t.date < bFilters.dateFrom) return false;
        if (bFilters.dateTo && t.date > bFilters.dateTo) return false;

        // Type Filter (t.type)
        if (bFilters.type && t.type !== bFilters.type) return false;

        // Category Filter
        if (bFilters.category && t.category !== bFilters.category) return false;

        // Status Filter
        if (bFilters.status) {
            const status = (t.status || 'Pendiente').toLowerCase();
            if (status !== bFilters.status.toLowerCase()) return false;
        }

        // Bank Filter
        if (bFilters.bank && (t.bank || '') !== bFilters.bank) return false;

        return true;
    });

    // Populate filter options dynamically based on ALL transactions (or just sortedTxns)
    const uniqueTypes = [...new Set(sortedTxns.map(t => t.type).filter(Boolean))];
    const categorySource = bFilters.type
        ? sortedTxns.filter(t => t.type === bFilters.type && t.category)
        : sortedTxns.filter(t => t.category);
    const uniqueCategories = [...new Set(categorySource.map(t => t.category).filter(Boolean))].sort();
    if (bFilters.category && !uniqueCategories.includes(bFilters.category)) {
        bFilters.category = '';
    }
    const uniqueStatuses = [...new Set(sortedTxns.map(t => t.status ? t.status.toLowerCase() : 'pendiente'))].sort();
    const uniqueBanks = [...new Set(sortedTxns.map(t => t.bank).filter(Boolean))].sort();

    // The advanced filters UI
    const advancedFiltersUI = `
        <div class="mb-8 flex flex-wrap gap-3 items-center bg-zinc-50 dark:bg-zinc-800/50 p-3 rounded-xl border border-zinc-200 dark:border-zinc-700">
            <div class="flex items-center gap-2">
                <span class="text-xs font-bold text-zinc-500 uppercase">Desde:</span>
                <input type="date" value="${bFilters.dateFrom}" onchange="state.businessData.filters.dateFrom = this.value; updateUI()" class="bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-700 rounded-lg px-2 py-1 text-sm focus:ring-brand-lime focus:border-brand-lime">
            </div>
            <div class="flex items-center gap-2">
                <span class="text-xs font-bold text-zinc-500 uppercase">Hasta:</span>
                <input type="date" value="${bFilters.dateTo}" onchange="state.businessData.filters.dateTo = this.value; updateUI()" class="bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-700 rounded-lg px-2 py-1 text-sm focus:ring-brand-lime focus:border-brand-lime">
            </div>
            <select onchange="state.businessData.filters.type = this.value; updateUI()" class="bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-700 rounded-lg px-3 py-1.5 text-sm focus:ring-brand-lime focus:border-brand-lime min-w-[120px]">
                <option value="">Todos los Tipos</option>
                ${uniqueTypes.map(t => `<option value="${t}" ${bFilters.type === t ? 'selected' : ''}>${t === 'INCOME' ? 'Ingreso' : t === 'COST' ? 'Costo' : t === 'EXPENSE' ? 'Gasto' : t}</option>`).join('')}
            </select>
            <select onchange="state.businessData.filters.category = this.value; updateUI()" class="bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-700 rounded-lg px-3 py-1.5 text-sm focus:ring-brand-lime focus:border-brand-lime min-w-[140px]">
                <option value="">Todas las Categorías</option>
                ${uniqueCategories.map(c => `<option value="${escapeHtml(c)}" ${bFilters.category === c ? 'selected' : ''}>${escapeHtml(c)}</option>`).join('')}
            </select>
            <select onchange="state.businessData.filters.status = this.value; updateUI()" class="bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-700 rounded-lg px-3 py-1.5 text-sm focus:ring-brand-lime focus:border-brand-lime min-w-[120px]">
                <option value="">Todos los Estados</option>
                <option value="pendiente" ${bFilters.status === 'pendiente' ? 'selected' : ''}>Pendiente</option>
                <option value="abonado" ${bFilters.status === 'abonado' ? 'selected' : ''}>Abonado</option>
                <option value="pagado" ${bFilters.status === 'pagado' ? 'selected' : ''}>Pagado</option>
            </select>
            <select onchange="state.businessData.filters.bank = this.value; updateUI()" class="bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-700 rounded-lg px-3 py-1.5 text-sm focus:ring-brand-lime focus:border-brand-lime min-w-[120px]">
                <option value="">Todos los Bancos</option>
                ${uniqueBanks.map(b => `<option value="${escapeHtml(b)}" ${bFilters.bank === b ? 'selected' : ''}>${escapeHtml(b)}</option>`).join('')}
            </select>
            <button onclick="state.businessData.filters = { dateFrom: '', dateTo: '', type: '', category: '', status: '', bank: '' }; updateUI()" class="text-xs font-bold text-zinc-500 hover:text-red-500 transition-colors px-2 py-1">
                Limpiar Filtros
            </button>
        </div>
    `;

    // --- LOGIC FOR DEFAULT DATE IN 'ADD TRANSACTION' MODAL ---
    let defaultTxnDate = new Date(Date.now() - new Date().getTimezoneOffset() * 60000).toISOString().split('T')[0];
    const now = new Date();
    const currentYear = now.getFullYear();
    const currentMonthIndex = now.getMonth();

    if (currentFilter !== 'all') {
        const targetMonthIndex = parseInt(currentFilter);
        // If the selected month is DIFFERENT from the current real-world month, default to the 1st of that month
        if (targetMonthIndex !== currentMonthIndex) {
            // Constuct date: Current Year, Target Month, Day 1
            // Note: We need YYYY-MM-DD format.
            const m = String(targetMonthIndex + 1).padStart(2, '0');
            defaultTxnDate = `${currentYear}-${m}-01`;
        }
        // If selected IS current month, let it be today's date (which is already set as default)
    }

    // --- SUMMARY CALCULATIONS (Based on FILTERED Data) ---
    const summary = {
        plansSold: {}, // { category: { count, mxn, usd } }
        financials: {
            income: { bankMXN: 0, cashMXN: 0, bankUSD: 0, cashUSD: 0, totalMXN: 0, totalUSD: 0 },
            outflow: { bankMXN: 0, cashMXN: 0, bankUSD: 0, cashUSD: 0, totalMXN: 0, totalUSD: 0 } // Costs + Expenses
        },
        costsByCategory: {}, // { category: { count, mxn, usd } }
        expensesByCategory: {}, // { category: { count, mxn, usd } }
    };

    const accounts = {
        receivable: { mxn: 0, usd: 0 },
        payable: { mxn: 0, usd: 0 }
    };

    filteredTxns.forEach(t => {
        // Cash logic: "Efectivo" if paymentMethod OR bank says so (for backward compatibility or explicit bank choice)
        const isCash = (t.paymentMethod || '').toLowerCase() === 'efectivo' || (t.bank || '').toLowerCase() === 'efectivo';
        const mxn = Number(t.amountMXN) || 0;
        const usd = Number(t.amountUSD) || 0;
        const status = (t.status || 'Pendiente').toLowerCase();
        const isPending = status === 'pendiente';

        if (!isPending && t.type === 'INCOME') {
            // Plans Sold (Income by Category)
            if (!summary.plansSold[t.category]) summary.plansSold[t.category] = { count: 0, mxn: 0, usd: 0 };
            summary.plansSold[t.category].count++;
            summary.plansSold[t.category].mxn += mxn;
            summary.plansSold[t.category].usd += usd;

            // Financials
            if (isCash) {
                summary.financials.income.cashMXN += mxn;
                summary.financials.income.cashUSD += usd;
            } else {
                summary.financials.income.bankMXN += mxn;
                summary.financials.income.bankUSD += usd;
            }
            summary.financials.income.totalMXN += mxn;
            summary.financials.income.totalUSD += usd;

        } else if (!isPending && (t.type === 'COST' || t.type === 'EXPENSE')) {
            // Financials (Outflows)
            if (isCash) {
                summary.financials.outflow.cashMXN += mxn;
                summary.financials.outflow.cashUSD += usd;
            } else {
                summary.financials.outflow.bankMXN += mxn;
                summary.financials.outflow.bankUSD += usd;
            }
            summary.financials.outflow.totalMXN += mxn;
            summary.financials.outflow.totalUSD += usd;

            // Category Breakdown
            const targetMap = t.type === 'COST' ? summary.costsByCategory : summary.expensesByCategory;
            if (!targetMap[t.category]) targetMap[t.category] = { count: 0, mxn: 0, usd: 0 };
            targetMap[t.category].count++;
            targetMap[t.category].mxn += mxn;
            targetMap[t.category].usd += usd;
        }

        if (status === 'pendiente') {
            if (t.type === 'INCOME') {
                accounts.receivable.mxn += mxn;
                accounts.receivable.usd += usd;
            } else {
                accounts.payable.mxn += mxn;
                accounts.payable.usd += usd;
            }
        }
    });

    const formatCurrency = (val, currency) => val.toLocaleString(currency === 'MXN' ? 'es-MX' : 'en-US', { style: 'currency', currency });

    // --- HTML RENDER ---
    return `
    <div class="flex flex-col md:flex-row justify-between items-start md:items-end mb-6 gap-4">
        <div>
            <h2 class="text-3xl font-black text-zinc-900 dark:text-white mb-2">Transacciones</h2>
            <p class="text-zinc-500">Registro diario de ingresos y egresos.</p>
        </div>
        <div class="flex gap-2">
            <button onclick="document.getElementById('txn-summary-modal').showModal()" class="bg-zinc-900 dark:bg-zinc-100 dark:text-zinc-900 text-white px-6 py-3 rounded-xl font-bold shadow-lg flex items-center gap-2 hover:bg-zinc-800 dark:hover:bg-zinc-200 transition-colors">
                <i data-lucide="bar-chart-2" width="20"></i>
                Ver Resumen
            </button>
            ${readOnly ? '' : `
            <button onclick="document.getElementById('add-txn-modal').showModal()" class="bg-sky-500 hover:bg-sky-600 text-white px-6 py-3 rounded-xl font-bold shadow-lg shadow-sky-500/20 flex items-center gap-2 transition-colors">
                <i data-lucide="plus-circle" width="20"></i>
                Nueva Transacción
            </button>
            `}
        </div>
    </div>

    <!-- MONTH FILTER -->
    <div class="mb-4 flex overflow-x-auto pb-2 gap-2 custom-scrollbar">
        <button onclick="state.businessData.txnMonthFilter = 'all'; updateUI()" 
                class="px-4 py-2 rounded-full text-sm font-bold whitespace-nowrap transition-all ${currentFilter === 'all' ? 'bg-zinc-900 text-white dark:bg-white dark:text-black' : 'bg-white border border-zinc-200 text-zinc-600 hover:bg-zinc-50 dark:bg-zinc-900 dark:border-zinc-800 dark:text-zinc-400'}">
            Todos
        </button>
        ${months.map((m, i) => `
            <button onclick="state.businessData.txnMonthFilter = '${i}'; updateUI()" 
                    class="px-4 py-2 rounded-full text-sm font-bold whitespace-nowrap transition-all ${parseInt(currentFilter) === i ? 'bg-zinc-900 text-white dark:bg-white dark:text-black' : 'bg-white border border-zinc-200 text-zinc-600 hover:bg-zinc-50 dark:bg-zinc-900 dark:border-zinc-800 dark:text-zinc-400'}">
                ${m}
            </button>
        `).join('')}
    </div>
    ${advancedFiltersUI}



    <!-- SUMMARY MODAL (POP OUT) -->
    <dialog id="txn-summary-modal" class="modal bg-transparent p-0 w-full max-w-5xl backdrop:bg-black/80">
        <div class="bg-white dark:bg-zinc-900 text-zinc-900 dark:text-white rounded-3xl shadow-2xl overflow-hidden w-full max-h-[90vh] overflow-y-auto">
            <div class="p-4 flex justify-between items-center bg-zinc-50 dark:bg-zinc-800 border-b border-zinc-200 dark:border-zinc-700 sticky top-0 z-10">
                <h3 class="font-black text-xl text-zinc-900 dark:text-white uppercase tracking-wider flex items-center gap-2">
                    <i data-lucide="bar-chart-2" class="text-brand-lime"></i> Resumen: ${currentFilter === 'all' ? 'Histórico' : months[currentFilter]}
                </h3>
                <form method="dialog">
                    <button class="p-2 rounded-full hover:bg-zinc-200 dark:hover:bg-zinc-700 text-zinc-500 transition-colors">
                        <i data-lucide="x" width="24"></i>
                    </button>
                </form>
            </div>
            
            <div class="p-6 md:p-8 space-y-8">
                <!-- RESÚMEN DASHBOARD CONTENT -->
                <div class="grid grid-cols-1 lg:grid-cols-12 gap-6">
                    
                    <!-- PLANES VENDIDOS (Left - 7 cols) -->
                    <div class="lg:col-span-7 bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-800 rounded-2xl shadow-sm overflow-hidden flex flex-col">
                        <div class="bg-brand-lime text-black font-bold p-3 text-center uppercase text-sm tracking-wider border-b border-lime-400">
                            PLANES VENDIDOS
                        </div>
                        <div class="overflow-x-auto">
                            <table class="w-full text-sm">
                                <thead class="bg-zinc-100 dark:bg-zinc-800 text-xs font-bold uppercase text-zinc-600 dark:text-zinc-400">
                                    <tr>
                                        <th class="p-3 text-left">NOMBRE</th>
                                        <th class="p-3 text-center">CANTIDAD</th>
                                        <th class="p-3 text-right">TOTAL PESOS</th>
                                        <th class="p-3 text-right">TOTAL DOLARES</th>
                                    </tr>
                                </thead>
                                <tbody class="divide-y divide-zinc-100 dark:divide-zinc-800">
                                    ${Object.entries(summary.plansSold).length === 0 ? '<tr><td colspan="4" class="p-4 text-center text-zinc-400 text-xs">Sin registros</td></tr>' :
            Object.entries(summary.plansSold).map(([cat, data]) => `
                                        <tr class="hover:bg-zinc-50 dark:hover:bg-zinc-800/50">
                                            <td class="p-3 font-medium">${cat}</td>
                                            <td class="p-3 text-center font-mono">${data.count}</td>
                                            <td class="p-3 text-right font-mono">${formatCurrency(data.mxn, 'MXN')}</td>
                                            <td class="p-3 text-right font-mono">${formatCurrency(data.usd, 'USD')}</td>
                                        </tr>
                                    `).join('')}
                                    <tr class="bg-brand-lime/20 font-bold border-t border-brand-lime/50">
                                        <td class="p-3 text-brand-lime uppercase text-xs">TOTAL INGRESOS</td>
                                        <td class="p-3 text-center text-brand-lime">${Object.values(summary.plansSold).reduce((a, b) => a + b.count, 0)}</td>
                                        <td class="p-3 text-right text-brand-lime font-mono">${formatCurrency(summary.financials.income.totalMXN, 'MXN')}</td>
                                        <td class="p-3 text-right text-brand-lime font-mono">${formatCurrency(summary.financials.income.totalUSD, 'USD')}</td>
                                    </tr>
                                </tbody>
                            </table>
                        </div>
                    </div>

                    <!-- FINANCIAL TOTALS (Right - 5 cols) -->
                    <div class="lg:col-span-5 space-y-6">
                        <!-- Totales Ingresos -->
                        <div class="bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-800 rounded-2xl shadow-sm overflow-hidden">
                            <div class="bg-emerald-500 text-white font-bold p-3 text-center uppercase text-sm tracking-wider">
                                TOTALES INGRESOS
                            </div>
                            <table class="w-full text-xs">
                                <tbody class="divide-y divide-zinc-100 dark:divide-zinc-800">
                                    <tr>
                                        <td class="p-3 font-bold bg-emerald-50 dark:bg-emerald-900/20 text-emerald-800 dark:text-emerald-400">BANCO INGRESOS</td>
                                        <td class="p-3 text-right font-mono">${formatCurrency(summary.financials.income.bankMXN, 'MXN')}</td>
                                        <td class="p-3 text-right font-mono">${formatCurrency(summary.financials.income.bankUSD, 'USD')}</td>
                                    </tr>
                                    <tr>
                                        <td class="p-3 font-bold bg-emerald-50 dark:bg-emerald-900/20 text-emerald-800 dark:text-emerald-400">EFECTIVO INGRESOS</td>
                                        <td class="p-3 text-right font-mono">${formatCurrency(summary.financials.income.cashMXN, 'MXN')}</td>
                                        <td class="p-3 text-right font-mono">${formatCurrency(summary.financials.income.cashUSD, 'USD')}</td>
                                    </tr>
                                    <tr class="bg-zinc-900 text-white font-bold">
                                        <td class="p-3 uppercase">TOTAL DOMINIO</td>
                                        <td class="p-3 text-right font-mono">${formatCurrency(summary.financials.income.totalMXN, 'MXN')}</td>
                                        <td class="p-3 text-right font-mono">${formatCurrency(summary.financials.income.totalUSD, 'USD')}</td>
                                    </tr>
                                </tbody>
                            </table>
                        </div>

                        <!-- Totales Egresos -->
                        <div class="bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-800 rounded-2xl shadow-sm overflow-hidden">
                            <div class="bg-red-500 text-white font-bold p-3 text-center uppercase text-sm tracking-wider">
                                TOTALES EGRESOS
                            </div>
                            <table class="w-full text-xs">
                                <tbody class="divide-y divide-zinc-100 dark:divide-zinc-800">
                                    <tr>
                                        <td class="p-3 font-bold bg-red-50 dark:bg-red-900/20 text-red-800 dark:text-red-400">BANCO EGRESOS</td>
                                        <td class="p-3 text-right font-mono">${formatCurrency(summary.financials.outflow.bankMXN, 'MXN')}</td>
                                        <td class="p-3 text-right font-mono">${formatCurrency(summary.financials.outflow.bankUSD, 'USD')}</td>
                                    </tr>
                                    <tr>
                                        <td class="p-3 font-bold bg-red-50 dark:bg-red-900/20 text-red-800 dark:text-red-400">EFECTIVO EGRESOS</td>
                                        <td class="p-3 text-right font-mono">${formatCurrency(summary.financials.outflow.cashMXN, 'MXN')}</td>
                                        <td class="p-3 text-right font-mono">${formatCurrency(summary.financials.outflow.cashUSD, 'USD')}</td>
                                    </tr>
                                    <tr class="bg-zinc-900 text-white font-bold">
                                        <td class="p-3 uppercase">TOTAL DOMINIO</td>
                                        <td class="p-3 text-right font-mono">${formatCurrency(summary.financials.outflow.totalMXN, 'MXN')}</td>
                                        <td class="p-3 text-right font-mono">${formatCurrency(summary.financials.outflow.totalUSD, 'USD')}</td>
                                    </tr>
                                </tbody>
                            </table>
                        </div>

                        <!-- Cuentas por Cobrar / Pagar -->
                        <div class="bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-800 rounded-2xl shadow-sm overflow-hidden">
                            <div class="bg-zinc-900 text-white font-bold p-3 text-center uppercase text-sm tracking-wider">
                                CUENTAS POR COBRAR / PAGAR
                            </div>
                            <table class="w-full text-xs">
                                <tbody class="divide-y divide-zinc-100 dark:divide-zinc-800">
                                    <tr>
                                        <td class="p-3 font-bold bg-emerald-50 dark:bg-emerald-900/20 text-emerald-800 dark:text-emerald-400">CUENTAS POR COBRAR</td>
                                        <td class="p-3 text-right font-mono">${formatCurrency(accounts.receivable.mxn, 'MXN')}</td>
                                        <td class="p-3 text-right font-mono">${formatCurrency(accounts.receivable.usd, 'USD')}</td>
                                    </tr>
                                    <tr>
                                        <td class="p-3 font-bold bg-red-50 dark:bg-red-900/20 text-red-800 dark:text-red-400">CUENTAS POR PAGAR</td>
                                        <td class="p-3 text-right font-mono">${formatCurrency(accounts.payable.mxn, 'MXN')}</td>
                                        <td class="p-3 text-right font-mono">${formatCurrency(accounts.payable.usd, 'USD')}</td>
                                    </tr>
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
                
                <!-- COSTOS Y GASTOS BREAKDOWN -->
                <div class="bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-800 rounded-2xl shadow-sm overflow-hidden">
                    <div class="bg-red-100 dark:bg-red-900/30 text-red-800 dark:text-red-400 font-bold p-3 text-center uppercase text-sm tracking-wider border-b border-red-200 dark:border-red-800">
                        EGRESOS POR CATEGORÍA
                    </div>
                    <div class="grid md:grid-cols-2 divide-y md:divide-y-0 md:divide-x divide-zinc-200 dark:divide-zinc-800">
                        <!-- Costos -->
                        <div>
                            <div class="bg-rose-50 dark:bg-rose-900/20 p-2 text-center text-xs font-black uppercase text-rose-600 dark:text-rose-400">COSTOS</div>
                            <table class="w-full text-xs">
                                <thead class="bg-zinc-50 dark:bg-zinc-800/50 text-zinc-500 font-bold">
                                    <tr>
                                        <th class="p-2 text-left">CATEGORÍA</th>
                                        <th class="p-2 text-center">CANT</th>
                                        <th class="p-2 text-right">PESOS</th>
                                        <th class="p-2 text-right">DOLARES</th>
                                    </tr>
                                </thead>
                                <tbody class="divide-y divide-zinc-100 dark:divide-zinc-800">
                                    ${Object.entries(summary.costsByCategory).map(([cat, data]) => `
                                        <tr class="hover:bg-zinc-50 dark:hover:bg-zinc-800/50">
                                            <td class="p-2 font-medium truncate max-w-[120px]" title="${cat}">${cat}</td>
                                            <td class="p-2 text-center font-mono">${data.count}</td>
                                            <td class="p-2 text-right font-mono">${formatCurrency(data.mxn, 'MXN')}</td>
                                            <td class="p-2 text-right font-mono">${formatCurrency(data.usd, 'USD')}</td>
                                        </tr>
                                    `).join('')}
                                    ${Object.keys(summary.costsByCategory).length === 0 ? '<tr><td colspan="4" class="p-4 text-center text-zinc-400">Sin costos registrados</td></tr>' : ''}
                                </tbody>
                            </table>
                        </div>
                        <!-- Gastos -->
                        <div>
                            <div class="bg-rose-50 dark:bg-rose-900/20 p-2 text-center text-xs font-black uppercase text-rose-600 dark:text-rose-400">GASTOS</div>
                            <table class="w-full text-xs">
                                <thead class="bg-zinc-50 dark:bg-zinc-800/50 text-zinc-500 font-bold">
                                    <tr>
                                        <th class="p-2 text-left">CATEGORÍA</th>
                                        <th class="p-2 text-center">CANT</th>
                                        <th class="p-2 text-right">PESOS</th>
                                        <th class="p-2 text-right">DOLARES</th>
                                    </tr>
                                </thead>
                                <tbody class="divide-y divide-zinc-100 dark:divide-zinc-800">
                                    ${Object.entries(summary.expensesByCategory).map(([cat, data]) => `
                                        <tr class="hover:bg-zinc-50 dark:hover:bg-zinc-800/50">
                                            <td class="p-2 font-medium truncate max-w-[120px]" title="${cat}">${cat}</td>
                                            <td class="p-2 text-center font-mono">${data.count}</td>
                                            <td class="p-2 text-right font-mono">${formatCurrency(data.mxn, 'MXN')}</td>
                                            <td class="p-2 text-right font-mono">${formatCurrency(data.usd, 'USD')}</td>
                                        </tr>
                                    `).join('')}
                                    ${Object.keys(summary.expensesByCategory).length === 0 ? '<tr><td colspan="4" class="p-4 text-center text-zinc-400">Sin gastos registrados</td></tr>' : ''}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            </div>
            
            <div class="bg-zinc-50 dark:bg-zinc-800 p-4 border-t border-zinc-200 dark:border-zinc-700 text-center">
                <form method="dialog">
                    <button class="bg-zinc-200 dark:bg-zinc-700 hover:bg-zinc-300 dark:hover:bg-zinc-600 px-6 py-2 rounded-lg font-bold text-zinc-600 dark:text-zinc-300 transition-colors">
                        Cerrar Resumen
                    </button>
                </form>
            </div>
        </div>
    </dialog>

    <!--Transactions Table-->
        <div class="bg-white dark:bg-zinc-900 rounded-2xl border border-zinc-200 dark:border-zinc-800 overflow-hidden shadow-sm">
            <div class="overflow-x-auto">
                <table class="w-full text-left border-collapse">
                    <thead class="bg-zinc-50 dark:bg-zinc-800/50 text-xs font-bold text-zinc-500 uppercase">
                        <tr>
                            <th class="p-4">Fecha</th>
                            <th class="p-4">Tipo</th>
                            <th class="p-4">Categoría</th>
                            <th class="p-4">Cliente / Proveedor</th>
                            <th class="p-4 text-right">Monto MXN</th>
                            <th class="p-4 text-right">Monto USD</th>
                            <th class="p-4 text-center">Método</th>
                            <th class="p-4">Banco</th>
                            <th class="p-4 text-center">Estado</th>
                            <th class="p-4 text-center">Acciones</th>
                        </tr>
                    </thead>
                    <tbody class="divide-y divide-zinc-100 dark:divide-zinc-800 text-sm">
                        ${filteredTxns.length === 0 ? `<tr><td colspan="10" class="p-8 text-center text-zinc-400">No hay transacciones registradas ${currentFilter !== 'all' ? 'en este mes' : ''}.</td></tr>` :
            filteredTxns.map(t => `
                            <tr class="hover:bg-zinc-50 dark:hover:bg-zinc-800/30">
                                <td class="p-4 font-mono text-zinc-600 dark:text-zinc-400">${t.date}</td>
                                <td class="p-4">
                                    <span class="px-2 py-1 rounded text-xs font-bold ${t.type === 'INCOME' ? 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400' :
                    t.type === 'COST' ? 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400' :
                        'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400'}">
                                        ${t.type === 'INCOME' ? 'INGRESO' : t.type === 'COST' ? 'COSTO' : 'GASTO'}
                                    </span>
                                </td>
                                <td class="p-4 font-medium">${t.category}</td>
                                <td class="p-4 text-zinc-600 dark:text-zinc-300">
                                    ${t.entityType ? `<span class="text-[10px] uppercase font-bold bg-zinc-100 dark:bg-zinc-700 px-1.5 py-0.5 rounded mr-1.5 align-middle text-zinc-500 dark:text-zinc-400">${t.entityType}</span>` : ''}
                                    <span class="align-middle">${t.client || '-'}</span>
                                    ${t.notes ? `<div class="text-xs text-zinc-400 mt-0.5 truncate max-w-[200px]">${t.notes}</div>` : ''}
                                </td>
                                <td class="p-4 text-right font-mono font-bold ${t.amountMXN > 0 ? (t.type === 'INCOME' ? 'text-emerald-600' : 'text-zinc-900 dark:text-white') : 'text-zinc-300'}">
                                    ${t.amountMXN ? `$${Number(t.amountMXN).toLocaleString('es-MX')}` : '-'}
                                </td>
                                <td class="p-4 text-right font-mono font-bold ${t.amountUSD > 0 ? (t.type === 'INCOME' ? 'text-emerald-600' : 'text-zinc-900 dark:text-white') : 'text-zinc-300'}">
                                    ${t.amountUSD ? `$${Number(t.amountUSD).toLocaleString('en-US')}` : '-'}
                                </td>
                                <td class="p-4 text-center text-xs font-bold text-zinc-500 uppercase">${t.paymentMethod || '-'}</td>
                                <td class="p-4 text-xs text-zinc-500">${t.bank}</td>
                                <td class="p-4 text-center">
                                    ${(() => {
                    const status = (t.status || 'Pendiente').toLowerCase();
                    const statusClass = status === 'pagado'
                        ? 'bg-emerald-100 text-emerald-700'
                        : status === 'abonado'
                            ? 'bg-blue-100 text-blue-700'
                            : 'bg-amber-100 text-amber-700';
                    const statusLabel = status === 'pagado' ? 'Pagado' : status === 'abonado' ? 'Abonado' : 'Pendiente';
                    if (readOnly) {
                        return `<span class="px-2 py-1 rounded text-xs font-bold uppercase ${statusClass}">${statusLabel}</span>`;
                    }
                    return `
                        <div class="relative inline-flex" id="bsd-${t.id}">
                          <button class="px-2 py-1 rounded text-xs font-bold uppercase ${statusClass} border border-transparent flex items-center gap-1 cursor-pointer"
                            onclick="event.stopPropagation();var m=document.getElementById('bsm-${t.id}');if(m.classList.contains('hidden')){m.classList.remove('hidden');setTimeout(function(){document.addEventListener('click',function h(){m.classList.add('hidden');document.removeEventListener('click',h)})},0)}else{m.classList.add('hidden')}">
                            <span id="bsl-${t.id}">${statusLabel}</span>
                            <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="6 9 12 15 18 9"></polyline></svg>
                          </button>
                          <div id="bsm-${t.id}" class="hidden absolute z-50 top-full mt-1 left-0 shadow-lg rounded-lg overflow-hidden border border-zinc-200 dark:border-zinc-700 min-w-[110px]">
                            <button class="w-full px-3 py-1.5 text-xs font-bold uppercase text-left bg-amber-100 text-amber-700 hover:bg-amber-200" onclick="event.stopPropagation();document.getElementById('bsm-${t.id}').classList.add('hidden');document.getElementById('bsl-${t.id}').parentElement.className='px-2 py-1 rounded text-xs font-bold uppercase bg-amber-100 text-amber-700 border border-transparent flex items-center gap-1 cursor-pointer';document.getElementById('bsl-${t.id}').textContent='Pendiente';actions.updateBusinessTransaction('${t.id}','status','Pendiente')">Pendiente</button>
                            <button class="w-full px-3 py-1.5 text-xs font-bold uppercase text-left bg-blue-100 text-blue-700 hover:bg-blue-200" onclick="event.stopPropagation();document.getElementById('bsm-${t.id}').classList.add('hidden');document.getElementById('bsl-${t.id}').parentElement.className='px-2 py-1 rounded text-xs font-bold uppercase bg-blue-100 text-blue-700 border border-transparent flex items-center gap-1 cursor-pointer';document.getElementById('bsl-${t.id}').textContent='Abonado';actions.updateBusinessTransaction('${t.id}','status','Abonado')">Abonado</button>
                            <button class="w-full px-3 py-1.5 text-xs font-bold uppercase text-left bg-emerald-100 text-emerald-700 hover:bg-emerald-200" onclick="event.stopPropagation();document.getElementById('bsm-${t.id}').classList.add('hidden');document.getElementById('bsl-${t.id}').parentElement.className='px-2 py-1 rounded text-xs font-bold uppercase bg-emerald-100 text-emerald-700 border border-transparent flex items-center gap-1 cursor-pointer';document.getElementById('bsl-${t.id}').textContent='Pagado';actions.updateBusinessTransaction('${t.id}','status','Pagado')">Pagado</button>
                          </div>
                        </div>`;
                })()}
                                </td>
                                <td class="p-4 text-center">
                                    ${readOnly ? `
                                    <span class="text-xs text-zinc-400">Solo lectura</span>
                                    ` : `
                                    <div class="flex items-center justify-center gap-2">
                                        <button onclick="actions.openEditBusinessTransaction('${t.id}')" class="text-zinc-300 hover:text-blue-500 transition-colors" title="Editar">
                                            <i data-lucide="pencil" width="16"></i>
                                        </button>
                                        <button onclick="actions.deleteBusinessTransaction('${t.id}')" class="text-zinc-300 hover:text-red-500 transition-colors" title="Eliminar">
                                            <i data-lucide="trash-2" width="16"></i>
                                        </button>
                                    </div>
                                    `}
                                </td>
                            </tr>
                        `).join('')}
                    </tbody>
                </table>
            </div>
        </div>

        <!--Add Transaction Modal-->
    <dialog id="add-txn-modal" class="modal bg-transparent p-0 w-full max-w-2xl backdrop:bg-black/50">
        <div class="bg-white dark:bg-zinc-900 rounded-2xl shadow-2xl border border-zinc-200 dark:border-zinc-700 p-8 w-full">
            <h3 class="text-xl font-bold mb-6 dark:text-white">Nueva Transacción</h3>
            <form method="dialog" class="space-y-4" onsubmit="
                    const formData = new FormData(this);
                    actions.addBusinessTransaction({
                        date: formData.get('date'),
                        paymentDate: formData.get('paymentDate'),
                        type: formData.get('type'),
                        category: formData.get('category'),
                        amountMXN: parseFloat(formData.get('amountMXN') || 0),
                        amountUSD: parseFloat(formData.get('amountUSD') || 0),
                        entityType: formData.get('entityType'),
                        client: formData.get('client'),
                        bank: formData.get('bank'),
                        paymentMethod: formData.get('paymentMethod'),
                        status: formData.get('status') || 'Pendiente',
                        notes: formData.get('notes')
                    });
                ">
                <div class="grid grid-cols-2 gap-4">
                    <div>
                        <label class="block text-xs font-bold text-zinc-500 mb-1">Fecha de Registro</label>
                        <input type="date" name="date" required class="w-full bg-zinc-50 dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 rounded-lg" value="${defaultTxnDate}">
                    </div>
                    <div>
                        <label class="block text-xs font-bold text-zinc-500 mb-1">Fecha de Pago</label>
                        <input type="date" name="paymentDate" class="w-full bg-zinc-50 dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 rounded-lg" value="${defaultTxnDate}">
                    </div>
                </div>

                <div class="grid grid-cols-1 gap-4">
                    <div>
                    <div>
                        <label class="block text-xs font-bold text-zinc-500 mb-1">Tipo</label>
                        <select name="type" class="w-full bg-zinc-50 dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 rounded-lg" onchange="actions.updateTransactionCategories(this.value)">
                            <option value="INCOME">Ingreso</option>
                            <option value="EXPENSE">Gasto</option>
                             <option value="COST">Costo</option>
                        </select>
                    </div>
                </div>

                <div>
                    <label class="block text-xs font-bold text-zinc-500 mb-1">Categoría</label>
                    <select id="cat-select" name="category" class="w-full bg-zinc-50 dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 rounded-lg">
                        ${config.incomeCategories.map(c => `<option value="${c}">${c}</option>`).join('')}
                    </select>
                </div>

                <div class="grid grid-cols-2 gap-4">
                    <div>
                        <label class="block text-xs font-bold text-zinc-500 mb-1">Monto MXN</label>
                        <input type="number" step="0.01" name="amountMXN" class="w-full bg-zinc-50 dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 rounded-lg" placeholder="0.00">
                    </div>
                    <div>
                        <label class="block text-xs font-bold text-zinc-500 mb-1">Monto USD</label>
                        <input type="number" step="0.01" name="amountUSD" class="w-full bg-zinc-50 dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 rounded-lg" placeholder="0.00">
                    </div>
                </div>

                <div class="grid grid-cols-2 gap-4">
                    <div>
                        <label class="block text-xs font-bold text-zinc-500 mb-1">CLIENTE O PROVEEDOR</label>
                        <select id="entity-type-select" name="entityType" class="w-full bg-zinc-50 dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 rounded-lg" onchange="actions.refreshTransactionEntityDatalist(this.value)">
                            <option value="CLIENTE">CLIENTE</option>
                            <option value="PROVEEDOR">PROVEEDOR</option>
                        </select>
                    </div>
                    <div>
                        <label class="block text-xs font-bold text-zinc-500 mb-1">NOMBRE DEL CLIENTE O PROVEEDOR</label>
                        <div class="flex gap-2">
                            <input type="text" 
                                name="client" 
                                list="entity-list" 
                                class="w-full bg-zinc-50 dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 rounded-lg" 
                                placeholder="Nombre..."
                                oninput="actions.handleTransactionEntityInput(this)"
                            >
                            <button id="btn-add-entity" type="button" onclick="actions.createTransactionEntity()" class="p-2 bg-brand-lime text-black rounded-lg hover:bg-lime-400 transition-colors disabled:opacity-60 disabled:cursor-not-allowed" title="Nuevo Cliente/Proveedor" disabled>
                                <i data-lucide="plus" width="20"></i>
                            </button>
                        </div>
                        <datalist id="entity-list">
                            ${buildBusinessEntityOptions('CLIENTE')}
                        </datalist>
                    </div>
                </div>

                <div class="grid grid-cols-2 gap-4">
                    <div>
                        <label class="block text-xs font-bold text-zinc-500 mb-1">Banco / Cuenta</label>
                        <select name="bank" class="w-full bg-zinc-50 dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 rounded-lg">
                            ${config.banks.map(c => `<option value="${c}">${c}</option>`).join('')}
                        </select>
                    </div>
                    <div>
                        <label class="block text-xs font-bold text-zinc-500 mb-1">Método de Pago</label>
                        <select name="paymentMethod" class="w-full bg-zinc-50 dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 rounded-lg">
                            ${config.paymentMethods.map(c => `<option value="${c}">${c}</option>`).join('')}
                        </select>
                    </div>
                </div>

                <div class="grid grid-cols-1 gap-4">
                    <div>
                        <label class="block text-xs font-bold text-zinc-500 mb-1">Estado</label>
                        <select name="status" class="w-full bg-zinc-50 dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 rounded-lg">
                            <option value="Pendiente">Pendiente</option>
                            <option value="Abonado">Abonado</option>
                            <option value="Pagado">Pagado</option>
                        </select>
                    </div>
                </div>

                <div>
                    <label class="block text-xs font-bold text-zinc-500 mb-1">Notas</label>
                    <textarea name="notes" class="w-full bg-zinc-50 dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 rounded-lg" rows="2"></textarea>
                </div>

                <div class="flex justify-end gap-2 pt-4">
                    <button type="button" onclick="document.getElementById('add-txn-modal').close()" class="px-4 py-2 text-zinc-500 hover:bg-zinc-100 dark:hover:bg-zinc-800 rounded-lg font-bold">Cancelar</button>
                    <button type="submit" class="bg-sky-500 hover:bg-sky-600 text-white px-6 py-2 rounded-lg font-bold">Guardar Transacción</button>
                </div>
            </form>
        </div>
    </dialog>

    <!--Edit Transaction Modal-->
    <dialog id="edit-txn-modal" class="modal bg-transparent p-0 w-full max-w-2xl backdrop:bg-black/50">
        <div class="bg-white dark:bg-zinc-900 rounded-2xl shadow-2xl border border-zinc-200 dark:border-zinc-700 p-8 w-full">
            <div class="flex justify-between items-center mb-6">
                <h3 class="text-xl font-bold dark:text-white">Editar Transacción</h3>
                <button type="button" onclick="document.getElementById('edit-txn-modal').close()" class="text-zinc-400 hover:text-zinc-600 dark:hover:text-white transition-colors"><i data-lucide="x" width="24"></i></button>
            </div>
            <form class="space-y-4" onsubmit="actions.handleBusinessTransactionUpdate(event)">
                <input type="hidden" name="id">
                <div class="grid grid-cols-2 gap-4">
                    <div>
                        <label class="block text-xs font-bold text-zinc-500 mb-1">Fecha de Registro</label>
                        <input type="date" name="date" required class="w-full bg-zinc-50 dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 rounded-lg px-3 py-2">
                    </div>
                    <div>
                        <label class="block text-xs font-bold text-zinc-500 mb-1">Fecha de Pago</label>
                        <input type="date" name="paymentDate" class="w-full bg-zinc-50 dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 rounded-lg px-3 py-2">
                    </div>
                </div>

                <div>
                    <div>
                        <label class="block text-xs font-bold text-zinc-500 mb-1">Tipo</label>
                        <select name="type" class="w-full bg-zinc-50 dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 rounded-lg px-3 py-2" onchange="actions.updateEditTransactionCategories(this.value)">
                            <option value="INCOME">Ingreso</option>
                            <option value="EXPENSE">Gasto</option>
                            <option value="COST">Costo</option>
                        </select>
                    </div>
                </div>

                <div>
                    <label class="block text-xs font-bold text-zinc-500 mb-1">Categoría</label>
                    <select id="edit-cat-select" name="category" class="w-full bg-zinc-50 dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 rounded-lg px-3 py-2">
                        ${config.incomeCategories.map(c => `<option value="${c}">${c}</option>`).join('')}
                    </select>
                </div>

                <div class="grid grid-cols-2 gap-4">
                    <div>
                        <label class="block text-xs font-bold text-zinc-500 mb-1">Monto MXN</label>
                        <input type="number" step="0.01" name="amountMXN" class="w-full bg-zinc-50 dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 rounded-lg px-3 py-2" placeholder="0.00">
                    </div>
                    <div>
                        <label class="block text-xs font-bold text-zinc-500 mb-1">Monto USD</label>
                        <input type="number" step="0.01" name="amountUSD" class="w-full bg-zinc-50 dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 rounded-lg px-3 py-2" placeholder="0.00">
                    </div>
                </div>

                <div class="grid grid-cols-2 gap-4">
                    <div>
                        <label class="block text-xs font-bold text-zinc-500 mb-1">CLIENTE O PROVEEDOR</label>
                        <select id="edit-entity-type-select" name="entityType" class="w-full bg-zinc-50 dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 rounded-lg px-3 py-2" onchange="actions.refreshEditTransactionEntityDatalist(this.value)">
                            <option value="CLIENTE">CLIENTE</option>
                            <option value="PROVEEDOR">PROVEEDOR</option>
                        </select>
                    </div>
                    <div>
                        <label class="block text-xs font-bold text-zinc-500 mb-1">NOMBRE DEL CLIENTE O PROVEEDOR</label>
                        <input type="text" name="client" list="edit-entity-list" class="w-full bg-zinc-50 dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 rounded-lg px-3 py-2" placeholder="Nombre...">
                        <datalist id="edit-entity-list">
                            ${buildBusinessEntityOptions('CLIENTE')}
                        </datalist>
                    </div>
                </div>

                <div class="grid grid-cols-2 gap-4">
                    <div>
                        <label class="block text-xs font-bold text-zinc-500 mb-1">Banco / Cuenta</label>
                        <select name="bank" class="w-full bg-zinc-50 dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 rounded-lg px-3 py-2">
                            ${config.banks.map(c => `<option value="${c}">${c}</option>`).join('')}
                        </select>
                    </div>
                    <div>
                        <label class="block text-xs font-bold text-zinc-500 mb-1">Método de Pago</label>
                        <select name="paymentMethod" class="w-full bg-zinc-50 dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 rounded-lg px-3 py-2">
                            ${config.paymentMethods.map(c => `<option value="${c}">${c}</option>`).join('')}
                        </select>
                    </div>
                </div>

                <div>
                    <label class="block text-xs font-bold text-zinc-500 mb-1">Estado</label>
                    <select name="status" class="w-full bg-zinc-50 dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 rounded-lg px-3 py-2">
                        <option value="Pendiente">Pendiente</option>
                        <option value="Abonado">Abonado</option>
                        <option value="Pagado">Pagado</option>
                    </select>
                </div>

                <div>
                    <label class="block text-xs font-bold text-zinc-500 mb-1">Notas</label>
                    <textarea name="notes" class="w-full bg-zinc-50 dark:bg-zinc-800 border-zinc-200 dark:border-zinc-700 rounded-lg px-3 py-2" rows="2"></textarea>
                </div>

                <div class="flex justify-end gap-2 pt-4">
                    <button type="button" onclick="document.getElementById('edit-txn-modal').close()" class="px-4 py-2 text-zinc-500 hover:bg-zinc-100 dark:hover:bg-zinc-800 rounded-lg font-bold">Cancelar</button>
                    <button type="submit" class="bg-sky-500 hover:bg-sky-600 text-white px-6 py-2 rounded-lg font-bold">Guardar Cambios</button>
                </div>
            </form>
        </div>
    </dialog>
`;
};



const renderBusinessDashboard = () => {
    const { transactions } = state.businessData;

    // --- FILTER STATE INITIALIZATION ---
    // Ensure filter state is an object, always with empty dates (show all history by default)
    if (!state.businessData.dashboardFilter || typeof state.businessData.dashboardFilter !== 'object') {
        state.businessData.dashboardFilter = { dateFrom: '', dateTo: '', client: '', provider: '' };
    }
    // Always clear date range if it was previously set to a restrictive default (allows all-time USD to show)
    if (!state.businessData._dashFilterInitialized) {
        state.businessData.dashboardFilter.dateFrom = '';
        state.businessData.dashboardFilter.dateTo = '';
        state.businessData._dashFilterInitialized = true;
    }
    const filters = state.businessData.dashboardFilter;

    // --- UNIQUE LISTS FOR DROPDOWNS ---
    const uniqueClients = [...new Set(transactions.filter(t => t.entityType === 'CLIENTE' && t.client).map(t => t.client))].sort();
    const uniqueProviders = [...new Set(transactions.filter(t => t.entityType === 'PROVEEDOR' && t.client).map(t => t.client))].sort();

    // --- FILTER LOGIC ---
    const filteredTxns = transactions.filter(t => {
        if (!t.date) return false;

        // Date Logic
        if (filters.dateFrom && t.date < filters.dateFrom) return false;
        if (filters.dateTo && t.date > filters.dateTo) return false;

        // Entity Logic (Exact match)
        if (filters.client && (t.entityType !== 'CLIENTE' || t.client !== filters.client)) return false;
        if (filters.provider && (t.entityType !== 'PROVEEDOR' || t.client !== filters.provider)) return false;

        return true;
    });

    const calcTxns = filteredTxns.filter(t => (t.status || 'Pendiente').toLowerCase() !== 'pendiente');

    // Calculate Totals (using FILTERED data)
    // MXN: Use only confirmed (non-pending) transactions
    const totalIncomeMXN = calcTxns.filter(t => t.type === 'INCOME').reduce((sum, t) => sum + (t.amountMXN || 0), 0);
    const totalExpenseMXN = calcTxns.filter(t => t.type === 'EXPENSE' || t.type === 'COST').reduce((sum, t) => sum + (t.amountMXN || 0), 0);
    const totalNetMXN = totalIncomeMXN - totalExpenseMXN;
    // USD: Use ALL filtered transactions (status-agnostic) so USD amounts registered always display
    const totalIncomeUSD = filteredTxns.filter(t => t.type === 'INCOME').reduce((sum, t) => sum + (t.amountUSD || 0), 0);
    const totalExpenseUSD = filteredTxns.filter(t => (t.type === 'EXPENSE' || t.type === 'COST')).reduce((sum, t) => sum + (t.amountUSD || 0), 0);
    const dashActiveClients = new Set(filteredTxns.filter(t => t.type === 'INCOME' && t.client).map(t => t.client)).size;

    // Sales by Category (Filtered)
    const salesByCat = {};
    calcTxns.filter(t => t.type === 'INCOME').forEach(t => {
        salesByCat[t.category] = (salesByCat[t.category] || 0) + 1;
    });

    return `
    <div class="mb-6 space-y-4">
        <div class="flex flex-col md:flex-row justify-between items-start md:items-center">
            <div>
                <h2 class="text-3xl font-black text-zinc-900 dark:text-white mb-2">Dashboard</h2>
                <p class="text-zinc-500">Visión general de tu negocio.</p>
            </div>
            <button onclick="actions.clearDashboardFilters()" class="text-xs text-zinc-400 hover:text-red-500 underline mt-2 md:mt-0">
                Limpiar Filtros
            </button>
        </div>
        
        <!-- ADVANCED FILTER BAR -->
        <div class="bg-white dark:bg-zinc-800 p-4 rounded-xl border border-zinc-200 dark:border-zinc-700 shadow-sm grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
            
            <!-- Date From -->
            <div>
                <label class="block text-[10px] font-bold text-zinc-500 uppercase mb-1">Desde</label>
                <input type="date" value="${filters.dateFrom}" onchange="actions.updateDashboardFilters('dateFrom', this.value)" 
                    class="w-full bg-zinc-50 dark:bg-zinc-900 border-zinc-200 dark:border-zinc-700 rounded-lg text-sm p-2">
            </div>

            <!-- Date To -->
            <div>
                <label class="block text-[10px] font-bold text-zinc-500 uppercase mb-1">Hasta</label>
                <input type="date" value="${filters.dateTo}" onchange="actions.updateDashboardFilters('dateTo', this.value)"
                    class="w-full bg-zinc-50 dark:bg-zinc-900 border-zinc-200 dark:border-zinc-700 rounded-lg text-sm p-2">
            </div>

            <!-- Client Select -->
            <div>
                <label class="block text-[10px] font-bold text-zinc-500 uppercase mb-1">Cliente</label>
                <select onchange="actions.updateDashboardFilters('client', this.value)" 
                    class="w-full bg-zinc-50 dark:bg-zinc-900 border-zinc-200 dark:border-zinc-700 rounded-lg text-sm p-2">
                    <option value="">Todos</option>
                    ${uniqueClients.map(c => `<option value="${c}" ${filters.client === c ? 'selected' : ''}>${c}</option>`).join('')}
                </select>
            </div>

            <!-- Provider Select -->
             <div>
                <label class="block text-[10px] font-bold text-zinc-500 uppercase mb-1">Proveedor</label>
                <select onchange="actions.updateDashboardFilters('provider', this.value)" 
                    class="w-full bg-zinc-50 dark:bg-zinc-900 border-zinc-200 dark:border-zinc-700 rounded-lg text-sm p-2">
                    <option value="">Todos</option>
                    ${uniqueProviders.map(p => `<option value="${p}" ${filters.provider === p ? 'selected' : ''}>${p}</option>`).join('')}
                </select>
            </div>

            <!-- Apply Filters -->
            <div class="flex items-end">
                <button type="button" onclick="actions.applyDashboardFilters()" class="w-full bg-sky-500 hover:bg-sky-600 text-white font-bold rounded-lg text-sm p-2 shadow-sm">
                    Aplicar
                </button>
            </div>

        </div>
    </div>

    <!-- SUMMARY CARDS (Filtered) -->
    <div class="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 mb-8">
        <div class="p-6 bg-white dark:bg-zinc-900 rounded-2xl border border-zinc-200 dark:border-zinc-800 border-l-4 border-l-emerald-500 shadow-sm relative overflow-hidden group">
            <div class="absolute right-0 top-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                 <i data-lucide="trending-up" class="w-16 h-16 text-emerald-500"></i>
            </div>
            <div class="text-xs font-bold text-zinc-500 uppercase mb-1">Ingresos (${state.vision360Currency})</div>
            <div class="text-2xl font-black text-emerald-600">${state.vision360Currency === 'USD' ? '$' + totalIncomeUSD.toLocaleString('en-US') : '$' + totalIncomeMXN.toLocaleString('es-MX')}</div>
            <div class="text-[10px] text-zinc-400 mt-2 font-medium uppercase tracking-wider">
                ${filters.dateFrom || filters.dateTo ? (filters.dateFrom || '') + ' - ' + (filters.dateTo || '') : 'Histórico'}
            </div>
        </div>
        <div class="p-6 bg-white dark:bg-zinc-900 rounded-2xl border border-zinc-200 dark:border-zinc-800 border-l-4 border-l-red-500 shadow-sm relative overflow-hidden group">
             <div class="absolute right-0 top-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                 <i data-lucide="trending-down" class="w-16 h-16 text-red-500"></i>
            </div>
            <div class="text-xs font-bold text-zinc-500 uppercase mb-1">Egresos (${state.vision360Currency})</div>
            <div class="text-2xl font-black text-red-600">${state.vision360Currency === 'USD' ? '$' + totalExpenseUSD.toLocaleString('en-US') : '$' + totalExpenseMXN.toLocaleString('es-MX')}</div>
            <div class="text-[10px] text-zinc-400 mt-2 font-medium uppercase tracking-wider">
                ${filters.dateFrom || filters.dateTo ? (filters.dateFrom || '') + ' - ' + (filters.dateTo || '') : 'Histórico'}
            </div>
        </div>
        <div class="p-6 bg-white dark:bg-zinc-900 rounded-2xl border border-zinc-200 dark:border-zinc-800 border-l-4 border-l-brand-lime shadow-sm relative overflow-hidden group">
            <div class="absolute right-0 top-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                <i data-lucide="trending-up" class="w-16 h-16 text-brand-lime"></i>
            </div>
            <div class="text-xs font-bold text-zinc-500 uppercase mb-1">Utilidad Neta</div>
            <div class="text-2xl font-black ${totalNetMXN >= 0 ? 'text-emerald-600' : 'text-red-500'}">${state.vision360Currency === 'USD' ? '$' + Math.abs(totalIncomeUSD - totalExpenseUSD).toLocaleString('en-US') : '$' + Math.abs(totalNetMXN).toLocaleString('es-MX')}</div>
            <div class="text-[10px] text-zinc-400 mt-2 font-medium uppercase tracking-wider">
                ${totalNetMXN >= 0 ? 'Ganancia' : 'Pérdida'} ${state.vision360Currency}
            </div>
        </div>
        <div class="p-6 bg-white dark:bg-zinc-900 rounded-2xl border border-zinc-200 dark:border-zinc-800 border-l-4 border-l-purple-500 shadow-sm relative overflow-hidden group">
            <div class="absolute right-0 top-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                <i data-lucide="users" class="w-16 h-16 text-purple-500"></i>
            </div>
            <div class="text-xs font-bold text-zinc-500 uppercase mb-1">Clientes Activos</div>
            <div class="text-2xl font-black text-purple-600">${dashActiveClients}</div>
            <div class="text-[10px] text-zinc-400 mt-2 font-medium uppercase tracking-wider">
                Con ingresos registrados
            </div>
        </div>
        </div>

        </div>

    <!-- CHARTS MODAL -->
    <dialog id="biz-charts-modal" class="modal bg-transparent p-0 w-full max-w-5xl backdrop:bg-black/70">
        <div class="bg-white dark:bg-zinc-900 rounded-2xl border border-zinc-200 dark:border-zinc-800 shadow-2xl max-h-[90vh] overflow-y-auto">
            <div class="sticky top-0 bg-white dark:bg-zinc-900 border-b border-zinc-200 dark:border-zinc-800 px-6 py-4 flex items-center justify-between z-10">
                <h2 class="text-xl font-bold text-zinc-900 dark:text-white flex items-center gap-2">
                    <i data-lucide="bar-chart-2" width="20" class="text-brand-blue"></i>
                    Gráficos Empresariales
                </h2>
                <button onclick="document.getElementById('biz-charts-modal').close()" class="text-zinc-400 hover:text-zinc-600 dark:hover:text-white transition-colors p-1.5 rounded-lg hover:bg-zinc-100 dark:hover:bg-zinc-800">
                    <i data-lucide="x" width="20"></i>
                </button>
            </div>
            <div class="p-6 space-y-6">
                <div class="bg-zinc-50 dark:bg-zinc-800/50 rounded-xl p-5">
                    <h3 class="font-bold text-zinc-800 dark:text-white mb-4 flex items-center gap-2"><i data-lucide="users" width="16" class="text-brand-blue"></i> Evolución Mensual Top 5 Clientes</h3>
                    <div class="relative h-64"><canvas id="bizChartTopClients"></canvas></div>
                </div>
                <div class="bg-zinc-50 dark:bg-zinc-800/50 rounded-xl p-5">
                    <h3 class="font-bold text-zinc-800 dark:text-white mb-4 flex items-center gap-2"><i data-lucide="truck" width="16" class="text-brand-blue"></i> Evolución Mensual Top 5 Proveedores</h3>
                    <div class="relative h-64"><canvas id="bizChartTopProviders"></canvas></div>
                </div>
                <div class="bg-zinc-50 dark:bg-zinc-800/50 rounded-xl p-5">
                    <h3 class="font-bold text-zinc-800 dark:text-white mb-4 flex items-center gap-2"><i data-lucide="trending-up" width="16" class="text-emerald-500"></i> Ingresos vs Egresos</h3>
                    <div class="relative h-64"><canvas id="bizChartIncomeExpense"></canvas></div>
                </div>
                <div class="bg-zinc-50 dark:bg-zinc-800/50 rounded-xl p-5">
                    <h3 class="font-bold text-zinc-800 dark:text-white mb-4 flex items-center gap-2"><i data-lucide="pie-chart" width="16" class="text-orange-500"></i> Gastos por Categoría</h3>
                    <div class="relative h-64"><canvas id="bizChartExpenseCat"></canvas></div>
                </div>
                <div class="bg-zinc-50 dark:bg-zinc-800/50 rounded-xl p-5">
                    <h3 class="font-bold text-zinc-800 dark:text-white mb-4 flex items-center gap-2"><i data-lucide="layers" width="16" class="text-purple-500"></i> Ingresos, Gastos y Costos por Subcategoría Mensual</h3>
                    <div class="relative h-80"><canvas id="bizChartSubcategoriesMonthly"></canvas></div>
                </div>
            </div>
        </div>
    </dialog>

`;
};



const initBusinessDashboardCharts = () => {
    // 1. Destroy existing charts if they exist
    ['bizIncomeExpense', 'bizExpenseCat', 'bizDailyTrend', 'bizBankDist', 'bizTopClients', 'bizTopProviders', 'bizSubcategoriesMonthly'].forEach(key => {
        if (state.charts[key]) {
            state.charts[key].destroy();
            state.charts[key] = null;
        }
    });

    // 2. Prepare Data
    const { transactions } = state.businessData;
    const filters = state.businessData.dashboardFilter;

    // --> Filtered Transactions for Snapshot Charts (Cat, Daily, Bank)
    // IMPORTANT: Even "Historical" charts like Income/Expense and Clients should arguably respect the filters IF it makes sense.
    // However, usually "Trends" need a range. 
    // If the user selected a Date Range, we should probably zoom into that range for trends?
    // For specific simplifiction:
    // 1. Snapshot Charts (Donuts, Totals) -> STRICTLY obey filters.
    // 2. Trend Charts (Line, Bar) -> Obey filters?
    //    If I filter "Client A", the "Top Clients" chart will only have 1 line. That is correct behavior.

    const calcTxns = transactions.filter(t => {
        if (!t.date) return false;

        // Date Logic
        if (filters && filters.dateFrom && t.date < filters.dateFrom) return false;
        if (filters && filters.dateTo && t.date > filters.dateTo) return false;

        // Entity Logic
        if (filters && filters.client && (t.entityType !== 'CLIENTE' || t.client !== filters.client)) return false;
        if (filters && filters.provider && (t.entityType !== 'PROVEEDOR' || t.client !== filters.provider)) return false;

        const status = (t.status || 'Pendiente').toLowerCase();
        if (status === 'pendiente') return false;

        return true;
    });

    // --- Chart 1: Income vs Expense (FILTERED range) ---
    // If we have strict filters, showing "Last 6 months" might be confusing if start/end is custom.
    // Let's adapt: If calcTxns > 0, we bin them by Month (or even Day if range is short?)
    // For simplicity, let's keep the "6 Months Binning" but apply it to the FILTERED set.
    // If the filter is ONE month, we get 1 bar.

    // We need to determine the bins dynamically based on data? OR just stick to "Last 6 months of relative to Today" but only fill with filtered data?
    // User expects: "Date from X to Y", I want to see bars for that range. 
    // Let's stick to "Last 6 Months" structure for now to avoid massive re-write, but aggregate the filtered data.
    // Result: If I filter "Jan 2020", all other 5 months will be 0. Correct.

    const buildMonthBuckets = (from, to) => {
        const parseDate = (value) => {
            if (!value) return null;
            const parsed = new Date(value);
            return Number.isNaN(parsed.getTime()) ? null : parsed;
        };
        const startRaw = parseDate(from);
        const endRaw = parseDate(to);
        if (!startRaw && !endRaw) return null;

        const start = startRaw || endRaw;
        const end = endRaw || startRaw;
        if (!start || !end) return null;

        let rangeStart = new Date(start.getFullYear(), start.getMonth(), 1);
        let rangeEnd = new Date(end.getFullYear(), end.getMonth(), 1);
        if (rangeStart > rangeEnd) {
            const tmp = rangeStart;
            rangeStart = rangeEnd;
            rangeEnd = tmp;
        }

        const includeYear = rangeStart.getFullYear() !== rangeEnd.getFullYear();
        const buckets = [];
        const cursor = new Date(rangeStart);
        while (cursor <= rangeEnd) {
            const label = cursor.toLocaleString('es-MX', { month: 'short' }) + (includeYear ? ` ${cursor.getFullYear()}` : '');
            buckets.push({
                year: cursor.getFullYear(),
                month: cursor.getMonth(),
                label
            });
            cursor.setMonth(cursor.getMonth() + 1);
        }
        return buckets;
    };

    const last6Months = [];
    const today = new Date();
    for (let i = 5; i >= 0; i--) {
        const d = new Date(today.getFullYear(), today.getMonth() - i, 1);
        last6Months.push({
            year: d.getFullYear(),
            month: d.getMonth(),
            label: d.toLocaleString('es-MX', { month: 'short' })
        });
    }

    const monthBuckets = buildMonthBuckets(filters?.dateFrom, filters?.dateTo);
    const chartMonths = (monthBuckets && monthBuckets.length > 0) ? monthBuckets : last6Months;

    calcTxns.forEach(t => {
        if (!t.date) return;
        const tDate = new Date(t.date);
        const bin = chartMonths.find(m => m.year === tDate.getFullYear() && m.month === tDate.getMonth());
        if (bin) {
            const amt = (t.amountMXN || 0);
            if (t.type === 'INCOME') {
                bin.income = (bin.income || 0) + amt;
            } else if (t.type === 'EXPENSE' || t.type === 'COST') {
                bin.expense = (bin.expense || 0) + amt;
            }
        }
    });

    const ctx1 = document.getElementById('bizChartIncomeExpense');
    if (ctx1) {
        state.charts.bizIncomeExpense = new Chart(ctx1, {
            type: 'bar',
            data: {
                labels: chartMonths.map(m => m.label),
                datasets: [
                    { label: 'Ingresos', data: chartMonths.map(m => m.income), backgroundColor: '#cde52d', borderRadius: 4 },
                    { label: 'Egresos', data: chartMonths.map(m => m.expense), backgroundColor: '#ef4444', borderRadius: 4 }
                ]
            },
            options: {
                responsive: true, maintainAspectRatio: false,
                plugins: { legend: { position: 'bottom' } },
                scales: {
                    x: { grid: { display: false } },
                    y: { beginAtZero: true, ticks: { callback: v => '$' + (v / 1000).toFixed(0) + 'k' } }
                }
            }
        });
    }

    // --- Chart 2: Expenses by Category (Doughnut) ---
    // [Filtered Data]
    const expenses = calcTxns.filter(t => t.type === 'EXPENSE' || t.type === 'COST');
    const catTotals = {};
    expenses.forEach(t => { const cat = t.category || 'Sin Cat'; catTotals[cat] = (catTotals[cat] || 0) + (t.amountMXN || 0); });
    const ctx2 = document.getElementById('bizChartExpenseCat');
    if (ctx2) {
        state.charts.bizExpenseCat = new Chart(ctx2, {
            type: 'doughnut',
            data: {
                labels: Object.keys(catTotals),
                datasets: [{ data: Object.values(catTotals), backgroundColor: ['#ef4444', '#f97316', '#f59e0b', '#84cc16', '#10b981', '#06b6d4', '#3b82f6', '#6366f1'], borderWidth: 0 }]
            },
            options: { responsive: true, maintainAspectRatio: false, cutout: '70%', plugins: { legend: { position: 'right', labels: { boxWidth: 12 } } } }
        });
    }

    // --- Chart 3: Daily Trend (Filtered Month) ---
    // [Filtered Data]
    const dailyData = {};
    calcTxns.forEach(t => {
        if (!t.date) return;
        if (!dailyData[t.date]) dailyData[t.date] = { income: 0, expense: 0 };
        const amt = (t.amountMXN || 0);
        if (t.type === 'INCOME') dailyData[t.date].income += amt;
        else if (t.type === 'EXPENSE' || t.type === 'COST') dailyData[t.date].expense += amt;
    });
    const dates = Object.keys(dailyData).sort();
    const ctx3 = document.getElementById('bizChartDailyTrend');
    if (ctx3) {
        state.charts.bizDailyTrend = new Chart(ctx3, {
            type: 'line',
            data: {
                labels: dates.map(d => d.split('-')[2]), // Just day number
                datasets: [
                    { label: 'Ingresos', data: dates.map(d => dailyData[d].income), borderColor: '#cde52d', backgroundColor: '#cde52d', tension: 0.3, pointRadius: 3 },
                    { label: 'Egresos', data: dates.map(d => dailyData[d].expense), borderColor: '#ef4444', backgroundColor: '#ef4444', tension: 0.3, pointRadius: 3 }
                ]
            },
            options: {
                responsive: true, maintainAspectRatio: false,
                plugins: { legend: { position: 'bottom' } },
                scales: { x: { grid: { display: false } }, y: { beginAtZero: true } }
            }
        });
    }

    // --- Chart 4: Bank Distribution ---
    // [Filtered Data]
    const bankTotals = {};
    calcTxns.forEach(t => { const amt = (t.amountMXN || 0); const bank = t.bank || 'Sin Banco'; bankTotals[bank] = (bankTotals[bank] || 0) + amt; });
    const ctx4 = document.getElementById('bizChartBankDist');
    if (ctx4) {
        state.charts.bizBankDist = new Chart(ctx4, {
            type: 'doughnut',
            data: { labels: Object.keys(bankTotals), datasets: [{ data: Object.values(bankTotals), backgroundColor: ['#3b82f6', '#10b981', '#f59e0b', '#ec4899', '#8b5cf6'], borderWidth: 0 }] },
            options: { responsive: true, maintainAspectRatio: false, cutout: '60%', plugins: { legend: { position: 'right', labels: { boxWidth: 12 } } } }
        });
    }

    // Colors for series
    const seriesColors = ['#cde52d', '#ef4444', '#3b82f6', '#f97316', '#a855f7'];

    // --- Chart 5: Top Clients Evolution (Line) ---
    // 1. Identify Top Clients in the FILTERED set
    // Note: If I filter Client=X, then Top Clients is just X. 
    const clientTotals = {};
    calcTxns.forEach(t => {
        if (t.entityType !== 'CLIENTE') return;
        const name = t.client || 'Anónimo';
        clientTotals[name] = (clientTotals[name] || 0) + (t.amountMXN || 0);
    });

    // If filtered, we might have few.
    const topClients = Object.entries(clientTotals).sort((a, b) => b[1] - a[1]).slice(0, 5).map(x => x[0]);

    // 2. Build Datasets using FILTERED txns or ALL?
    // If I filter by Date Range X-Y, I want to see the evolution WITHIN X-Y.
    // The previous logic hardcoded "last6Months".
    // We should really plot the dates available in the filtered set.
    // BUT for stability let's stick to the buckets we defined (Last 6 Months) for x-axis 
    // AND only populate with calcTxns data.
    // This means if I pick a date range outside last 6 months, chart is empty.
    // Improve: If we want to be truly dynamic we would rebuild x-axis based on dateFrom/dateTo.
    // For now, let's stick to "Last 6 Months" axis but fill with filtered data (so it respects Client filter).

    const clientDatasets = topClients.map((client, index) => {
        const data = chartMonths.map(m => {
            return calcTxns.reduce((sum, t) => {
                if (t.entityType === 'CLIENTE' && (t.client || 'Anónimo') === client) {
                    const d = new Date(t.date);
                    if (d.getFullYear() === m.year && d.getMonth() === m.month) {
                        return sum + (t.amountMXN || 0);
                    }
                }
                return sum;
            }, 0);
        });
        return { label: client, data: data, borderColor: seriesColors[index % seriesColors.length], backgroundColor: seriesColors[index % seriesColors.length], tension: 0.3, pointRadius: 3 };
    });

    const ctx5 = document.getElementById('bizChartTopClients');
    if (ctx5) {
        state.charts.bizTopClients = new Chart(ctx5, { type: 'line', data: { labels: chartMonths.map(m => m.label), datasets: clientDatasets }, options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { position: 'bottom', labels: { boxWidth: 10, usePointStyle: true } } }, scales: { x: { grid: { display: false } }, y: { beginAtZero: true, ticks: { callback: v => v >= 1000 ? '$' + (v / 1000).toFixed(0) + 'k' : '$' + v } } } } });
    }

    // --- Chart 6: Top Providers Evolution (Line) ---
    const provTotals = {};
    calcTxns.forEach(t => {
        if (t.entityType !== 'PROVEEDOR') return;
        const name = t.client || 'Anónimo';
        provTotals[name] = (provTotals[name] || 0) + (t.amountMXN || 0);
    });
    const topProv = Object.entries(provTotals).sort((a, b) => b[1] - a[1]).slice(0, 5).map(x => x[0]);

    const provDatasets = topProv.map((prov, index) => {
        const data = chartMonths.map(m => {
            return calcTxns.reduce((sum, t) => {
                if (t.entityType === 'PROVEEDOR' && (t.client || 'Anónimo') === prov) {
                    const d = new Date(t.date);
                    if (d.getFullYear() === m.year && d.getMonth() === m.month) {
                        return sum + (t.amountMXN || 0);
                    }
                }
                return sum;
            }, 0);
        });
        return { label: prov, data: data, borderColor: seriesColors[index % seriesColors.length], backgroundColor: seriesColors[index % seriesColors.length], tension: 0.3, pointRadius: 3 };
    });

    const ctx6 = document.getElementById('bizChartTopProviders');
    if (ctx6) {
        state.charts.bizTopProviders = new Chart(ctx6, { type: 'line', data: { labels: chartMonths.map(m => m.label), datasets: provDatasets }, options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { position: 'bottom', labels: { boxWidth: 10, usePointStyle: true } } }, scales: { x: { grid: { display: false } }, y: { beginAtZero: true, ticks: { callback: v => v >= 1000 ? '$' + (v / 1000).toFixed(0) + 'k' : '$' + v } } } } });
    }

    // --- Chart 7: Subcategories Monthly Evolution (Line) ---
    // Collect all categories grouped by type
    const categoryByType = {
        INCOME: {},
        EXPENSE: {},
        COST: {}
    };

    calcTxns.forEach(t => {
        const type = t.type;
        if (!['INCOME', 'EXPENSE', 'COST'].includes(type)) return;

        const cat = t.category || 'Sin Categoría';
        if (!categoryByType[type][cat]) {
            categoryByType[type][cat] = 0;
        }
        categoryByType[type][cat] += (t.amountMXN || 0);
    });

    // Get top 3 subcategories for each type
    const topIncome = Object.entries(categoryByType.INCOME)
        .sort((a, b) => b[1] - a[1])
        .slice(0, 3)
        .map(x => x[0]);

    const topExpense = Object.entries(categoryByType.EXPENSE)
        .sort((a, b) => b[1] - a[1])
        .slice(0, 3)
        .map(x => x[0]);

    const topCost = Object.entries(categoryByType.COST)
        .sort((a, b) => b[1] - a[1])
        .slice(0, 3)
        .map(x => x[0]);

    // Build datasets for each subcategory (monthly evolution)
    const allSubcategories = [...topIncome, ...topExpense, ...topCost];
    const subcatColors = {
        // Income colors (greens/blues)
        [topIncome[0]]: '#10b981',
        [topIncome[1]]: '#0d85fa',
        [topIncome[2]]: '#84cc16',
        // Expense colors (reds)
        [topExpense[0]]: '#ef4444',
        [topExpense[1]]: '#f97316',
        [topExpense[2]]: '#dc2626',
        // Cost colors (oranges)
        [topCost[0]]: '#f59e0b',
        [topCost[1]]: '#fb923c',
        [topCost[2]]: '#ea580c'
    };

    const subcatDatasets = allSubcategories.filter(Boolean).map(subcat => {
        const data = chartMonths.map(m => {
            return calcTxns.reduce((sum, t) => {
                if ((t.category || 'Sin Categoría') === subcat) {
                    const d = new Date(t.date);
                    if (d.getFullYear() === m.year && d.getMonth() === m.month) {
                        return sum + (t.amountMXN || 0);
                    }
                }
                return sum;
            }, 0);
        });

        return {
            label: subcat,
            data: data,
            borderColor: subcatColors[subcat] || '#6b7280',
            backgroundColor: subcatColors[subcat] || '#6b7280',
            tension: 0.3,
            pointRadius: 4,
            pointHoverRadius: 6,
            borderWidth: 2
        };
    });

    const ctxSubcat = document.getElementById('bizChartSubcategoriesMonthly');
    if (ctxSubcat && subcatDatasets.length > 0) {
        state.charts.bizSubcategoriesMonthly = new Chart(ctxSubcat, {
            type: 'line',
            data: {
                labels: chartMonths.map(m => m.label),
                datasets: subcatDatasets
            },
            options: {
                responsive: true,
                maintainAspectRatio: false,
                plugins: {
                    legend: {
                        position: 'top',
                        labels: {
                            boxWidth: 12,
                            padding: 15,
                            font: { size: 11 }
                        }
                    },
                    tooltip: {
                        callbacks: {
                            label: function (context) {
                                const label = context.dataset.label || '';
                                const value = context.parsed.y || 0;
                                return label + ': $' + value.toLocaleString('es-MX');
                            }
                        }
                    }
                },
                scales: {
                    x: {
                        grid: { display: false }
                    },
                    y: {
                        beginAtZero: true,
                        ticks: {
                            callback: v => v >= 1000 ? '$' + (v / 1000).toFixed(0) + 'k' : '$' + v
                        }
                    }
                }
            }
        });
    }

};


const renderBusinessCashFlow = () => {
    const { transactions } = state.businessData;
    const months = ['Enero', 'Febrero', 'Marzo', 'Abril', 'Mayo', 'Junio', 'Julio', 'Agosto', 'Septiembre', 'Octubre', 'Noviembre', 'Diciembre'];

    const role = String(state.user?.role || '').toLowerCase().trim();
    const isCoachee = role === 'client' || role === 'coachee' || role === 'user';

    // 1. Helper to get monthly totals by category
    const annualBudget = state.businessData.annualBudget || ensureBusinessAnnualBudget();
    const totalExpensesMXN = annualBudget.expenses.reduce((sum, item) => sum + (item.mxn || 0), 0);
    const totalExpensesUSD = annualBudget.expenses.reduce((sum, item) => sum + (item.usd || 0), 0);
    const totalPayrollMXN = annualBudget.payroll.reduce((sum, item) => sum + (item.mxn || 0), 0);
    const totalPayrollUSD = annualBudget.payroll.reduce((sum, item) => sum + (item.usd || 0), 0);

    const getMonthlyCategoryTotals = (typeFilter) => {
        const relevantTxns = transactions.filter(t =>
            typeFilter(t.type) && (t.status || 'Pendiente').toLowerCase() !== 'pendiente'
        );

        // Get unique categories
        const categories = [...new Set(relevantTxns.map(t => t.category || 'Otros'))].sort();

        return categories.map(cat => {
            const monthlyValues = months.map((_, i) => {
                const monthTxns = relevantTxns.filter(t => {
                    if (!t.date || (t.category || 'Otros') !== cat) return false;
                    const parts = String(t.date).split('-');
                    if (parts.length !== 3) return false;
                    const monthIndex = parseInt(parts[1], 10) - 1;
                    return monthIndex === i;
                });

                return {
                    mxn: monthTxns.reduce((s, t) => s + (t.amountMXN || 0), 0),
                    usd: monthTxns.reduce((s, t) => s + (t.amountUSD || 0), 0)
                };
            });
            return { category: cat, monthlyValues };
        });
    };

    // 2. Data for tables
    const incomeRows = getMonthlyCategoryTotals(t => t === 'INCOME');
    const expenseRows = getMonthlyCategoryTotals(t => t === 'EXPENSE');
    const costRows = getMonthlyCategoryTotals(t => t === 'COST');

    // 3. Totals (preserve for summary rows if needed, or simply render rows)
    // We can compute totals from the rows on the fly or reuse previous logic for a "Total" row.
    const getTotals = (rows) => {
        return months.map((_, i) => ({
            mxn: rows.reduce((s, r) => s + r.monthlyValues[i].mxn, 0),
            usd: rows.reduce((s, r) => s + r.monthlyValues[i].usd, 0)
        }));
    };

    const totalIncome = getTotals(incomeRows);
    const totalExpenses = getTotals(expenseRows);
    const totalCosts = getTotals(costRows);

    // --- Cuentas por Cobrar / Pagar Monthly Calculation ---
    const accountsMonthly = {
        receivable: Array(12).fill(null).map(() => ({ mxn: 0, usd: 0 })),
        payable: Array(12).fill(null).map(() => ({ mxn: 0, usd: 0 }))
    };

    (state.businessData.transactions || []).forEach(t => {
        if (!t.date) return;
        const status = (t.status || 'Pendiente').toLowerCase();
        const mxn = Number(t.amountMXN) || 0;
        const usd = Number(t.amountUSD) || 0;
        // Date string YYYY-MM-DD. Split to avoid timezone issues.
        const parts = t.date.split('-');
        if (parts.length === 3) {
            const monthIndex = parseInt(parts[1], 10) - 1;
            if (monthIndex >= 0 && monthIndex < 12) {
                if (status === 'pendiente') {
                    if (t.type === 'INCOME') {
                        accountsMonthly.receivable[monthIndex].mxn += mxn;
                        accountsMonthly.receivable[monthIndex].usd += usd;
                    } else if (t.type === 'COST' || t.type === 'EXPENSE') {
                        accountsMonthly.payable[monthIndex].mxn += mxn;
                        accountsMonthly.payable[monthIndex].usd += usd;
                    }
                }
            }
        }
    });


    return `
    <div class="space-y-6">
        <div class="flex items-center justify-between">
            <div>
                <h2 class="text-3xl font-black text-zinc-900 dark:text-white">Flujo de Caja Anual</h2>
                <p class="text-zinc-500">Visualiza el comportamiento mensual de tu dinero en Pesos y Dólares.</p>
            </div>
        </div>

        <!-- 1. RESUMEN DE INGRESOS -->
        <div class="bg-white dark:bg-zinc-900 rounded-3xl border border-zinc-200 dark:border-zinc-800 shadow-xl overflow-hidden">
            <div class="bg-emerald-50 dark:bg-emerald-900/10 border-b border-emerald-100 dark:border-emerald-900/20 p-4 flex items-center gap-3">
                 <div class="w-10 h-10 rounded-xl bg-emerald-100 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400 flex items-center justify-center shadow-sm">
                    <i data-lucide="trending-up" width="20"></i>
                </div>
                <h3 class="font-bold text-emerald-900 dark:text-emerald-400 uppercase tracking-wider text-sm">Resumen de Ingresos</h3>
            </div>

            <div class="overflow-x-auto custom-scrollbar">
                <table class="w-full text-right text-sm whitespace-nowrap border-collapse">
                    <thead class="bg-white dark:bg-zinc-900 text-xs font-bold text-zinc-500 uppercase">
                        <tr>
                            <th rowspan="2" class="p-4 text-left sticky left-0 bg-white dark:bg-zinc-900 border-r border-zinc-200 dark:border-zinc-700 min-w-[200px] z-20">Categoría</th>
                            ${months.map(m => `<th colspan="2" class="p-2 text-center border-b border-zinc-100 dark:border-zinc-800 border-l border-zinc-100 dark:border-zinc-800 min-w-[200px] text-zinc-400">${m}</th>`).join('')}
                        </tr>
                        <tr>
                            ${months.map(() => `
                                <th class="p-2 text-center text-xs border-l border-zinc-100 dark:border-zinc-800 border-b border-zinc-100 dark:border-zinc-800 text-zinc-400">MXN</th>
                                <th class="p-2 text-center text-xs border-r border-zinc-100 dark:border-zinc-800 border-b border-zinc-100 dark:border-zinc-800 text-zinc-400">USD</th>
                            `).join('')}
                        </tr>
                    </thead>
                    <tbody class="divide-y divide-zinc-100 dark:divide-zinc-800">
                        ${incomeRows.length > 0 ? incomeRows.map(row => `
                        <tr class="group hover:bg-zinc-50 dark:hover:bg-zinc-800/20 transition-colors">
                            <td class="p-4 text-left font-medium text-emerald-600 sticky left-0 bg-white dark:bg-zinc-900 group-hover:bg-zinc-50 dark:group-hover:bg-zinc-800/20 border-r border-zinc-200 dark:border-zinc-700 z-10 flex items-center gap-2">
                                <span class="w-1.5 h-1.5 rounded-full bg-emerald-500"></span> ${row.category}
                            </td>
                            ${row.monthlyValues.map(v => `
                                <td class="p-4 font-mono font-medium border-l border-zinc-100 dark:border-zinc-800 text-zinc-900 dark:text-white">$${v.mxn.toLocaleString('es-MX', { maximumFractionDigits: 0 })}</td>
                                <td class="p-4 font-mono font-medium border-r border-zinc-100 dark:border-zinc-800 text-zinc-500 dark:text-zinc-400">$${v.usd.toLocaleString('en-US', { maximumFractionDigits: 0 })}</td>
                            `).join('')}
                        </tr>
                        `).join('') : `
                        <tr><td colspan="${1 + months.length * 2}" class="p-4 text-center text-zinc-500">No hay ingresos registrados</td></tr>
                        `}
                        
                        <!-- Total Row -->
                        <tr class="bg-zinc-50 dark:bg-zinc-800/30 font-bold border-t border-zinc-200 dark:border-zinc-700">
                            <td class="p-4 text-left sticky left-0 bg-zinc-50 dark:bg-zinc-800/30 border-r border-zinc-200 dark:border-zinc-700 z-10 uppercase text-xs tracking-wider text-zinc-700 dark:text-zinc-300">Total Ingresos</td>
                            ${totalIncome.map(v => `
                                <td class="p-4 font-mono border-l border-zinc-200/50 dark:border-zinc-700/50 text-emerald-600">$${v.mxn.toLocaleString('es-MX', { maximumFractionDigits: 0 })}</td>
                                <td class="p-4 font-mono border-r border-zinc-200/50 dark:border-zinc-700/50 text-emerald-600">$${v.usd.toLocaleString('en-US', { maximumFractionDigits: 0 })}</td>
                            `).join('')}
                        </tr>
                    </tbody>
                </table>
            </div>
        </div>


        <!-- 2. RESUMEN DE COSTOS -->
        <div class="bg-white dark:bg-zinc-900 rounded-3xl border border-zinc-200 dark:border-zinc-800 shadow-xl overflow-hidden">
            <div class="bg-orange-50 dark:bg-orange-900/10 border-b border-orange-100 dark:border-orange-900/20 p-4 flex items-center gap-3">
                 <div class="w-10 h-10 rounded-xl bg-orange-100 dark:bg-orange-900/30 text-orange-600 dark:text-orange-400 flex items-center justify-center shadow-sm">
                    <i data-lucide="package" width="20"></i>
                </div>
                <h3 class="font-bold text-orange-900 dark:text-orange-400 uppercase tracking-wider text-sm">Resumen de Costos</h3>
            </div>

            <div class="overflow-x-auto custom-scrollbar">
                <table class="w-full text-right text-sm whitespace-nowrap border-collapse">
                    <thead class="bg-white dark:bg-zinc-900 text-xs font-bold text-zinc-500 uppercase">
                        <tr>
                            <th rowspan="2" class="p-4 text-left sticky left-0 bg-white dark:bg-zinc-900 border-r border-zinc-200 dark:border-zinc-700 min-w-[200px] z-20">Categoría</th>
                            ${months.map(m => `<th colspan="2" class="p-2 text-center border-b border-zinc-100 dark:border-zinc-800 border-l border-zinc-100 dark:border-zinc-800 min-w-[200px] text-zinc-400">${m}</th>`).join('')}
                        </tr>
                        <tr>
                            ${months.map(() => `
                                <th class="p-2 text-center text-xs border-l border-zinc-100 dark:border-zinc-800 border-b border-zinc-100 dark:border-zinc-800 text-zinc-400">MXN</th>
                                <th class="p-2 text-center text-xs border-r border-zinc-100 dark:border-zinc-800 border-b border-zinc-100 dark:border-zinc-800 text-zinc-400">USD</th>
                            `).join('')}
                        </tr>
                    </thead>
                    <tbody class="divide-y divide-zinc-100 dark:divide-zinc-800">
                        ${costRows.length > 0 ? costRows.map(row => `
                        <tr class="group hover:bg-zinc-50 dark:hover:bg-zinc-800/20 transition-colors">
                            <td class="p-4 text-left font-medium text-orange-600 sticky left-0 bg-white dark:bg-zinc-900 group-hover:bg-zinc-50 dark:group-hover:bg-zinc-800/20 border-r border-zinc-200 dark:border-zinc-700 z-10 flex items-center gap-2">
                                <span class="w-1.5 h-1.5 rounded-full bg-orange-500"></span> ${row.category}
                            </td>
                            ${row.monthlyValues.map(v => `
                                <td class="p-4 font-mono font-medium border-l border-zinc-100 dark:border-zinc-800 text-zinc-900 dark:text-white">$${v.mxn.toLocaleString('es-MX', { maximumFractionDigits: 0 })}</td>
                                <td class="p-4 font-mono font-medium border-r border-zinc-100 dark:border-zinc-800 text-zinc-500 dark:text-zinc-400">$${v.usd.toLocaleString('en-US', { maximumFractionDigits: 0 })}</td>
                            `).join('')}
                        </tr>
                        `).join('') : `
                        <tr><td colspan="${1 + months.length * 2}" class="p-4 text-center text-zinc-500">No hay costos registrados</td></tr>
                        `}
                        
                        <!-- Total Row -->
                        <tr class="bg-zinc-50 dark:bg-zinc-800/30 font-bold border-t border-zinc-200 dark:border-zinc-700">
                            <td class="p-4 text-left sticky left-0 bg-zinc-50 dark:bg-zinc-800/30 border-r border-zinc-200 dark:border-zinc-700 z-10 uppercase text-xs tracking-wider text-zinc-700 dark:text-zinc-300">Total Costos</td>
                            ${totalCosts.map(v => `
                                <td class="p-4 font-mono border-l border-zinc-200/50 dark:border-zinc-700/50 text-orange-600">$${v.mxn.toLocaleString('es-MX', { maximumFractionDigits: 0 })}</td>
                                <td class="p-4 font-mono border-r border-zinc-200/50 dark:border-zinc-700/50 text-orange-600">$${v.usd.toLocaleString('en-US', { maximumFractionDigits: 0 })}</td>
                            `).join('')}
                        </tr>
                    </tbody>
                </table>
            </div>
        </div>

        <!-- 3. RESUMEN DE EGRESOS -->
        <div class="bg-white dark:bg-zinc-900 rounded-3xl border border-zinc-200 dark:border-zinc-800 shadow-xl overflow-hidden">
            <div class="bg-red-50 dark:bg-red-900/10 border-b border-red-100 dark:border-red-900/20 p-4 flex items-center gap-3">
                 <div class="w-10 h-10 rounded-xl bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400 flex items-center justify-center shadow-sm">
                    <i data-lucide="trending-down" width="20"></i>
                </div>
                <h3 class="font-bold text-red-900 dark:text-red-400 uppercase tracking-wider text-sm">Resumen de Gastos</h3>
            </div>

            <div class="overflow-x-auto custom-scrollbar">
                <table class="w-full text-right text-sm whitespace-nowrap border-collapse">
                    <thead class="bg-white dark:bg-zinc-900 text-xs font-bold text-zinc-500 uppercase">
                        <tr>
                            <th rowspan="2" class="p-4 text-left sticky left-0 bg-white dark:bg-zinc-900 border-r border-zinc-200 dark:border-zinc-700 min-w-[200px] z-20">Categoría</th>
                            ${months.map(m => `<th colspan="2" class="p-2 text-center border-b border-zinc-100 dark:border-zinc-800 border-l border-zinc-100 dark:border-zinc-800 min-w-[200px] text-zinc-400">${m}</th>`).join('')}
                        </tr>
                        <tr>
                            ${months.map(() => `
                                <th class="p-2 text-center text-xs border-l border-zinc-100 dark:border-zinc-800 border-b border-zinc-100 dark:border-zinc-800 text-zinc-400">MXN</th>
                                <th class="p-2 text-center text-xs border-r border-zinc-100 dark:border-zinc-800 border-b border-zinc-100 dark:border-zinc-800 text-zinc-400">USD</th>
                            `).join('')}
                        </tr>
                    </thead>
                    <tbody class="divide-y divide-zinc-100 dark:divide-zinc-800">
                        ${expenseRows.length > 0 ? expenseRows.map(row => `
                        <tr class="group hover:bg-zinc-50 dark:hover:bg-zinc-800/20 transition-colors">
                            <td class="p-4 text-left font-medium text-red-600 sticky left-0 bg-white dark:bg-zinc-900 group-hover:bg-zinc-50 dark:group-hover:bg-zinc-800/20 border-r border-zinc-200 dark:border-zinc-700 z-10 flex items-center gap-2">
                                <span class="w-1.5 h-1.5 rounded-full bg-red-500"></span> ${row.category}
                            </td>
                            ${row.monthlyValues.map(v => `
                                <td class="p-4 font-mono font-medium border-l border-zinc-100 dark:border-zinc-800 text-zinc-900 dark:text-white">$${v.mxn.toLocaleString('es-MX', { maximumFractionDigits: 0 })}</td>
                                <td class="p-4 font-mono font-medium border-r border-zinc-100 dark:border-zinc-800 text-zinc-500 dark:text-zinc-400">$${v.usd.toLocaleString('en-US', { maximumFractionDigits: 0 })}</td>
                            `).join('')}
                        </tr>
                        `).join('') : `
                         <tr><td colspan="${1 + months.length * 2}" class="p-4 text-center text-zinc-500">No hay gastos registrados</td></tr>
                        `}

                        <!-- Total Row -->
                        <tr class="bg-zinc-50 dark:bg-zinc-800/30 font-bold border-t border-zinc-200 dark:border-zinc-700">
                            <td class="p-4 text-left sticky left-0 bg-zinc-50 dark:bg-zinc-800/30 border-r border-zinc-200 dark:border-zinc-700 z-10 uppercase text-xs tracking-wider text-zinc-700 dark:text-zinc-300">Total Gastos</td>
                            ${totalExpenses.map(v => `
                                <td class="p-4 font-mono border-l border-zinc-200/50 dark:border-zinc-700/50 text-red-600">$${v.mxn.toLocaleString('es-MX', { maximumFractionDigits: 0 })}</td>
                                <td class="p-4 font-mono border-r border-zinc-200/50 dark:border-zinc-700/50 text-red-600">$${v.usd.toLocaleString('en-US', { maximumFractionDigits: 0 })}</td>
                            `).join('')}
                        </tr>
                    </tbody>
                </table>
            </div>
        </div>


        <!-- CUENTAS POR COBRAR / PAGAR -->
        <div class="bg-white dark:bg-zinc-900 rounded-3xl border border-zinc-200 dark:border-zinc-800 shadow-xl overflow-hidden">
             <div class="bg-zinc-900 text-white font-bold p-4 text-center uppercase tracking-wider text-sm">
                CUENTAS POR COBRAR / PAGAR
            </div>
            <div class="overflow-x-auto custom-scrollbar">
                <table class="w-full text-right text-sm whitespace-nowrap border-collapse">
                    <thead class="bg-white dark:bg-zinc-900 text-xs font-bold text-zinc-500 uppercase">
                        <tr>
                            <th rowspan="2" class="p-4 text-left sticky left-0 bg-white dark:bg-zinc-900 border-r border-zinc-200 dark:border-zinc-700 min-w-[200px] z-20">Concepto</th>
                            ${months.map(m => `<th colspan="2" class="p-2 text-center border-b border-zinc-100 dark:border-zinc-800 border-l border-zinc-100 dark:border-zinc-800 min-w-[200px] text-zinc-400">${m}</th>`).join('')}
                        </tr>
                        <tr>
                            ${months.map(() => `
                                <th class="p-2 text-center text-xs border-l border-zinc-100 dark:border-zinc-800 border-b border-zinc-100 dark:border-zinc-800 text-zinc-400">MXN</th>
                                <th class="p-2 text-center text-xs border-r border-zinc-100 dark:border-zinc-800 border-b border-zinc-100 dark:border-zinc-800 text-zinc-400">USD</th>
                            `).join('')}
                        </tr>
                    </thead>
                    <tbody class="divide-y divide-zinc-100 dark:divide-zinc-800">
                        <tr>
                            <td class="p-4 font-bold bg-emerald-50 dark:bg-emerald-900/20 text-emerald-800 dark:text-emerald-400 uppercase sticky left-0 z-10 border-r border-zinc-200 dark:border-zinc-700">CUENTAS POR COBRAR</td>
                            ${accountsMonthly.receivable.map(v => `
                                <td class="p-4 font-mono font-bold text-emerald-600 border-l border-zinc-100 dark:border-zinc-800">$${v.mxn.toLocaleString('es-MX', { maximumFractionDigits: 0 })}</td>
                                <td class="p-4 font-mono font-bold text-emerald-600 border-r border-zinc-100 dark:border-zinc-800">$${v.usd.toLocaleString('en-US', { maximumFractionDigits: 0 })}</td>
                            `).join('')}
                        </tr>
                        <tr>
                            <td class="p-4 font-bold bg-red-50 dark:bg-red-900/20 text-red-800 dark:text-red-400 uppercase sticky left-0 z-10 border-r border-zinc-200 dark:border-zinc-700">CUENTAS POR PAGAR</td>
                            ${accountsMonthly.payable.map(v => `
                                <td class="p-4 font-mono font-bold text-red-600 border-l border-zinc-100 dark:border-zinc-800">$${v.mxn.toLocaleString('es-MX', { maximumFractionDigits: 0 })}</td>
                                <td class="p-4 font-mono font-bold text-red-600 border-r border-zinc-100 dark:border-zinc-800">$${v.usd.toLocaleString('en-US', { maximumFractionDigits: 0 })}</td>
                            `).join('')}
                        </tr>
                    </tbody>
                </table>
            </div>
        </div>

        <!-- 4. FLUJO NETO (Ingresos - Costos - Gastos) -->
        <div class="bg-white dark:bg-zinc-900 rounded-3xl border border-zinc-200 dark:border-zinc-800 shadow-xl overflow-hidden">
            <div class="bg-blue-50 dark:bg-blue-900/10 border-b border-blue-100 dark:border-blue-900/20 p-4 flex items-center gap-3">
                 <div class="w-10 h-10 rounded-xl bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 flex items-center justify-center shadow-sm">
                    <i data-lucide="activity" width="20"></i>
                </div>
                <h3 class="font-bold text-blue-900 dark:text-blue-400 uppercase tracking-wider text-sm">Flujo Neto (Ingresos - Gastos Totales)</h3>
            </div>

            <div class="overflow-x-auto custom-scrollbar">
                <table class="w-full text-right text-sm whitespace-nowrap border-collapse">
                    <thead class="bg-white dark:bg-zinc-900 text-xs font-bold text-zinc-500 uppercase">
                        <tr>
                            <th rowspan="2" class="p-4 text-left sticky left-0 bg-white dark:bg-zinc-900 border-r border-zinc-200 dark:border-zinc-700 min-w-[200px] z-20">Concepto</th>
                            ${months.map(m => `<th colspan="2" class="p-2 text-center border-b border-zinc-100 dark:border-zinc-800 border-l border-zinc-100 dark:border-zinc-800 min-w-[200px] text-zinc-400">${m}</th>`).join('')}
                        </tr>
                        <tr>
                            ${months.map(() => `
                                <th class="p-2 text-center text-xs border-l border-zinc-100 dark:border-zinc-800 border-b border-zinc-100 dark:border-zinc-800 text-zinc-400">MXN</th>
                                <th class="p-2 text-center text-xs border-r border-zinc-100 dark:border-zinc-800 border-b border-zinc-100 dark:border-zinc-800 text-zinc-400">USD</th>
                            `).join('')}
                        </tr>
                    </thead>
                    <tbody class="divide-y divide-zinc-100 dark:divide-zinc-800">
                        <tr class="group hover:bg-zinc-50 dark:hover:bg-zinc-800/20 transition-colors font-bold">
                            <td class="p-4 text-left font-medium text-blue-600 sticky left-0 bg-white dark:bg-zinc-900 group-hover:bg-zinc-50 dark:group-hover:bg-zinc-800/20 border-r border-zinc-200 dark:border-zinc-700 z-10 flex items-center gap-2">
                                <span class="w-1.5 h-1.5 rounded-full bg-blue-500"></span> Flujo Neto
                            </td>
                            ${months.map((_, i) => {
        const netMXN = totalIncome[i].mxn - (totalCosts[i].mxn + totalExpenses[i].mxn);
        const netUSD = totalIncome[i].usd - (totalCosts[i].usd + totalExpenses[i].usd);
        const colorClassMXN = netMXN >= 0 ? 'text-blue-600' : 'text-red-500';
        const colorClassUSD = netUSD >= 0 ? 'text-blue-600' : 'text-red-500';
        return `
                                <td class="p-4 font-mono font-medium border-l border-zinc-100 dark:border-zinc-800 ${colorClassMXN}">$${netMXN.toLocaleString('es-MX', { maximumFractionDigits: 0 })}</td>
                                <td class="p-4 font-mono font-medium border-r border-zinc-100 dark:border-zinc-800 ${colorClassUSD}">$${netUSD.toLocaleString('en-US', { maximumFractionDigits: 0 })}</td>
                                `;
    }).join('')}
                        </tr>
                    </tbody>
                </table>
            </div>
        </div>

        <!-- 5. RENTABILIDAD (Flujo Neto / Ingresos) -->
        <div class="bg-white dark:bg-zinc-900 rounded-3xl border border-zinc-200 dark:border-zinc-800 shadow-xl overflow-hidden">
            <div class="bg-lime-50 dark:bg-lime-900/10 border-b border-lime-100 dark:border-lime-900/20 p-4 flex items-center gap-3">
                 <div class="w-10 h-10 rounded-xl bg-lime-100 dark:bg-lime-900/30 text-lime-600 dark:text-lime-400 flex items-center justify-center shadow-sm">
                    <i data-lucide="percent" width="20"></i>
                </div>
                <h3 class="font-bold text-lime-900 dark:text-lime-400 uppercase tracking-wider text-sm">Rentabilidad (Flujo Neto / Ingresos)</h3>
            </div>

            <div class="overflow-x-auto custom-scrollbar">
                <table class="w-full text-right text-sm whitespace-nowrap border-collapse">
                    <thead class="bg-white dark:bg-zinc-900 text-xs font-bold text-zinc-500 uppercase">
                        <tr>
                            <th rowspan="2" class="p-4 text-left sticky left-0 bg-white dark:bg-zinc-900 border-r border-zinc-200 dark:border-zinc-700 min-w-[200px] z-20">Concepto</th>
                            ${months.map(m => `<th colspan="2" class="p-2 text-center border-b border-zinc-100 dark:border-zinc-800 border-l border-zinc-100 dark:border-zinc-800 min-w-[200px] text-zinc-400">${m}</th>`).join('')}
                        </tr>
                        <tr>
                            ${months.map(() => `
                                <th class="p-2 text-center text-xs border-l border-zinc-100 dark:border-zinc-800 border-b border-zinc-100 dark:border-zinc-800 text-zinc-400">MXN</th>
                                <th class="p-2 text-center text-xs border-r border-zinc-100 dark:border-zinc-800 border-b border-zinc-100 dark:border-zinc-800 text-zinc-400">USD</th>
                            `).join('')}
                        </tr>
                    </thead>
                    <tbody class="divide-y divide-zinc-100 dark:divide-zinc-800">
                        <tr class="group hover:bg-zinc-50 dark:hover:bg-zinc-800/20 transition-colors font-bold">
                            <td class="p-4 text-left font-medium text-lime-600 sticky left-0 bg-white dark:bg-zinc-900 group-hover:bg-zinc-50 dark:group-hover:bg-zinc-800/20 border-r border-zinc-200 dark:border-zinc-700 z-10 flex items-center gap-2">
                                <span class="w-1.5 h-1.5 rounded-full bg-lime-500"></span> Rentabilidad %
                            </td>
                            ${months.map((_, i) => {
        const netMXN = totalIncome[i].mxn - (totalCosts[i].mxn + totalExpenses[i].mxn);
        const netUSD = totalIncome[i].usd - (totalCosts[i].usd + totalExpenses[i].usd);

        let rentMXN = 0;
        let rentUSD = 0;

        if (totalIncome[i].mxn !== 0) {
            rentMXN = (netMXN / totalIncome[i].mxn);
        }
        if (totalIncome[i].usd !== 0) {
            rentUSD = (netUSD / totalIncome[i].usd);
        }

        const colorClassMXN = rentMXN >= 0 ? 'text-lime-600 dark:text-lime-400' : 'text-red-500';
        const colorClassUSD = rentUSD >= 0 ? 'text-lime-600 dark:text-lime-400' : 'text-red-500';

        return `
                                <td class="p-4 font-mono font-medium border-l border-zinc-100 dark:border-zinc-800 ${colorClassMXN}">${(rentMXN * 100).toLocaleString('es-MX', { maximumFractionDigits: 1 })}%</td>
                                <td class="p-4 font-mono font-medium border-r border-zinc-100 dark:border-zinc-800 ${colorClassUSD}">${(rentUSD * 100).toLocaleString('en-US', { maximumFractionDigits: 1 })}%</td>
                                `;
    }).join('')}
                        </tr>
                    </tbody>
                </table>
            </div>
        </div>




    </div>
    `;
};



const renderBusinessAnnualBudget = () => {
    const annualBudget = ensureBusinessAnnualBudget();
    const expenses = annualBudget.expenses || [];
    const payroll = annualBudget.payroll || [];

    const sum = (rows, field) => (rows || []).reduce((s, r) => s + (Number(r[field]) || 0), 0);
    const format = (value, locale) => value.toLocaleString(locale, { maximumFractionDigits: 0 });

    const renderAnnualTable = (section, title, rows, totalLabel, totalIdPrefix) => `
    <div class="bg-white dark:bg-zinc-900 rounded-2xl border border-zinc-200 dark:border-zinc-800 overflow-hidden shadow-sm">
        <div class="bg-brand-lime/80 text-center font-bold text-black text-xs uppercase py-2 border-b border-black/10">${title}</div>
        <div class="overflow-x-auto">
            <table class="w-full text-sm">
                <thead class="bg-zinc-50 dark:bg-zinc-800/50 text-xs font-bold text-zinc-500 uppercase">
                    <tr>
                        <th class="p-3 text-left">Concepto</th>
                        <th class="p-3 text-right">Pesos (MXN)</th>
                        <th class="p-3 text-right">Dolares (USD)</th>
                    </tr>
                </thead>
                <tbody class="divide-y divide-zinc-100 dark:divide-zinc-800">
                    ${rows.map(row => `
                    <tr class="hover:bg-zinc-50 dark:hover:bg-zinc-800/30">
                        <td class="p-3 text-zinc-700 dark:text-zinc-300 font-medium">${row.label}</td>
                        <td class="p-2">
                            <input type="number" min="0" value="${row.mxn || ''}" onchange="actions.updateAnnualBudgetRow('${section}', '${row.key}', 'mxn', this.value)" class="w-full bg-transparent border border-transparent hover:border-zinc-200 dark:hover:border-zinc-700 rounded p-1 text-right font-mono text-zinc-700 dark:text-zinc-300 focus:border-brand-lime focus:ring-0">
                        </td>
                        <td class="p-2">
                            <input type="number" min="0" value="${row.usd || ''}" onchange="actions.updateAnnualBudgetRow('${section}', '${row.key}', 'usd', this.value)" class="w-full bg-transparent border border-transparent hover:border-zinc-200 dark:hover:border-zinc-700 rounded p-1 text-right font-mono text-zinc-700 dark:text-zinc-300 focus:border-brand-lime focus:ring-0">
                        </td>
                    </tr>
                    `).join('')}
                </tbody>
                <tfoot class="bg-zinc-900 text-white font-bold">
                    <tr>
                        <td class="p-3">${totalLabel}</td>
                        <td class="p-3 text-right font-mono" id="${totalIdPrefix}-mxn">$${format(sum(rows, 'mxn'), 'es-MX')}</td>
                        <td class="p-3 text-right font-mono" id="${totalIdPrefix}-usd">$${format(sum(rows, 'usd'), 'en-US')}</td>
                    </tr>
                </tfoot>
            </table>
        </div>
    </div>
    `;

    return `
    <div class="mb-8">
        <h2 class="text-3xl font-black text-zinc-900 dark:text-white mb-2">Presupuesto Anual</h2>
        <p class="text-zinc-500">Define tus metas de gasto anual en Pesos y Dolares.</p>
    </div>
    <div class="space-y-8">
        ${renderAnnualTable('expenses', 'Categoria', expenses, 'Total Gastos', 'annual-expenses-total')}
        ${renderAnnualTable('payroll', 'Nomina', payroll, 'Total Nomina', 'annual-payroll-total')}
    </div>
    `;
};

const renderBusinessBudget = () => {
    const role = String(state.user?.role || '').toLowerCase().trim();
    const isCoacheeRole = role === 'client' || role === 'coachee' || role === 'user';
    if (isCoacheeRole) {
        return renderBusinessAnnualBudget();
    }
    // Ensure data is initialized
    if (!state.businessData.budget.fixed) {
        actions.initBusinessBudget();
    }

    // Deconstruct safe arrays
    // Deconstruct safe arrays
    const { incomes, fixed, variable, debt, savings } = state.businessData.budget;

    // Helper to render each card section
    const renderSection = (title, category, items, icon, colorClass) => {
        // Calculate totals for footer
        const m1 = items.reduce((s, i) => s + (i.m1 || 0), 0);
        const m2 = items.reduce((s, i) => s + (i.m2 || 0), 0);
        const m3 = items.reduce((s, i) => s + (i.m3 || 0), 0);
        const avg = (m1 + m2 + m3) / 3;

        return `
    <div>
            <div class="p-4 ${colorClass} text-white flex justify-between items-center">
                <div class="flex items-center gap-2">
                    <i data-lucide="${icon}" width="20"></i>
                    <h3 class="font-bold text-lg uppercase tracking-wider">${title}</h3>
                </div>
                <button onclick="actions.addBudgetRow('${category}')" class="bg-white/20 hover:bg-white/30 text-white p-2 rounded-lg transition-colors backdrop-blur-sm" title="Agregar fila">
                    <i data-lucide="plus" width="20"></i>
                </button>
            </div>
            <div class="overflow-x-auto flex-1 custom-scrollbar">
                <table class="w-full text-sm">
                    <thead class="bg-zinc-50 dark:bg-zinc-800/50 text-xs font-bold text-zinc-500 uppercase sticky top-0 backdrop-blur-sm z-10">
                        <tr>
                            <th class="p-3 text-left w-1/3">Concepto</th>
                            <th class="p-3 text-center">Mes 1</th>
                            <th class="p-3 text-center">Mes 2</th>
                            <th class="p-3 text-center">Mes 3</th>
                            <th class="p-3 text-right text-zinc-900 dark:text-white">Promedio</th>
                            <th class="p-3 w-10"></th>
                        </tr>
                    </thead>
                    <tbody id="tbody-${category}" class="divide-y divide-zinc-100 dark:divide-zinc-800">
                        ${items.map(item => `<tr id="row-${item.id}" class="hover:bg-zinc-50 dark:hover:bg-zinc-800/30 group transition-colors border-b border-zinc-50 dark:border-zinc-800/50 last:border-0">${renderBudgetRow(category, item)}</tr>`).join('')}
                    </tbody>
                    <tfoot class="bg-zinc-50 dark:bg-zinc-800 font-bold text-zinc-900 dark:text-white border-t border-zinc-200 dark:border-zinc-700 sticky bottom-0 z-10 shadow-[0_-5px_10px_rgba(0,0,0,0.05)]">
                        <tr>
                            <td class="p-3 text-xs uppercase text-zinc-500">TOTALES</td>
                            <td class="p-3 text-center font-mono" id="total-${category}-m1">$${m1.toLocaleString('es-MX', { maximumFractionDigits: 0 })}</td>
                            <td class="p-3 text-center font-mono" id="total-${category}-m2">$${m2.toLocaleString('es-MX', { maximumFractionDigits: 0 })}</td>
                            <td class="p-3 text-center font-mono" id="total-${category}-m3">$${m3.toLocaleString('es-MX', { maximumFractionDigits: 0 })}</td>
                            <td class="p-3 text-right font-mono text-base" id="total-${category}-avg">$${avg.toLocaleString('es-MX', { maximumFractionDigits: 0 })}</td>
                            <td></td>
                        </tr>
                    </tfoot>
                </table>
            </div>
        </div>
    `;
    };

    return `
    <div>
        <div class="flex items-center gap-4">
             <button onclick="actions.goBackToQuiz()" class="bg-white dark:bg-zinc-900 p-2 rounded-full border border-zinc-200 dark:border-zinc-800 hover:bg-zinc-50 dark:hover:bg-zinc-800 transition-colors shadow-sm">
                <i data-lucide="arrow-left" width="24"></i>
            </button>
            <div>
                <h2 class="text-3xl font-black text-zinc-900 dark:text-white mb-2">Presupuesto Trimestral</h2>
                <p class="text-zinc-500 dark:text-zinc-400">Planifica, proyecta y controla tu dinero por trimestre.</p>
            </div>
        </div>

        <div class="flex gap-4 items-center">
            <!-- Global Currency Toggle -->
            <div class="bg-zinc-100 dark:bg-zinc-800 rounded-xl p-1 flex items-center shadow-inner">
                <button onclick="actions.setGlobalBudgetCurrency('MXN')" 
                        class="px-3 py-1.5 rounded-lg text-sm font-bold transition-all ${state.businessData.budgetCurrency === 'MXN' ? 'bg-white dark:bg-zinc-700 text-green-600 shadow-sm' : 'text-zinc-400 hover:text-zinc-600 dark:hover:text-zinc-300'}">
                    MXN
                </button>
                <button onclick="actions.setGlobalBudgetCurrency('USD')" 
                        class="px-3 py-1.5 rounded-lg text-sm font-bold transition-all ${state.businessData.budgetCurrency === 'USD' ? 'bg-white dark:bg-zinc-700 text-green-600 shadow-sm' : 'text-zinc-400 hover:text-zinc-600 dark:hover:text-zinc-300'}">
                    USD
                </button>
            </div>

            <button onclick="actions.showBudgetResults()" class="bg-zinc-900 dark:bg-white text-white dark:text-zinc-900 px-6 py-3 rounded-xl font-bold shadow-lg hover:scale-105 transition-transform flex items-center gap-2 group">
                <i data-lucide="bar-chart-2" class="group-hover:text-brand-lime transition-colors"></i> 
                Ver Resultados
            </button>
        </div>
    </div>

    <div class="flex flex-col gap-8 pb-20 animate-fade-in-up">
        ${renderSection('Ingresos Mensuales', 'incomes', incomes || [], 'wallet', 'bg-brand-lime')}
        ${renderSection('Gastos Fijos', 'fixed', fixed || [], 'anchor', 'bg-blue-600')}
        ${renderSection('Gastos Variables', 'variable', variable || [], 'trending-up', 'bg-purple-600')}
        ${renderSection('Deudas y Créditos', 'debt', debt || [], 'credit-card', 'bg-red-500')}
        ${renderSection('Ahorro e Inversión', 'savings', savings || [], 'piggy-bank', 'bg-emerald-500')}
    </div>
`;
};

// --- ACTIONS & INIT ---
const resolveUserFullName = (profile, sessionUser) => {
    const candidates = [
        profile?.full_name,
        sessionUser?.user_metadata?.full_name,
        sessionUser?.user_metadata?.name,
        sessionUser?.full_name,
        sessionUser?.name,
        sessionUser?.email ? sessionUser.email.split('@')[0] : '',
        sessionUser?.email
    ];

    for (const candidate of candidates) {
        const normalized = String(candidate || '').trim();
        if (normalized) return normalized;
    }

    return '';
};

const hydrateUserFromSession = (session) => {
    if (!session?.user || state.user) return;
    const fullName = resolveUserFullName(null, session.user);
    state.user = {
        id: session.user.id,
        email: session.user.email,
        full_name: fullName,
        role: session.user.user_metadata?.role || 'client',
        plan_type: session.user.user_metadata?.plan_type,
        created_at: session.user.created_at
    };
    applyCoachPlanType(state.user);
    const resolvedPlanType = resolveClientPlanType(state.user);
    if (resolvedPlanType) {
        state.user.plan_type = resolvedPlanType;
        if (resolvedPlanType !== 'negocio') {
            state.clientCategory = 'personal';
        }
    }
};

const getUserIdFromSession = async () => {
    if (state.user?.id) return state.user.id;
    if (lastAuthSession?.user?.id) return lastAuthSession.user.id;
    try {
        const { data, error } = await withTimeout(
            supabaseClient.auth.getSession(),
            15000,
            'getSession'
        );
        if (error) console.warn('Session check error:', error);
        hydrateUserFromSession(data?.session);
        return data?.session?.user?.id || null;
    } catch (error) {
        console.warn('Session check failed:', error);
        return null;
    }
};

const getEffectiveUserId = async () => {
    if (state.isViewingCoachee) {
        if (state.impersonatedUserId) return state.impersonatedUserId;
        if (state.user?.user_id) return state.user.user_id;
        if (state.user?.id) return state.user.id;
    }
    return await getUserIdFromSession();
};

const isAuthError = (error) => {
    const message = String(error?.message || '').toLowerCase();
    return error?.status === 401 || error?.status === 403 || message.includes('jwt') || message.includes('auth');
};

const isBusinessReadOnly = () => state.isViewingCoachee === true;

const ensureBusinessEditAllowed = () => {
    if (isBusinessReadOnly()) {
        showToast('Vista solo lectura para coachees.', 'warning');
        return false;
    }
    return true;
};

const withTimeout = (promise, ms, label) => {
    let timer;
    const timeout = new Promise((_, reject) => {
        timer = setTimeout(() => reject(new Error(`${label} timeout`)), ms);
    });
    return Promise.race([promise, timeout]).finally(() => clearTimeout(timer));
};

const normalizeRoleValue = (role) => {
    const normalized = String(role || '').toLowerCase().trim();
    if (!normalized) return '';
    if (normalized === 'coach' || normalized.startsWith('coach ') || normalized.startsWith('coach_') || normalized.startsWith('coach-')) {
        return 'coach';
    }
    if (normalized === 'coachee' || normalized.startsWith('coachee')) {
        return 'coachee';
    }
    if (normalized === 'client' || normalized === 'user') {
        return 'client';
    }
    return normalized;
};

const isCoachRole = (role) => normalizeRoleValue(role) === 'coach';
const isCoachFreePlan = (user) => {
    const plan = String(user?.plan_type || '').toLowerCase().trim();
    return plan === 'plan free' || user?._subscriptionExpired === true;
};

const normalizeCoachPlanValue = (value) => {
    const normalized = String(value || '').trim().toLowerCase();
    if (!normalized) return '';
    if (normalized.includes('basic')) return 'Plan Basic';
    if (normalized.includes('plus') || normalized.includes('premium')) return 'Plan Plus';
    if (normalized.includes('new')) return 'Plan New';
    return value;
};

const resolveCoachPlanType = (user) => {
    if (!isCoachRole(user?.role)) return '';
    const candidates = [user?.plan_type, user?.package_type, user?.plan];
    for (const candidate of candidates) {
        const resolved = normalizeCoachPlanValue(candidate);
        if (resolved) return resolved;
    }
    return '';
};

const isCoachPlusPlan = (user) => {
    const plan = normalizeCoachPlanValue(user?.plan_type || user?.package_type || user?.plan || '');
    return plan === 'Plan Plus';
};

const getCoachPlanContactLimit = (user) => {
    if (user?.coach_coachee_override_active === true) {
        const rawOverride = user?.coach_coachee_override_limit;
        if (rawOverride === -1) return null; // ilimitado
        const overrideValue = Number.parseInt(rawOverride, 10);
        if (Number.isFinite(overrideValue) && overrideValue >= 0) {
            return overrideValue;
        }
        // Si el override está activo pero no es válido, cae al plan base.
    }
    const plan = normalizeCoachPlanValue(user?.plan_type || user?.package_type || user?.plan || '');
    if (plan === 'Plan Basic') return 3;
    if (plan === 'Plan Plus') {
        const hasUpgrade = user?.coach_upgrade_active === true;
        return hasUpgrade ? 30 : 10;
    }
    return null;
};

const getCoachActiveContactCount = () => {
    const archivedIds = loadArchivedContactIds();
    return (state.coachees || []).filter(c => c && c.id && !archivedIds.has(c.id)).length;
};

const canCoachAddContact = () => {
    if (!isCoachRole(state.user?.role)) return true;
    const limit = getCoachPlanContactLimit(state.user);
    if (!limit) return true;
    return getCoachActiveContactCount() < limit;
};

const notifyCoachContactLimit = () => {
    const limit = getCoachPlanContactLimit(state.user);
    if (!limit) return;
    const count = getCoachActiveContactCount();
    showToast(`Limite alcanzado (${count}/${limit}). Elimina o archiva un contacto para agregar otro.`, 'warning');
};

const applyCoachPlanType = (user) => {
    if (!user || !isCoachRole(user?.role)) return '';
    const resolved = resolveCoachPlanType(user);
    if (resolved && user.plan_type !== resolved) {
        user.plan_type = resolved;
    }
    return resolved;
};

const normalizePlanTypeValue = (value) => {
    const normalized = String(value || '').toLowerCase().trim();
    if (!normalized) return '';
    if (normalized.startsWith('neg') || normalized.includes('business')) return 'negocio';
    if (normalized.startsWith('per')) return 'personal';
    return normalized;
};

const resolveClientPlanType = (user) => {
    const normalized = normalizePlanTypeValue(user?.plan_type);
    if (normalized) return normalized;
    const role = normalizeRoleValue(user?.role) || 'client';
    if (role === 'client' || role === 'coachee' || role === 'user') {
        return 'personal';
    }
    return '';
};

const canAccessBusinessModule = (user) => resolveClientPlanType(user) === 'negocio';

const redirectForRole = (role, profile, { force = false } = {}) => {
    if (!force) return;
    const effectiveRole = normalizeRoleValue(role) || 'client';

    let deferCoachUi = false;
    if (isCoachRole(effectiveRole)) {
        if (showLoadingScreen()) {
            window.__LOADER_BOOT_TS__ = Date.now();
            deferCoachUi = true;
        }
        // --- Redirect to 'plans' tab on first load if not dismissed ---
        // Note: `force` is only true on login, not hot reload, 
        // so we check state.user.coach_plans_dismissed.
        if (profile?.coach_plans_dismissed === false || state.user?.coach_plans_dismissed === false) {
            state.coachTab = 'plans';
        }

        if (profile && profile.show_welcome === false) {
            console.log("Coach has show_welcome=false, redirecting to Salud Financiera (Auth)");
            state.view = 'quiz_intro';
        } else {
            console.log("Coach has show_welcome=true, redirecting to Coach Module (Auth)");
            // --- PLAN BASIC: one-time redirect to 'plans' tab ---
            // Only do this once per page load (guard flag prevents double-fire from
            // onAuthStateChange SIGNED_IN + getSession both calling applySessionRedirect)
            // NOTE: _coachPlanTabInitDone may reset on hot reload or hard F5,
            // so we also check localStorage as a fallback.
            if (!window._coachPlanTabInitDone) {
                window._coachPlanTabInitDone = true;
                const coachId = profile?.id || state.user?.id;
                const isLocalDismissed = coachId ? localStorage.getItem('valori_coach_dismissed_' + coachId) === 'true' : false;

                const _dismissed = profile?.coach_plans_dismissed === true || state.user?.coach_plans_dismissed === true || isLocalDismissed;
                const _explicitlyNotDismissed = profile?.coach_plans_dismissed === false || state.user?.coach_plans_dismissed === false;

                if (_explicitlyNotDismissed && !_dismissed) {
                    state.coachTab = 'plans';
                    console.log('[CoachPlans] Coach with plans not dismissed → coachTab set to plans');
                }
            }
            state.view = 'coach_module';
        }
    } else {
        console.log("Redirecting to Client Module (Vision 360) (Auth)");
        state.view = 'client_module';
        state.clientTab = 'vision360';
    }

    if (deferCoachUi) {
        requestAnimationFrame(() => requestAnimationFrame(() => updateUI()));
    } else {
        updateUI();
    }
};


const resolveSessionProfile = async (session) => {
    if (!session?.user) return { role: 'client', profile: null };

    let profile = null;
    try {
        const { data, error } = await withTimeout(
            supabaseClient
                .from('profiles')
                .select('*')
                .eq('id', session.user.id)
                .single(),
            15000,
            'fetchProfile'
        );
        profile = data;
        if (error) console.warn("Error fetching profile on auth:", error);
        if (profile && profile.admin_blocked === true) {
            const now = Date.now();
            if (now - blockedAccessHandledAt > 1500) {
                showToast('Acceso bloqueado por el administrador.', 'error');
            }
            blockedAccessHandledAt = now;
            performLogout();
            return { role: 'blocked', profile };
        }
    } catch (error) {
        console.warn("Exception fetching profile on auth:", error);
    }

    const role = normalizeRoleValue(profile?.role || session.user.user_metadata?.role || 'client') || 'client';

    // Determine active coach relationship
    let hasActiveCoach = false;
    let hasPendingCoach = false;
    let linkedCoachId = null;
    if (role === 'client' || role === 'coachee') {
        try {
            const { data: rels, error: relsError } = await supabaseClient
                .from('coaching_relationships')
                .select('id, status, coach_id')
                .eq('coachee_id', session.user.id)
                .limit(1);
            if (!relsError && rels && rels.length > 0) {
                const status = (rels[0].status || '').toLowerCase();
                linkedCoachId = rels[0].coach_id || null;
                if (status === 'active') {
                    hasActiveCoach = true;
                } else if (status === 'pending') {
                    hasPendingCoach = true;
                }
            }
        } catch (e) {
            console.warn("Could not fetch coaching_relationships", e);
        }
    }

    const fullName = resolveUserFullName(profile, session.user);
    const alreadyDismissedInSession = state.user?.coach_plans_dismissed === true;
    state.user = {
        id: session.user.id,
        email: session.user.email,
        ...profile,
        role,
        hasActiveCoach,
        hasPendingCoach,
        coach_id: linkedCoachId || profile?.coach_id || profile?.coachId || null,
        full_name: fullName
    };
    applyCoachPlanType(state.user);
    // Preserve in-session dismiss flag: if the coach already navigated away
    // and set this to true, don't let a fresh DB read (which may still have false)
    // overwrite the in-session value.
    if (alreadyDismissedInSession) {
        state.user.coach_plans_dismissed = true;
    }

    // Check subscription expiry: if expired, downgrade to Plan Free via server (service role)
    if (state.user.subscription_expires_at && new Date(state.user.subscription_expires_at) < new Date()) {
        state.user._expiredPlan = state.user.plan_type;
        state.user._subscriptionExpired = true;
        state.user.plan_type = 'Plan Free';
        state.user.subscription_expires_at = null;
        state.coachTab = 'plans';
        // Re-render immediately so the expired banner shows without a page refresh
        updateUI();
        fetch(`http://localhost:3000/api/stripe/expire-subscription?userId=${encodeURIComponent(state.user.id)}`)
            .then(r => r.json())
            .then(data => {
                if (data.ok) {
                    console.log('[Subscription] Plan expirado, revertido a Plan Free en BD');
                } else {
                    console.warn('[Subscription] Error al expirar en BD:', data.message);
                }
            })
            .catch(e => console.warn('[Subscription] Error de red al expirar:', e));
    }

    if (state.user.coach_upgrade_expires_at && new Date(state.user.coach_upgrade_expires_at) < new Date()) {
        state.user.coach_upgrade_active = false;
        state.user.coach_upgrade_expires_at = null;
        fetch(`http://localhost:3000/api/stripe/expire-upgrade?userId=${encodeURIComponent(state.user.id)}`)
            .then(r => r.json())
            .then(data => {
                if (data.ok) {
                    console.log('[Upgrade] Expirado, desactivado en BD');
                } else {
                    console.warn('[Upgrade] Error al expirar en BD:', data.message);
                }
            })
            .catch(e => console.warn('[Upgrade] Error de red al expirar:', e));
    }

    if (isCoachFreePlan(state.user)) {
        state.coachTab = 'plans';
    }

    return { role, profile };
};

const applySessionRedirect = async (session, { forceRedirect = false } = {}) => {
    if (!session?.user) return;

    const fallbackRole = normalizeRoleValue(session.user.user_metadata?.role) || 'client';
    const fullName = resolveUserFullName(null, session.user);

    let initialPlanType = session.user.user_metadata?.plan_type || session.user.user_metadata?.package_type || session.user.user_metadata?.plan;
    if (isCoachRole(fallbackRole) && !initialPlanType) {
        initialPlanType = 'Plan Basic'; // Default to Basic to prevent UI flashing of premium modules
    }
    state.user = {
        id: session.user.id,
        email: session.user.email,
        full_name: fullName,
        role: fallbackRole,
        plan_type: initialPlanType,
        created_at: session.user.created_at
    };
    applyCoachPlanType(state.user);
    if (isCoachRole(fallbackRole)) {
        state.authProfilePending = true;
        state.coachTab = 'plans';
    }

    const resolvedPlanType = resolveClientPlanType(state.user);
    if (resolvedPlanType) {
        state.user.plan_type = resolvedPlanType;
        if (resolvedPlanType !== 'negocio') {
            state.clientCategory = 'personal';
        }
    }

    void actions.fetchBudget();
    void actions.fetchSavingsGoals();
    if (actions.fetchDiagnosisAnswers) {
        void actions.fetchDiagnosisAnswers({ silent: true, force: true });
    }
    if (actions.fetchPersonalTransactions) {
        void actions.fetchPersonalTransactions();
    }
    if (actions.fetchNotifications) {
        void actions.fetchNotifications();
    }

    const { role, profile } = await resolveSessionProfile(session);
    state.authProfilePending = false;
    if (role === 'blocked') return;
    const effectiveRole = normalizeRoleValue(role || fallbackRole) || 'client';

    if (forceRedirect) {
        redirectForRole(effectiveRole, profile || state.user, { force: true });
    } else {
        // Re-render after profile load so subscription/plan state is always up to date
        updateUI();
    }

    if (isCoachRole(effectiveRole)) {
        // Only do this once per page load (guard flag prevents double-fire from
        // onAuthStateChange SIGNED_IN + getSession both calling applySessionRedirect)
        // NOTE: _coachPlanTabInitDone may reset on hot reload or hard F5,
        // so we also check localStorage as a fallback.
        if (!window._coachPlanTabInitDone) {
            window._coachPlanTabInitDone = true;
            const coachId = profile?.id || state.user?.id;
            const isLocalDismissed = coachId ? localStorage.getItem('valori_coach_dismissed_' + coachId) === 'true' : false;

            const _dismissed = profile?.coach_plans_dismissed === true || state.user?.coach_plans_dismissed === true || isLocalDismissed;
            const _explicitlyNotDismissed = profile?.coach_plans_dismissed === false || state.user?.coach_plans_dismissed === false;

            if (_explicitlyNotDismissed && !_dismissed) {
                state.coachTab = 'plans';
                console.log('[CoachPlans] Coach with plans not dismissed → coachTab set to plans');
            }
        }
        void actions.loadCoachees();
        void actions.loadCoachSessions();
        void actions.fetchCoachRequests();
    }
};

const performLogout = () => {
    isManualLogout = true;
    state.user = null;
    state.coachAuth = false;
    state.view = 'login';
    updateUI();

    supabaseClient.auth.signOut({ scope: 'local' }).catch((error) => {
        console.warn('Local sign out error:', error);
    });
    supabaseClient.auth.signOut({ scope: 'global' }).catch((error) => {
        console.warn('Global sign out error:', error);
    });

    setTimeout(() => {
        isManualLogout = false;
    }, 2000);
};

