    // Costing Module Actions
    startCostingModule: async () => {
        // Load data from localStorage and MERGE with defaults to preserve new keys
        const savedData = localStorage.getItem('costingData');
        if (savedData) {
            try {
                const parsed = JSON.parse(savedData);
                state.costingData = {
                    investment: parsed.investment ?? [],
                    fixedExpenses: parsed.fixedExpenses ?? [],
                    labor: parsed.labor ?? [],
                    services: parsed.services ?? Array(20).fill().map((_, i) => ({ id: i + 1, sold: 0 })),
                    products: parsed.products ?? [],
                    priceList: parsed.priceList ?? [],
                    participationData: parsed.participationData ?? {},
                    participationSheets: parsed.participationSheets ?? {},
                    settings: parsed.settings ?? { dollarRate: 18.50, margin: 40 },
                    selectedProductId: parsed.selectedProductId ?? null,
                };
            } catch (e) { console.warn('Error loading costingData from localStorage', e); }
        }

        state.view = 'costing_module';
        state.costingTab = 'general';
        state.costingAnimate = true;
        // window.scrollTo removed for better mobile UX
        updateUI();
        actions.fetchCostingPriceList();
        await actions.fetchCostingDataFromServer();
    },
    setCostingTab: (tab) => {
        state.costingTab = tab;
        state.costingAnimate = true;
        updateUI();
    },
    setCoachTab: async (tab) => {
        if (tab === 'resources' || tab === 'c_resources' || tab === 'clients') {
            tab = 'contacts';
        }
        // --- persist coach_plans_dismissed when coach navigates away from 'plans' ---
        const isCoach = state.user?.role === 'coach';
        const needsDismiss = state.user?.coach_plans_dismissed === false;

        if (isCoach && needsDismiss && tab !== 'plans') {
            state.user.coach_plans_dismissed = true;
            try {
                await supabaseClient.rpc('dismiss_coach_plans', { p_coach_id: state.user.id });
                console.log('[CoachPlans] coach_plans_dismissed persisted via RPC for coach:', state.user.id);
            } catch (err) {
                console.warn('[CoachPlans] Could not update coach_plans_dismissed via RPC:', err);
            }
            localStorage.setItem('valori_coach_dismissed_' + state.user.id, 'true');
        }

        state.coachTab = tab;
        updateUI();

        if (tab === 'requests') {
            await actions.fetchCoachRequests();
        }

        if ((tab === 'coachees' || tab === 'contacts') && (!state.coachees || state.coachees.length === 0)) {
            await actions.loadCoachees();
        }

        if (tab === 'calendar' || tab === 'dashboard') {
            await actions.loadCoachSessions();
        }

        if (tab === 'calendar' && state.googleCalendar?.connected) {
            await actions.syncGoogleCalendar({ silent: true });
        }

        if (tab === 'forms') {
            await actions.fetchCoachForms();
        }

        if (tab === 'contracts') {
            await actions.fetchCoachContracts();
        }
    },
    setAnalysisCurrency: (currency) => {
        state.analysisCurrency = currency;
        updateUI();
    },
    fetchCostingDataFromServer: async () => {
        try {
            const userId = await getEffectiveUserId();
            if (!userId) return;
            const { data, error } = await supabaseClient
                .from('costing_data')
                .select('data')
                .eq('user_id', userId)
                .single();

            if (error || !data?.data) return;

            const serverData = data.data || {};
            state.costingData = {
                investment: serverData.investment ?? state.costingData.investment ?? [],
                fixedExpenses: serverData.fixedExpenses ?? state.costingData.fixedExpenses ?? [],
                labor: serverData.labor ?? state.costingData.labor ?? [],
                services: serverData.services ?? state.costingData.services ?? Array(20).fill().map((_, i) => ({ id: i + 1, sold: 0 })),
                products: serverData.products ?? state.costingData.products ?? [],
                priceList: serverData.priceList ?? state.costingData.priceList ?? [],
                participationData: serverData.participationData ?? state.costingData.participationData ?? {},
                participationSheets: serverData.participationSheets ?? state.costingData.participationSheets ?? {},
                participationOrder: serverData.participationOrder ?? state.costingData.participationOrder ?? [],
                settings: serverData.settings ?? state.costingData.settings ?? { dollarRate: 18.50, margin: 40 },
                selectedProductId: serverData.selectedProductId ?? state.costingData.selectedProductId ?? null,
            };
            localStorage.setItem('costingData', JSON.stringify(state.costingData));
            updateUI();
        } catch (error) {
            console.warn('Error loading costing_data:', error);
        }
    },
    saveCostingDataToServer: async () => {
        try {
            const userId = await getEffectiveUserId();
            if (!userId) return;
            const payload = {
                user_id: userId,
                data: state.costingData || {}
            };
            const { error } = await supabaseClient
                .from('costing_data')
                .upsert(payload, { onConflict: 'user_id' });
            if (error) console.warn('Error saving costing_data:', error);
        } catch (error) {
            console.warn('Error saving costing_data:', error);
        }
    },

