// --- TOAST NOTIFICATION SYSTEM ---
const showToast = (message, type = 'success') => {
    // Determine colors based on type
    const colors = {
        success: 'bg-green-500 text-white shadow-green-500/30',
        error: 'bg-red-500 text-white shadow-red-500/30',
        info: 'bg-brand-blue text-white shadow-blue-500/30',
        warning: 'bg-yellow-500 text-white shadow-yellow-500/30'
    };
    const icons = {
        success: 'check-circle',
        error: 'alert-circle',
        info: 'info',
        warning: 'alert-triangle'
    };

    const theme = colors[type] || colors.info;
    const icon = icons[type] || icons.info;

    // Create container if it doesn't exist
    let container = document.getElementById('toast-container');
    if (!container) {
        container = document.createElement('div');
        container.id = 'toast-container';
        container.className = 'fixed top-4 right-4 z-[9999] flex flex-col gap-3 pointer-events-none';
        document.body.appendChild(container);
    }

    // Create toast element
    const toast = document.createElement('div');
    toast.className = `pointer-events-auto flex items-center gap-3 px-6 py-4 rounded-2xl shadow-xl transform transition-all duration-300 translate-x-10 opacity-0 ${theme} min-w-[300px] border border-white/10 backdrop-blur-md`;

    toast.innerHTML = `
    <i data-lucide="${icon}" width = "24" height = "24" ></i>
        <div class="flex-1 font-bold text-sm leading-tight">${message}</div>
        <button onclick="this.parentElement.remove()" class="opacity-70 hover:opacity-100 transition-opacity">
            <i data-lucide="x" width="18"></i>
        </button>
`;

    container.appendChild(toast);

    // Refresh icons
    if (window.lucide) window.lucide.createIcons();

    // Animation In
    requestAnimationFrame(() => {
        toast.classList.remove('translate-x-10', 'opacity-0');
    });

    // Auto Remove
    setTimeout(() => {
        toast.classList.add('translate-x-10', 'opacity-0');
        setTimeout(() => toast.remove(), 300);
    }, 4000);
};

// Expose showToast globally
window.showToast = showToast;


