const calculateDebtSimulation = (debt, overrides = {}) => {
    let balance = parseFloat(debt.initialDebt) || 0;
    const rate = parseFloat(debt.annualInterest) || 0;
    const minMois = parseFloat(debt.minPayment) || 0;
    const monthlyRate = rate / 100 / 12;

    // Safety
    if (balance <= 0) return { timeline: [], totalInterest: 0 };

    const timeline = [];
    let totalInterest = 0;
    let month = 1;

    // Limit 120 months to avoid infinite loops and per request usually 10 years cap
    while (balance > 0.1 && month <= 120) {
        const interest = balance * monthlyRate;

        // Manual Overrides
        const overrideKey = `${debt.id ? debt.id : 'idx_' + (state.debtControl.debts.indexOf(debt))}-${month}`;
        // Note: debt.id might not be stable if we use index, assume we use index for now if no ID.
        // Better: ensure debts have IDs. For now, let's use the override object passed in which is state.debtControl.overrides[debtIndex][month]

        const overrideData = overrides[month] || {};

        let payment = minMois;

        // Apply overrides
        if (overrideData.underPayment > 0) payment = overrideData.underPayment;
        if (overrideData.additionalPayment > 0) payment += overrideData.additionalPayment;

        const newExpenses = overrideData.newExpenses || 0;

        // Balance check logic
        // If balance + interest + newExpenses < payment, cap payment
        const amountDue = balance + interest + newExpenses;

        if (amountDue < payment) {
            payment = amountDue;
        } else if (payment < interest) {
            // Force payment >= interest to prevent negative amortization loop in auto-calc, 
            // UNLESS explicit underpayment? React logic says: if underpayment is set, we use it.
            // If manual payment covers less than interest, balance grows.
            if (!overrideData.underPayment) {
                payment = interest + 1;
            }
        }

        const principal = payment - interest;
        balance = balance - principal + newExpenses;

        if (balance < 0) balance = 0;

        totalInterest += interest;

        timeline.push({
            month,
            balance: balance,
            interest: interest,
            paid: payment,
            basePayment: minMois,
            manualExtra: overrideData.additionalPayment || 0,
            underPayment: overrideData.underPayment || 0,
            newExpenses: newExpenses
        });
        month++;
    }
    return { timeline, totalInterest };
};

const initDebtDetailChart = (debtIndex, timeline) => {
    const ctx = document.getElementById(`debtDetailChart-${debtIndex}`);
    if (!ctx) return;

    // Store chart instance in array or map
    if (!state.charts.debtDetail) state.charts.debtDetail = {};
    if (state.charts.debtDetail[debtIndex]) {
        state.charts.debtDetail[debtIndex].destroy();
    }

    const labels = timeline.map(t => `Mes ${t.month}`);
    const dataBalance = timeline.map(t => t.balance);
    const dataPaid = timeline.map(t => t.paid);

    state.charts.debtDetail[debtIndex] = new Chart(ctx, {
        type: 'bar',
        data: {
            labels,
            datasets: [
                {
                    label: 'Saldo',
                    data: dataBalance,
                    backgroundColor: '#DCE775',
                    type: 'bar',
                    order: 2
                },
                {
                    label: 'Total Pagado',
                    data: dataPaid,
                    backgroundColor: '#3b82f6',
                    type: 'bar',
                    order: 1
                }
            ]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            scales: {
                y: {
                    beginAtZero: true,
                    grid: { color: document.documentElement.classList.contains('dark') ? '#333' : '#ddd' },
                    ticks: { color: document.documentElement.classList.contains('dark') ? '#aaa' : '#666' }
                },
                x: {
                    grid: { display: false },
                    ticks: { color: document.documentElement.classList.contains('dark') ? '#aaa' : '#666' }
                }
            },
            plugins: {
                tooltip: {
                    callbacks: {
                        label: (context) => new Intl.NumberFormat('es-MX', { style: 'currency', currency: 'MXN' }).format(context.raw)
                    }
                },
                legend: { display: false } // Hidden per design check, or keep minimal
            }
        }
    });
};

