const restoreDebtControl = async () => {
    const userId = await getEffectiveUserId();
    if (userId) {
        try {
            const { data } = await supabaseClient.from('user_savings_goals').select('extra_data').eq('user_id', userId).single();
            if (data && data.extra_data && data.extra_data.debt_control) {
                state.debtControl = {
                    debts: data.extra_data.debt_control,
                    config: data.extra_data.debt_config || { startDate: new Date(Date.now() - new Date().getTimezoneOffset() * 60000).toISOString().split('T')[0] },
                    selectedDebtIndex: 0
                };
            } else {
                const local = localStorage.getItem('debt_control_' + userId);
                if (local) {
                    const parsed = JSON.parse(local);
                    // Handle old local format vs new
                    if (parsed.debts) {
                        state.debtControl = { ...parsed, selectedDebtIndex: 0 };
                    } else {
                        state.debtControl = { debts: parsed, selectedDebtIndex: 0 }; // Old array format
                    }
                }
            }
        } catch (e) { console.warn(e); }
    }
};

