// Ensure state initialization helpers in case actions are called before render
const ensureDebtsGoalsState = () => {
    const currentMonthStr = new Date().toISOString().slice(0, 7); // "YYYY-MM"
    if (!state.debtsGoals) {
        state.debtsGoals = {
            goals: [
                { name: 'AHORRO PAZ', target: 0, monthlyContribution: 0, targetMonths: 6, startDate: currentMonthStr, months: Array(120).fill(0) },
                { name: 'Ahorro 2', target: 0, monthlyContribution: 0, targetMonths: 6, startDate: currentMonthStr, months: Array(120).fill(0) },
                { name: 'Ahorro 3', target: 0, monthlyContribution: 0, targetMonths: 6, startDate: currentMonthStr, months: Array(120).fill(0) },
                { name: 'Ahorro 4', target: 0, monthlyContribution: 0, targetMonths: 6, startDate: currentMonthStr, months: Array(120).fill(0) }
            ],
            debts: Array(10).fill(null).map((_, i) => ({
                bank: '',
                debt: 0,
                interest: '',
                payment: 0,
                date: '',
                comments: ''
            })),
            notes: ''
        };
    } else {
        // Upgrade existing state if needed
        if (state.debtsGoals.notes === undefined || state.debtsGoals.notes === null) {
            state.debtsGoals.notes = '';
        }
        state.debtsGoals.goals.forEach(g => {
            if (!g.startDate) g.startDate = currentMonthStr;
            if (!g.months || g.months.length < 120) {
                const oldMonths = g.months || [];
                g.months = Array(120).fill(0);
                // Simple migration: copy old values
                oldMonths.forEach((val, i) => { if (i < 120) g.months[i] = val; });
            }
        });
    }
}

actions.updateDebtGoalName = (index, value) => {
    ensureDebtsGoalsState();
    state.debtsGoals.goals[index].name = value;
    // No updateUI() here to prevent input blur from re-rendering and swallowing "Save" clicks
};

actions.updateDebtGoalTarget = (index, value) => {
    ensureDebtsGoalsState();
    const val = parseFloat(value) || 0;
    state.debtsGoals.goals[index].target = val;

    // CHANGED LOGIC: Keep Months FIXED, recalculate Monthly Contribution
    // User wants: Change Target -> Updates Monthly Payment required to reach it in same time.
    const targetMonths = state.debtsGoals.goals[index].targetMonths || 0;

    if (targetMonths > 0) {
        const newMonthlyContribution = val / targetMonths;
        state.debtsGoals.goals[index].monthlyContribution = newMonthlyContribution;
        fillMonthsDistribution(index, newMonthlyContribution, targetMonths);
    } else {
        // If 0 months, we can't calculate a monthly contribution.
        // We just save the target. User must set months next.
        state.debtsGoals.goals[index].monthlyContribution = 0;
        fillMonthsDistribution(index, 0, 0);
    }

    updateUI();
};

actions.updateDebtGoalMonthsInput = (index, value) => {
    ensureDebtsGoalsState();
    const val = parseFloat(value) || 0;
    state.debtsGoals.goals[index].targetMonths = val;

    let monthlyContribution;

    // Standard Logic: Calculate Monthly Contribution based on Target / Months
    const target = state.debtsGoals.goals[index].target || 0;
    monthlyContribution = (val > 0) ? target / val : 0;
    state.debtsGoals.goals[index].monthlyContribution = monthlyContribution;

    // Auto-fill months
    fillMonthsDistribution(index, monthlyContribution, val);

    updateUI();
};

actions.updateDebtGoalStartDate = (index, value) => {
    ensureDebtsGoalsState();
    state.debtsGoals.goals[index].startDate = value;

    // Recalculate distribution
    const goal = state.debtsGoals.goals[index];
    fillMonthsDistribution(index, goal.monthlyContribution, goal.targetMonths);

    updateUI();
};

actions.updateGlobalMonthlySavings = (value) => {
    const globalCap = parseFloat(value) || 0;
    state.debtsGoals.globalMonthlyCapacity = globalCap;

    const goals = state.debtsGoals.goals;

    // 1. Calculate Total Demand (Sum of all targets)
    // We only consider goals that have a target > 0 to avoid division by zero issues or allocating to empty goals
    const totalTargetNeeded = goals.reduce((sum, g) => sum + (parseFloat(g.target) || 0), 0);

    // 2. Proportional Distribution
    goals.forEach((g, index) => {
        const target = parseFloat(g.target) || 0;
        let monthlyAllocated = 0;

        if (totalTargetNeeded > 0 && target > 0) {
            // Weight = (Goal Target / Total Target)
            const weight = target / totalTargetNeeded;
            monthlyAllocated = globalCap * weight;
        } else {
            // Fallback if no total demand or 0 target
            monthlyAllocated = 0;
        }

        // Update the goal's monthly contribution state
        g.monthlyContribution = monthlyAllocated;

        // 3. Calculate Duration & Fill
        if (monthlyAllocated > 0.01) {
            const duration = Math.ceil(target / monthlyAllocated);
            g.targetMonths = duration;
            fillMonthsDistribution(index, monthlyAllocated, duration);
        } else {
            g.targetMonths = 0;
            fillMonthsDistribution(index, 0, 0);
        }
    });

    updateUI();
};

actions.updateDebtGoalMonthlyContribution = (index, value) => {
    // Legacy / Per-Goal Override Handler (Optional: can keep or disable if Global is master)
    // For now, let's keep it but it might conflict with global recalc. 
    // If user edits local, it deviates from the global plan. 
    ensureDebtsGoalsState();
    const val = parseFloat(value) || 0;
    const goal = state.debtsGoals.goals[index];

    // Update Monthly Contribution
    goal.monthlyContribution = val;

    // Calculate new Months based on Target / Monthly
    const target = goal.target || 0;

    if (val > 0 && target > 0) {
        // Calculate months needed, rounding up
        // Example: Target 1000, Monthly 300 -> 3.33 -> 4 months
        const calculatedMonths = Math.ceil(target / val);
        goal.targetMonths = calculatedMonths;

        // Auto-fill distribution
        fillMonthsDistribution(index, val, calculatedMonths);
    }

    updateUI();
};

// Helper to fill the months array starting from start date
const fillMonthsDistribution = (goalIndex, amount, durationMonths) => {
    ensureDebtsGoalsState();
    const goal = state.debtsGoals.goals[goalIndex];
    const baseYear = 2024;
    const [y, m] = (goal.startDate || new Date().toISOString().slice(0, 7)).split('-').map(Number);
    const startOffset = (y - baseYear) * 12 + (m - 1);

    // Reset/Ensure 120 month array
    if (!goal.months || goal.months.length < 120) {
        goal.months = Array(120).fill(0);
    } else {
        goal.months.fill(0);
    }

    for (let i = 0; i < durationMonths; i++) {
        const targetIndex = startOffset + i;
        if (targetIndex >= 0 && targetIndex < 120) {
            goal.months[targetIndex] = amount;
        }
    }
};

actions.updateDebtGoalMonth = (goalIndex, monthIndex, value) => {
    ensureDebtsGoalsState();
    const val = parseFloat(value) || 0;
    const goals = state.debtsGoals.goals;
    const goal = goals[goalIndex];

    // 1. Update the direct edit
    if (!goal.months) goal.months = Array(120).fill(0);
    goal.months[monthIndex] = val;

    const globalCap = parseFloat(state.debtsGoals.globalMonthlyCapacity) || 0;

    if (globalCap > 0) {
        // --- GLOBAL LOGIC: Rebalance Current Month + Future Ripple ---

        let availableForOthers = Math.max(0, globalCap - val);
        const otherGoals = goals.filter((_, idx) => idx !== goalIndex);
        const totalOtherTarget = otherGoals.reduce((sum, g) => sum + (parseFloat(g.target) || 0), 0);

        otherGoals.forEach(g => {
            const t = parseFloat(g.target) || 0;
            let share = 0;
            if (totalOtherTarget > 0) {
                share = (t / totalOtherTarget) * availableForOthers;
            }
            if (!g.months) g.months = Array(120).fill(0);
            g.months[monthIndex] = share;
        });

        // B. Future Ripple
        const baseYear = 2024;
        const currentMIdxNow = (new Date().getFullYear() - baseYear) * 12 + new Date().getMonth();
        const totalAllTargets = goals.reduce((sum, g) => sum + (parseFloat(g.target) || 0), 0);

        // Ripple starts from NEXT month after edited monthIndex
        for (let i = monthIndex + 1; i < 120; i++) {
            const goalNeeds = goals.map(g => {
                const totalT = parseFloat(g.target) || 0;
                let accumulated = 0;
                for (let k = 0; k < i; k++) {
                    accumulated += (parseFloat(g.months[k]) || 0);
                }
                return Math.max(0, totalT - accumulated);
            });

            goals.forEach((g, gIdx) => {
                const need = goalNeeds[gIdx];
                const totalT = parseFloat(g.target) || 0;
                let alloc = 0;
                if (totalAllTargets > 0 && need > 0.01) {
                    const baseRate = globalCap * (totalT / totalAllTargets);
                    alloc = Math.min(need, baseRate);
                }
                g.months[i] = alloc;
            });
        }

        // C. Update Duration Counters
        goals.forEach(g => {
            let lastActive = -1;
            for (let i = 0; i < 120; i++) {
                if ((g.months[i] || 0) > 0.01) lastActive = i;
            }
            if (lastActive >= 0) {
                const [y, m] = g.startDate.split('-').map(Number);
                const startOffset = (y - 2024) * 12 + (m - 1);
                g.targetMonths = Math.max(0, lastActive - startOffset + 1);
            } else {
                g.targetMonths = 0;
            }

            const totalAlloc = g.months.reduce((a, b) => a + b, 0);
            if (g.targetMonths > 0) g.monthlyContribution = totalAlloc / g.targetMonths;
            else g.monthlyContribution = 0;
        });

    } else {
        // Local logic updated for linear indexing
        const target = parseFloat(goal.target) || 0;
        const monthlyContrib = parseFloat(goal.monthlyContribution) || 0;

        if (target > 0 && monthlyContrib > 0) {
            let accumulated = 0;
            for (let i = 0; i <= monthIndex; i++) {
                accumulated += (parseFloat(goal.months[i]) || 0);
            }

            let remaining = target - accumulated;
            let nextM = monthIndex + 1;

            while ((remaining > 0.01 || nextM < 120) && nextM < 120) {
                if (remaining <= 0.01) {
                    goal.months[nextM] = 0;
                } else {
                    const amount = Math.min(remaining, monthlyContrib);
                    goal.months[nextM] = amount;
                    remaining -= amount;
                }
                nextM++;
            }

            let lastActive = -1;
            for (let i = 0; i < 120; i++) {
                if ((parseFloat(goal.months[i]) || 0) > 0.01) lastActive = i;
            }

            if (lastActive >= 0) {
                const [y, m] = goal.startDate.split('-').map(Number);
                const startOffset = (y - 2024) * 12 + (m - 1);
                goal.targetMonths = Math.max(0, lastActive - startOffset + 1);
            }
        }
    }

    updateUI();
};

