actions.recalculateAhorroPaz = () => {
    ensureDebtsGoalsState();

    // Recalculate from current Presupuesto Ideal data
    const idealBudget = state.budgetData.idealBudget || {};
    const getCatSum = (cat) => (idealBudget[cat] || []).reduce((sum, item) => sum + (parseFloat(item.amount) || 0), 0);

    const totalFixed = getCatSum('fixed');
    const totalDebtBudget = getCatSum('debt');
    const ahorroPazMonthlyBase = totalFixed + totalDebtBudget;

    if (state.debtsGoals.goals.length > 0) {
        const monthsPaz = state.debtsGoals.goals[0].targetMonths || 6;
        const ahorroPazTarget = ahorroPazMonthlyBase * monthsPaz;
        const goal = state.debtsGoals.goals[0];

        goal.target = ahorroPazTarget;
        goal.monthlyContribution = ahorroPazMonthlyBase;

        // Auto-fill months distribution
        fillMonthsDistribution(0, ahorroPazMonthlyBase, monthsPaz);
    }

    showToast('AHORRO PAZ actualizado', 'success');
    updateUI();
};

