actions.fetchSavingsGoals = async () => {
    const userId = await getEffectiveUserId();
    if (!userId) {
        console.log("No user logged in, using default state");
        ensureDebtsGoalsState();
        return;
    }

    try {
        const { data, error } = await supabaseClient
            .from('user_savings_goals')
            .select('goals_data, debts_data, notes')
            .eq('user_id', userId)
            .single();

        console.log("fetchSavingsGoals - Raw data from DB:", data);

        if (error && error.code !== 'PGRST116') {
            // PGRST116 = no rows found, which is OK for new users
            console.error("❌ Database error details:", {
                code: error.code,
                message: error.message,
                details: error.details,
                hint: error.hint
            });
            ensureDebtsGoalsState();
            return;
        }

        if (data && data.goals_data && Array.isArray(data.goals_data) && data.goals_data.length > 0) {
            // User has saved data - load it
            console.log("Loading saved goals from DB:", data.goals_data);
            state.debtsGoals = {
                goals: data.goals_data,
                debts: data.debts_data || [],
                notes: data.notes || ''
            };
        } else {
            // No data or empty data - initialize fresh
            console.log("No saved data found, initializing defaults");
            ensureDebtsGoalsState();
            if (data && Object.prototype.hasOwnProperty.call(data, 'notes')) {
                state.debtsGoals.notes = data.notes || '';
                state.debtsGoals.notesOpen = !!data.notes;
            }
        }

        console.log("Final state.debtsGoals:", state.debtsGoals);
    } catch (e) {
        console.error("Exception in fetchSavingsGoals:", e);
        ensureDebtsGoalsState();
    }
};

// --- LOAD DIAGNOSIS ANSWERS ---
actions.fetchDiagnosisAnswers = async ({ silent = false, force = false } = {}) => {
    if (!force && state.answers && Object.keys(state.answers).length > 0) return true;

    const applyAnswers = (answers, meta = {}) => {
        if (!answers || typeof answers !== 'object') return false;
        state.answers = answers;
        state.diagnosisLastSavedAt = meta.created_at || null;
        state.diagnosisLastScore = meta.score ?? null;
        state.diagnosisSummary = meta.result_summary || null;
        if (!silent) updateUI();
        return true;
    };

    const tryLocalBackup = (key) => {
        if (!key) return null;
        try {
            const raw = localStorage.getItem(key);
            if (!raw) return null;
            const parsed = JSON.parse(raw);
            if (parsed && typeof parsed === 'object') return parsed;
        } catch (e) {
            console.warn('Error loading diagnosis backup:', e);
        }
        return null;
    };

    const userId = await getEffectiveUserId();
    if (!userId) {
        const local = tryLocalBackup('diagnosis_answers_backup');
        if (local) return applyAnswers(local);
        return false;
    }

    try {
        const { data, error } = await withTimeout(
            supabaseClient
                .from('quiz_results_financial_health')
                .select('answers, created_at, score, result_summary')
                .eq('user_id', userId)
                .order('created_at', { ascending: false })
                .limit(1),
            15000,
            'fetchDiagnosis'
        );

        if (error) throw error;
        const row = Array.isArray(data) ? data[0] : null;
        if (row && row.answers) {
            return applyAnswers(row.answers, row);
        }
    } catch (error) {
        console.warn('Error fetching diagnosis answers:', error);
    }

    const local = tryLocalBackup(`diagnosis_answers_backup_${userId}`) || tryLocalBackup('diagnosis_answers_backup');
    if (local) return applyAnswers(local);

    return false;
};

// --- SAVE DIAGNOSIS ANSWERS ---
actions.saveDiagnosisAnswers = async () => {
    const userId = await getUserIdFromSession();
    if (!userId) {
        console.warn('Usuario no autenticado, no se pueden guardar las respuestas del diagnostico');
        try {
            localStorage.setItem('diagnosis_answers_backup', JSON.stringify(state.answers));
            showToast('Sesion expirada. Guardado localmente.', 'warning');
        } catch (localError) {
            console.error('Error al guardar en localStorage:', localError);
            showToast('Error al guardar: Sesion expirada', 'error');
        }
        return;
    }

    try {
        // Calculate score before saving
        const score = calculatePersonalScore();

        const payload = {
            user_id: userId,
            answers: state.answers,
            score: Math.round(score * 10), // Convert to 0-100 scale (0.0-10.0 becomes 0-100)
            result_summary: score >= 8.0 ? 'Excelente Salud Financiera!' :
                (score >= 5.0 ? 'Vas por buen camino, pero hay areas de mejora.' :
                    'Necesitas atencion urgente en tus finanzas.'),
            created_at: new Date().toISOString()
        };

        const { error } = await withTimeout(
            supabaseClient
                .from('quiz_results_financial_health')
                .insert(payload),
            15000,
            'saveDiagnosis'
        );

        if (error) throw error;

        console.log('Respuestas del diagnostico guardadas correctamente');
        showToast('Respuestas guardadas', 'success');
    } catch (error) {
        console.error('Error al guardar respuestas del diagnostico:', error);
        if (isAuthError(error)) {
            showToast('Sesion expirada. Guardado localmente.', 'warning');
        } else {
            showToast('Error al guardar. Guardado localmente.', 'warning');
        }
        try {
            localStorage.setItem(`diagnosis_answers_backup_${userId}`, JSON.stringify(state.answers));
            console.log('Respuestas guardadas localmente (backup)');
        } catch (localError) {
            console.error('Error al guardar en localStorage:', localError);
            showToast('Error al guardar: ' + error.message, 'error');
        }
    }
};

