const renderDebtsAndGoals = () => {
    // Ensure state initialization
    ensureDebtsGoalsState();

    const idealBudget = state.budgetData.idealBudget || {};
    const getCatSum = (cat) => (idealBudget[cat] || []).reduce((sum, item) => sum + (parseFloat(item.amount) || 0), 0);

    const totalFixed = getCatSum('fixed');
    const totalDebtBudget = getCatSum('debt');
    const ahorroPazMonthlyBase = totalFixed + totalDebtBudget;

    // Logic related to "AHORRO PAZ" enforcement removed to allow editing
    // If goals are empty, we might want to ensure at least defaults exist (handled in ensureDebtsGoalsState)

    const { goals, debts } = state.debtsGoals;

    // --- DYNAMIC DISPLAY LOGIC ---
    const baseYear = 2024;
    const currentM = new Date().getMonth();
    const currentY = new Date().getFullYear();
    const currentGlobalIdx = (currentY - baseYear) * 12 + currentM;

    // Minimum 12 rows from now
    let maxMonthIdx = currentGlobalIdx + 11;
    goals.forEach(g => {
        const [y, m] = g.startDate.split('-').map(Number);
        const startIdx = (y - baseYear) * 12 + (m - 1);
        const endIdx = startIdx + (g.targetMonths || 0) - 1;
        if (endIdx > maxMonthIdx) maxMonthIdx = endIdx;
    });

    // Cap at array limit (120)
    maxMonthIdx = Math.min(maxMonthIdx, 119);

    const allMonthsNames = ['Enero', 'Febrero', 'Marzo', 'Abril', 'Mayo', 'Junio', 'Julio', 'Agosto', 'Septiembre', 'Octubre', 'Noviembre', 'Diciembre'];
    const displayMonths = [];
    for (let i = currentGlobalIdx; i <= maxMonthIdx; i++) {
        const rowY = baseYear + Math.floor(i / 12);
        const rowM = i % 12;
        displayMonths.push({
            name: `${allMonthsNames[rowM]} ${rowY} `,
            index: i,
            offset: i - currentGlobalIdx
        });
    }

    // Calculations for Footer
    const totalAportacionMensualHeader = goals.reduce((sum, g) => sum + g.monthlyContribution, 0);
    const monthsTotals = displayMonths.map(m => goals.reduce((sum, g) => sum + (g.months[m.index] || 0), 0));
    const totalAhorroFinal = goals.reduce((sum, g) => sum + g.months.reduce((a, b) => a + b, 0), 0);

    const totalDeuda = debts.reduce((sum, d) => sum + (parseFloat(d.debt) || 0), 0);
    const totalPagoMensual = debts.reduce((sum, d) => sum + (parseFloat(d.payment) || 0), 0);

    const formatCurrency = (val) => val.toLocaleString('es-MX', { style: 'currency', currency: 'MXN' });
    const normalizedRole = normalizeRoleValue(state.user?.role);
    const isCoacheeRole = normalizedRole === 'client' || normalizedRole === 'coachee' || normalizedRole === 'user';

    return `
    <div class="min-h-screen bg-gray-50 dark:bg-brand-black p-4 md:p-8 animate-fade-in pb-32">
        <!-- Header -->
        <div class="flex items-center gap-4 mb-8 justify-between">
            <div class="flex items-center gap-4">
                <button onclick="actions.startClientModule()" class="flex items-center gap-2 bg-white dark:bg-zinc-900 px-3 py-2 rounded-xl border border-zinc-200 dark:border-zinc-800 text-zinc-500 dark:text-zinc-400 hover:text-zinc-900 dark:hover:text-white hover:bg-zinc-50 dark:hover:bg-zinc-800 transition shadow-sm">
                    <i data-lucide="home" width="18"></i>
                    <span class="text-sm font-medium">Volver</span>
                </button>
                <button onclick="actions.startIdealBudget()" class="bg-white dark:bg-zinc-900 p-2 rounded-full border border-zinc-200 dark:border-zinc-800 hover:bg-zinc-50 dark:hover:bg-zinc-800 transition-colors shadow-sm">
                    <i data-lucide="arrow-left" width="24"></i>
                </button>
                <div>
                    <h1 class="text-3xl font-black text-brand-lime mt-1">Deudas y Metas</h1>
                    <p class="text-zinc-500 dark:text-zinc-400">Planifica tu libertad financiera</p>
                </div>
            </div>
            
            <div class="flex gap-4">
                ${isCoacheeRole ? `
                <button onclick="actions.openDebtsGoalsNotesModal()" class="bg-white dark:bg-zinc-900 text-zinc-700 dark:text-zinc-200 px-4 py-3 rounded-xl font-bold shadow-sm border border-zinc-200 dark:border-zinc-800 hover:bg-zinc-50 dark:hover:bg-zinc-800 transition-colors flex items-center gap-2">
                    <i data-lucide="file-text" width="18"></i> Notas
                </button>
                ` : ''}
                <button onclick="actions.saveSavingsGoals()" class="bg-zinc-900 dark:bg-white text-white dark:text-black px-6 py-3 rounded-xl font-bold shadow-lg hover:scale-105 transition-transform flex items-center gap-2">
                    <i data-lucide="save" width="20"></i> Guardar
                </button>
                <button onclick="actions.nextStepFromGoals()" class="bg-brand-blue text-white px-6 py-3 rounded-xl font-bold shadow-lg hover:scale-105 transition-transform flex items-center gap-2">
                    Siguiente Paso <i data-lucide="arrow-right" width="20"></i>
                </button>
            </div>
        </div>

        ${isCoacheeRole ? `
        <dialog id="debts-goals-notes-modal" class="modal bg-transparent p-0 w-full max-w-lg backdrop:bg-black/70">
            <div class="bg-white dark:bg-zinc-900 rounded-2xl border border-zinc-200 dark:border-zinc-800 shadow-xl p-6">
                <div class="flex items-center justify-between mb-4">
                    <h3 class="text-lg font-bold text-zinc-900 dark:text-white">Notas</h3>
                    <button onclick="actions.closeDebtsGoalsNotesModal()" class="p-2 rounded-lg hover:bg-zinc-100 dark:hover:bg-zinc-800 text-zinc-400 hover:text-zinc-600 dark:hover:text-white transition-colors">
                        <i data-lucide="x" width="20"></i>
                    </button>
                </div>
                <textarea rows="6"
                    oninput="actions.updateDebtsGoalsNotes(this.value)"
                    class="w-full bg-zinc-50 dark:bg-zinc-800 border border-zinc-200 dark:border-zinc-700 rounded-xl px-4 py-3 focus:outline-none focus:border-brand-lime transition-colors dark:text-white resize-none"
                    placeholder="Escribe tus notas o comentarios...">${state.debtsGoals.notes || ''}</textarea>
                <div class="flex gap-3 justify-end mt-5">
                    <button type="button" onclick="actions.closeDebtsGoalsNotesModal()" class="px-4 py-2 rounded-xl border border-zinc-200 dark:border-zinc-700 text-zinc-600 dark:text-zinc-300 font-bold hover:bg-zinc-50 dark:hover:bg-zinc-800 transition-colors">Cerrar</button>
                    <button type="button" onclick="actions.saveSavingsGoals(); actions.closeDebtsGoalsNotesModal();" class="px-4 py-2 rounded-xl bg-brand-blue text-white font-bold hover:bg-blue-600 transition-colors">Guardar</button>
                </div>
            </div>
        </dialog>
        ` : ''}

        <!-- METAS DE AHORRO SECTION -->
        <div class="bg-white dark:bg-zinc-900 rounded-2xl border border-zinc-200 dark:border-zinc-800 shadow-sm overflow-hidden mb-8">
            <div class="p-6 border-b border-zinc-200 dark:border-zinc-800 flex justify-between items-center bg-brand-lime/10">
                <div class="flex items-center gap-3">
                    <div class="w-10 h-10 rounded-full bg-brand-lime flex items-center justify-center text-black shadow-sm">
                        <i data-lucide="piggy-bank" width="20"></i>
                    </div>
                    <h2 class="text-xl font-bold text-zinc-900 dark:text-white">Metas de Ahorro</h2>
                </div>
                <div class="flex flex-col items-end gap-2">
                     <div class="flex flex-col items-end">
                         <span class="text-xs font-bold text-zinc-500 uppercase">Ahorro Mensual Total</span>
                         <span class="text-2xl font-black text-brand-lime dark:text-lime-400">${formatCurrency(totalAportacionMensualHeader)}</span>
                     </div>
                </div>
            </div>
            
            <div class="overflow-x-auto custom-scrollbar">
                <table class="w-full text-sm">
                    <thead>
                        <tr class="bg-zinc-50 dark:bg-zinc-800/50 border-b border-zinc-200 dark:border-zinc-800">
                            <th class="p-4 text-left min-w-[150px] font-bold text-zinc-500 uppercase tracking-wider">Mes / Meta</th>
                            ${goals.map((g, i) => {
        return `
                                <th class="p-4 min-w-[200px]">
                                    <div class="flex flex-col gap-2">
                                        <div class="flex items-center justify-center gap-2">
                                            <input type="text" value="${g.name}" 
                                                   onchange="actions.updateDebtGoalName(${i}, this.value)" 
                                                   class="bg-transparent text-center font-bold text-zinc-900 dark:text-white border-b border-transparent focus:border-brand-lime focus:outline-none transition-colors w-full" />
                                        </div>
                                        
                                        <div class="flex items-center bg-white dark:bg-zinc-800 rounded-lg border border-zinc-200 dark:border-zinc-700 p-1">
                                            <span class="text-zinc-400 px-2">$</span>
                                            <input type="number" value="${g.target || ''}" 
                                                   onchange="actions.updateDebtGoalTarget(${i}, this.value)"
                                                   class="w-full bg-transparent border-none focus:ring-0 text-center font-bold text-zinc-700 dark:text-zinc-300" placeholder="Meta Total">
                                        </div>
                                        <div class="flex flex-col gap-2 mt-2">
                                            <div class="flex items-center gap-2 bg-zinc-100 dark:bg-zinc-800 rounded-lg p-1 relative border border-transparent focus-within:border-brand-lime focus-within:bg-white dark:focus-within:bg-zinc-800/80 transition-all group-hover:border-zinc-200 dark:group-hover:border-zinc-700">
                                                <span class="text-[9px] font-bold text-zinc-400 uppercase tracking-wider absolute -top-2 left-2 bg-white dark:bg-zinc-900 px-1">Aporte Mensual</span>
                                                <span class="text-zinc-500 pl-2 text-xs">$</span>
                                                <input type="number" 
                                                       value="${g.monthlyContribution || ''}" 
                                                       onchange="actions.updateDebtGoalMonthlyContribution(${i}, this.value)"
                                                       class="w-full bg-transparent border-none text-center font-bold text-zinc-800 dark:text-zinc-200 text-sm focus:ring-0 p-1" 
                                                       placeholder="0">
                                            </div>
                                            <div class="flex items-center gap-2 bg-white dark:bg-zinc-800 rounded-lg border border-zinc-200 dark:border-zinc-700 p-1">
                                                <span class="text-[10px] font-bold text-zinc-400 uppercase tracking-wider px-1">Meses</span>
                                                <input type="number" 
                                                       value="${g.targetMonths || 6}" 
                                                       onchange="actions.updateDebtGoalMonthsInput(${i}, this.value)"
                                                       class="w-full bg-transparent border-none text-center font-bold text-zinc-700 dark:text-zinc-300 text-sm focus:ring-0 p-0" 
                                                       placeholder="6">
                                            </div>
                                            <div class="flex items-center gap-2 bg-white dark:bg-zinc-800 rounded-lg border border-zinc-200 dark:border-zinc-700 p-1">
                                                <span class="text-[10px] font-bold text-zinc-400 uppercase tracking-wider px-1">Inicio</span>
                                                <input type="month" 
                                                       value="${g.startDate || ''}" 
                                                       onchange="actions.updateDebtGoalStartDate(${i}, this.value)"
                                                       class="w-full bg-transparent border-none text-center font-bold text-zinc-700 dark:text-zinc-300 text-xs focus:ring-0 p-0">
                                            </div>
                                        </div>
                                    </div>
                                </th>
                                `}).join('')}
                            <th class="p-4 text-center min-w-[150px] font-bold text-zinc-500 uppercase tracking-wider bg-zinc-100 dark:bg-zinc-800/80">Total Mes</th>
                        </tr>
                    </thead>
                    <tbody class="divide-y divide-zinc-100 dark:divide-zinc-800">
                        ${displayMonths.map((mObj, idx) => `
                            <tr class="group hover:bg-zinc-50 dark:hover:bg-zinc-800/30 transition-colors">
                                <td class="p-4 font-bold text-zinc-900 dark:text-zinc-300 sticky left-0 bg-white dark:bg-zinc-900 group-hover:bg-zinc-50 dark:group-hover:bg-zinc-800/30 shadow-[4px_0_8px_-4px_rgba(0,0,0,0.1)] transition-colors">
                                    ${mObj.name}
                                </td>
                                ${goals.map((g, gIdx) => {
            const [y, m] = g.startDate.split('-').map(Number);
            const startIdx = (y - baseYear) * 12 + (m - 1);
            const endIdx = startIdx + (g.targetMonths || 0) - 1;
            const isVisible = (mObj.index >= startIdx && mObj.index <= endIdx);
            const cellValue = g.months[mObj.index] || '';

            return `
                                    <td class="p-4 ${!isVisible ? 'bg-zinc-50/50 dark:bg-zinc-900/50' : ''}">
                                        <div class="relative ${!isVisible ? 'opacity-30 grayscale' : ''}">
                                            <span class="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-400 pointer-events-none">$</span>
                                            <input type="number" value="${cellValue}" 
                                                   onchange="actions.updateDebtGoalMonth(${gIdx}, ${mObj.index}, this.value)"
                                                   ${!isVisible ? 'disabled' : ''}
                                                   class="w-full bg-zinc-50 dark:bg-zinc-800 border border-transparent focus:border-brand-lime focus:bg-white dark:focus:bg-zinc-700 rounded-xl py-2.5 pl-7 pr-3 text-center font-medium transition-all shadow-sm focus:shadow-md ${!isVisible ? 'cursor-not-allowed' : ''}" placeholder="0">
                                        </div>
                                    </td>
                                    `
        }).join('')}
                                <td class="p-4 text-center font-bold text-zinc-900 dark:text-white bg-zinc-50/50 dark:bg-zinc-800/50">
                                    ${formatCurrency(monthsTotals[idx])}
                                </td>
                            </tr>
                        `).join('')} 
                    </tbody>
                    <tfoot>
                         <tr class="bg-zinc-100 dark:bg-zinc-800 font-bold border-t-2 border-zinc-200 dark:border-zinc-700">
                            <td class="p-4 text-zinc-900 dark:text-white sticky left-0 bg-zinc-100 dark:bg-zinc-800 shadow-[4px_0_8px_-4px_rgba(0,0,0,0.1)]">
                                TOTAL ACUMULADO
                            </td>
                            ${goals.map(g => `
                                <td class="p-4 text-center text-brand-lime dark:text-lime-400 text-lg">
                                    ${formatCurrency(g.months.reduce((a, b) => a + b, 0))}
                                </td>
                            `).join('')}
                             <td class="p-4 text-center text-2xl text-black dark:text-brand-lime">
                                ${formatCurrency(totalAhorroFinal)}
                            </td>
                        </tr>
                    </tfoot>
                </table>
            </div>
        </div>

        <!-- DEUDAS ACTUALES SECTION -->
    <div class="bg-white dark:bg-zinc-900 rounded-2xl border border-zinc-200 dark:border-zinc-800 shadow-sm overflow-hidden">
        <div class="p-6 border-b border-zinc-200 dark:border-zinc-800 flex justify-between items-center bg-red-50 dark:bg-red-900/10">
            <div class="flex items-center gap-3">
                <div class="w-10 h-10 rounded-full bg-red-500 flex items-center justify-center text-white shadow-sm">
                    <i data-lucide="credit-card" width="20"></i>
                </div>
                <h2 class="text-xl font-bold text-zinc-900 dark:text-white">Deudas Actuales</h2>
            </div>
            <div class="flex flex-col items-end">
                <span class="text-xs font-bold text-red-500 uppercase">Deuda Total</span>
                <span class="text-2xl font-black text-red-600 dark:text-red-400">${formatCurrency(totalDeuda)}</span>
            </div>
        </div>

        <div class="overflow-x-auto custom-scrollbar">
            <table class="w-full text-sm">
                <thead>
                    <tr class="bg-zinc-50 dark:bg-zinc-800/50 border-b border-zinc-200 dark:border-zinc-800 text-xs font-bold text-zinc-500 uppercase tracking-wider">
                        <th class="p-4 text-left w-64">Banco / Institución</th>
                        <th class="p-4 text-center">Deuda Total</th>
                        <th class="p-4 text-center">% Interés</th>
                        <th class="p-4 text-center">Pago Mensual</th>
                        <th class="p-4 text-center">Fecha Pago</th>
                        <th class="p-4 text-left">Comentarios</th>
                    </tr>
                </thead>
                <tbody class="divide-y divide-zinc-100 dark:divide-zinc-800">
                    ${debts.map((d, i) => `
                            <tr class="group hover:bg-zinc-50 dark:hover:bg-zinc-800/50 transition-colors">
                                <td class="p-3 pl-4">
                                     <input type="text" value="${d.bank}" 
                                            onchange="actions.updateDebtRow(${i}, 'bank', this.value)" 
                                            class="w-full bg-transparent font-medium text-zinc-900 dark:text-white border-b border-transparent focus:border-zinc-300 focus:outline-none transition-colors" placeholder="Nombre Banco">
                                </td>
                                <td class="p-3">
                                    <div class="relative max-w-[140px] mx-auto">
                                        <span class="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-400 pointer-events-none">$</span>
                                        <input type="number" value="${d.debt || ''}" 
                                               onchange="actions.updateDebtRow(${i}, 'debt', this.value)" 
                                               class="w-full bg-zinc-50 dark:bg-zinc-800/50 border border-zinc-200 dark:border-zinc-700 rounded-lg py-2 pl-6 pr-2 text-center focus:ring-2 focus:ring-red-500/20 focus:border-red-500 transition-all font-mono" placeholder="0">
                                    </div>
                                </td>
                                <td class="p-3">
                                    <div class="relative max-w-[80px] mx-auto">
                                        <input type="text" value="${d.interest}" 
                                               onchange="actions.updateDebtRow(${i}, 'interest', this.value)" 
                                               class="w-full bg-zinc-50 dark:bg-zinc-800/50 border border-zinc-200 dark:border-zinc-700 rounded-lg py-2 px-2 text-center focus:ring-2 focus:ring-red-500/20 focus:border-red-500 transition-all" placeholder="%">
                                    </div>
                                </td>
                                <td class="p-3">
                                     <div class="relative max-w-[140px] mx-auto">
                                        <span class="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-400 pointer-events-none">$</span>
                                        <input type="number" value="${d.payment || ''}" 
                                               onchange="actions.updateDebtRow(${i}, 'payment', this.value)" 
                                               class="w-full bg-zinc-50 dark:bg-zinc-800/50 border border-zinc-200 dark:border-zinc-700 rounded-lg py-2 pl-6 pr-2 text-center focus:ring-2 focus:ring-red-500/20 focus:border-red-500 transition-all font-mono" placeholder="0">
                                    </div>
                                </td>
                                <td class="p-3 text-center">
                                    <input type="date" value="${d.date}" 
                                           onchange="actions.updateDebtRow(${i}, 'date', this.value)" 
                                           class="bg-transparent border-none focus:ring-0 text-zinc-600 dark:text-zinc-400 text-sm">
                                </td>
                                <td class="p-3 pr-4">
                                    <input type="text" value="${d.comments}" 
                                           onchange="actions.updateDebtRow(${i}, 'comments', this.value)" 
                                           class="w-full bg-transparent border-b border-transparent focus:border-zinc-300 focus:outline-none text-zinc-600 dark:text-zinc-400 text-sm transition-colors" placeholder="Notas...">
                                </td>
                            </tr>
                        `).join('')}
                </tbody>
                <tfoot class="bg-zinc-50 dark:bg-zinc-800 border-t border-zinc-200 dark:border-zinc-700">
                    <tr>
                        <td class="p-4 font-bold text-zinc-900 dark:text-white uppercase text-right">Totales</td>
                        <td class="p-4 text-center font-bold text-zinc-900 dark:text-white text-lg">${formatCurrency(totalDeuda)}</td>
                        <td></td>
                        <td class="p-4 text-center font-bold text-zinc-900 dark:text-white text-lg">${formatCurrency(totalPagoMensual)}</td>
                        <td colspan="2"></td>
                    </tr>
                </tfoot>
            </table>
        </div>
    </div>
    </div>
    `;
};
window.renderDebtsAndGoals = renderDebtsAndGoals;

// --- ROBUST BUSINESS QUIZ RENDERER (Appended Fix) ---
const renderBusinessQuizRobust = () => {
    // 1. Safe State Access
    const sectionIndex = state.businessQuiz.currentSectionIndex || 0;
    const allSections = BUSINESS_QUIZ_DATA.sections || [];
    const totalSections = allSections.length;

    // 2. Validate Section
    const section = allSections[sectionIndex];
    if (!section) {
        return `<div class="p-10 text-center text-red-500">Error: Sección no encontrada (Index: ${sectionIndex})</div>`;
    }

    // 3. Calculate Progress (Granular based on visible questions)
    let totalQuestionsCount = 0;
    let answeredQuestionsCount = 0;

    allSections.forEach(s => {
        const sAnswers = state.businessQuiz.answers[s.id] || {};
        const questions = s.questions || [];

        questions.forEach(q => {
            // 1. Determine Visibility
            let isVisible = true;
            if (q.depends_on) {
                const pId = q.depends_on;
                const isExplicitlyShown = Object.keys(sAnswers).some(k => k.endsWith('_show') && sAnswers[k] === q.id);
                const isSkipped = sAnswers[pId + '_skip_section'] === true; // Usually set by trigger
                const parentAnswered = sAnswers[pId] !== undefined && sAnswers[pId] !== null && sAnswers[pId] !== '';

                if (q.requires_explicit_show) {
                    // STRICT: Must be explicitly shown by the trigger answer
                    isVisible = isExplicitlyShown;
                } else {
                    // LAX: Visible if parent answered (and not skipped) OR explicitly shown
                    isVisible = isExplicitlyShown || (!isSkipped && parentAnswered);
                }
            }

            if (isVisible) {
                totalQuestionsCount++;

                const val = sAnswers[q.id];
                let isAnswered = false;
                if (q.type === 'multiple_check_info') {
                    isAnswered = Array.isArray(val) && val.length > 0;
                } else {
                    isAnswered = val !== undefined && val !== null && val !== '';
                }

                if (isAnswered) {
                    answeredQuestionsCount++;
                }
            }
        });
    });

    const progress = totalQuestionsCount > 0 ? Math.round((answeredQuestionsCount / totalQuestionsCount) * 100) : 0;

    // 4. Render
    return `
    <div class="min-h-screen bg-gray-50 dark:bg-brand-black flex flex-col md:flex-row">
            <!-- Sidebar -->
            <aside class="w-full md:w-80 bg-white dark:bg-zinc-900/30 border-b md:border-b-0 md:border-r border-zinc-200 dark:border-zinc-800 p-6 flex flex-col shrink-0 backdrop-blur-md">
                <div class="mb-8 flex items-center gap-3">
                    <button onclick="actions.backToBusinessDashboard()" class="p-2 -ml-2 rounded-lg hover:bg-zinc-100 dark:hover:bg-zinc-800 text-zinc-400 hover:text-zinc-900 dark:hover:text-white transition-colors">
                        <i data-lucide="arrow-left" width="20"></i>
                    </button>
                    <span class="font-bold text-zinc-900 dark:text-white">Salud Empresarial</span>
                </div>
                
                <div class="mb-8">
                    <div class="flex justify-between text-sm font-bold text-zinc-500 dark:text-zinc-400 mb-2">
                        <span>Progreso de Secciones</span>
                        <span>${progress}%</span>
                    </div>
                    <div class="w-full bg-zinc-200 dark:bg-zinc-800 h-2 rounded-full overflow-hidden">
                        <div class="bg-brand-blue h-full transition-all duration-500 ease-out" style="width: ${progress}%"></div>
                    </div>
                </div>

                <nav class="space-y-1">
                    ${allSections.map((s, idx) => {
        const isActive = idx === sectionIndex;
        const isCompleted = (() => {
            const sAnswers = state.businessQuiz.answers[s.id] || {};
            if (!s.questions || s.questions.length === 0) return true;

            return s.questions.every(q => {
                // 1. Determine Visibility
                let isVisible = true;

                if (q.depends_on) {
                    const pId = q.depends_on;
                    const isExplicitlyShown = Object.keys(sAnswers).some(k => k.endsWith('_show') && sAnswers[k] === q.id);
                    const isSkipped = sAnswers[pId + '_skip_section'] === true;
                    const parentAnswered = sAnswers[pId] !== undefined && sAnswers[pId] !== null && sAnswers[pId] !== '';

                    if (q.requires_explicit_show) {
                        isVisible = isExplicitlyShown;
                    } else {
                        isVisible = isExplicitlyShown || (!isSkipped && parentAnswered);
                    }
                }

                if (!isVisible) return true;

                const val = sAnswers[q.id];
                if (q.type === 'multiple_check_info') {
                    return Array.isArray(val) && val.length > 0;
                }
                return val !== undefined && val !== null && val !== '';
            });
        })();
        return `
                            <div onclick="actions.goToBusinessSection(${idx})" class="w-full flex items-center gap-3 p-3 rounded-lg cursor-pointer hover:bg-zinc-100 dark:hover:bg-zinc-800 transition-all duration-300 ${isActive ? 'bg-sky-50 dark:bg-sky-900/20 text-sky-600 dark:text-sky-400 ring-1 ring-sky-200 dark:ring-sky-800' : 'text-zinc-500 dark:text-zinc-400'}">
                                <div class="w-6 h-6 rounded-full flex items-center justify-center text-[10px] ${isActive ? 'bg-sky-600 text-white' : (isCompleted ? 'bg-green-500 text-white' : 'bg-zinc-200 dark:bg-zinc-800')}">
                                    ${isCompleted ? '<i data-lucide="check" width="12"></i>' : idx + 1}
                                </div>
                                <div class="font-bold text-xs truncate">${s.title}</div>
                            </div>
                        `;
    }).join('')}
                </nav>
            </aside>

            <!-- Main Content -->
    <main class="flex-1 p-6 md:p-10 overflow-y-auto">
        <div class="max-w-3xl mx-auto">
            <header class="mb-8">
                <span class="text-xs font-bold uppercase tracking-wider text-sky-600 bg-sky-100 dark:bg-sky-900/30 px-3 py-1 rounded-full border border-sky-200 dark:border-sky-800">
                    Pilar ${sectionIndex}/${totalSections - 1}
                </span>
                <h2 class="text-3xl md:text-4xl font-black text-zinc-900 dark:text-white mt-4 mb-2">${section.title}</h2>
                <p class="text-zinc-600 dark:text-zinc-400">${section.description || 'Analiza tu negocio con los siguientes puntos.'}</p>
            </header>

            <div class="space-y-6">
                ${(section.questions || []).map((q, qIdx) => {
        // Conditional Logic
        if (q.type === 'conditional' || q.depends_on) {
            const parentId = q.depends_on;
            const parentAnswer = state.businessQuiz.answers[section.id]?.[parentId];

            let isExplicitlyShown = false;
            const sectionAnswers = state.businessQuiz.answers[section.id] || {};

            Object.keys(sectionAnswers).forEach(key => {
                if (key.endsWith('_show')) {
                    const val = sectionAnswers[key];
                    if (val === q.id) isExplicitlyShown = true;
                    if (Array.isArray(val) && val.includes(q.id)) isExplicitlyShown = true;
                }
            });

            let isSkippedByParent = false;
            if (parentId) {
                if (state.businessQuiz.answers[section.id]?.[parentId + '_skip_section'] === true) {
                    isSkippedByParent = true;
                }
            }

            if (q.requires_explicit_show && !isExplicitlyShown) return '';

            if (!isExplicitlyShown && (isSkippedByParent || parentAnswer === undefined)) return '';
        }

        const selectedValue = state.businessQuiz.answers[section.id]?.[q.id];
        const customTextValue = state.businessQuiz.answers[section.id]?.[q.id + '_custom'] || '';

        // MONEY TYPE HANDLER
        if (q.type === 'money') {
            const moneyValue = state.businessQuiz.answers[section.id]?.[q.id] || '';
            // Fetch Global Currency from 'intro' section
            const globalCurrencyIdx = state.businessQuiz.answers['intro']?.['i_moneda_preferida'];
            const globalCurrency = globalCurrencyIdx === 1 ? 'USD' : 'MXN';

            return `
                <div class="bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-800 rounded-2xl p-6 md:p-8 transition-all hover:border-zinc-300 dark:hover:border-zinc-700 shadow-sm">
                    <div class="mb-6">
                        <h3 class="font-bold text-lg text-zinc-900 dark:text-white">${q.text}</h3>
                    </div>
                    <div class="flex gap-4">
                        <div class="relative flex-1">
                            <span class="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-500 font-bold">$</span>
                            <input type="number" 
                                value="${moneyValue}" 
                                onchange="actions.answerBusiness('${section.id}', '${q.id}', this.value)" 
                                class="w-full bg-zinc-50 dark:bg-zinc-800 border border-zinc-200 dark:border-zinc-700 rounded-xl py-4 pl-10 pr-4 text-lg font-mono font-bold text-zinc-900 dark:text-white focus:ring-2 focus:ring-sky-500/20 focus:border-sky-500 outline-none transition-all" 
                                placeholder="0.00">
                        </div>
                        <div class="w-24 md:w-32 shrink-0 flex items-center justify-center bg-zinc-100 dark:bg-zinc-800 rounded-xl border border-zinc-200 dark:border-zinc-700">
                             <span class="font-black text-xl text-zinc-500 dark:text-zinc-400">
                                 ${globalCurrency}
                            </span>
                        </div>
                    </div>
                </div>
            `;
        }

        // PERCENTAGE TYPE SLIDER HANDLER (La Barra - Premium Refined)
        if (q.type === 'percentage') {
            const pctValue = state.businessQuiz.answers[section.id]?.[q.id] || 0;

            return `
                <div class="bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-800 rounded-3xl p-8 transition-all hover:border-sky-300/50 dark:hover:border-sky-500/30 shadow-sm relative overflow-hidden group">
                    <div class="mb-8 flex justify-between items-start">
                        <h3 class="font-bold text-xl text-zinc-900 dark:text-white max-w-lg leading-tight">${q.text}</h3>
                    </div>
                    
                    <div class="space-y-10">
                        <!-- Numeric Display: Focused, Premium and Centered -->
                        <div class="flex justify-center items-baseline gap-4 px-2">
                            <span class="text-6xl font-black text-zinc-900 dark:text-white tracking-tighter transition-all duration-300 transform scale-110 origin-center">${pctValue}</span>
                            <span class="text-3xl font-black text-zinc-400 dark:text-zinc-600 tracking-tighter">%</span>
                        </div>

                        <!-- Slider Container with Custom Track & Thumb -->
                        <div class="relative py-6 group/slider">
                            <style>
                                /* Scoped-like Custom Slider Styles */
                                input.premium-slider-${q.id} {
                                    -webkit-appearance: none;
                                    width: 100%;
                                    height: 12px;
                                    border-radius: 999px;
                                    outline: none;
                                    transition: all 0.3s ease;
                                    cursor: pointer;
                                    background: #f4f4f5; /* Light mode default */
                                }
                                .dark input.premium-slider-${q.id} {
                                    background: #27272a; /* Dark mode default */
                                }
                                input.premium-slider-${q.id}::-webkit-slider-thumb {
                                    -webkit-appearance: none;
                                    appearance: none;
                                    width: 24px;
                                    height: 24px;
                                    border-radius: 50%;
                                    background: #0ea5e9;
                                    border: 4px solid #fff;
                                    box-shadow: 0 4px 10px rgba(14, 165, 233, 0.4);
                                    transition: all 0.2s ease;
                                }
                                .dark input.premium-slider-${q.id}::-webkit-slider-thumb {
                                    border-color: #18181b;
                                }
                                input.premium-slider-${q.id}:hover::-webkit-slider-thumb {
                                    transform: scale(1.1);
                                    box-shadow: 0 6px 15px rgba(14, 165, 233, 0.5);
                                }
                                input.premium-slider-${q.id}:active::-webkit-slider-thumb {
                                    transform: scale(0.95);
                                }
                            </style>
                            <input type="range" 
                                min="0" 
                                max="100" 
                                step="1"
                                value="${pctValue}" 
                                class="premium-slider-${q.id} w-full"
                                oninput="this.closest('.space-y-10').querySelector('span:first-child').innerText = this.value; this.style.background = 'linear-gradient(to right, #0ea5e9 ' + this.value + '%, ' + (document.documentElement.classList.contains('dark') ? '#27272a' : '#f4f4f5') + ' ' + this.value + '%)'"
                                onchange="actions.answerBusiness('${section.id}', '${q.id}', this.value)" 
                                style="background: linear-gradient(to right, #0ea5e9 ${pctValue}%, ${pctValue === 0 ? 'transparent' : (document.documentElement.classList.contains('dark') ? '#27272a' : '#f4f4f5')} ${pctValue}%);"
                            >
                        </div>

                        <!-- Scale Markers: Minimal and Clean -->
                        <div class="flex justify-between px-1 relative">
                            <div class="flex flex-col items-center">
                                <div class="w-1 h-2 bg-zinc-200 dark:bg-zinc-800 rounded-full mb-2"></div>
                                <span class="text-[10px] font-black text-zinc-400 dark:text-zinc-600 uppercase tracking-widest">0%</span>
                            </div>
                            <div class="flex flex-col items-center">
                                <div class="w-1 h-2 bg-zinc-200 dark:bg-zinc-800 rounded-full mb-2"></div>
                                <span class="text-[10px] font-black text-zinc-400 dark:text-zinc-600 uppercase tracking-widest">50%</span>
                            </div>
                            <div class="flex flex-col items-center">
                                <div class="w-1 h-2 bg-zinc-200 dark:bg-zinc-800 rounded-full mb-2"></div>
                                <span class="text-[10px] font-black text-zinc-400 dark:text-zinc-600 uppercase tracking-widest">100%</span>
                            </div>
                        </div>
                    </div>
                </div>
            `;
        }

        return `
                                <div class="bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-800 rounded-2xl p-6 md:p-8 transition-all hover:border-zinc-300 dark:hover:border-zinc-700 shadow-sm">
                                    <div class="flex justify-between items-start mb-6">
                                        <h3 class="font-bold text-lg text-zinc-900 dark:text-white">${q.text}</h3>
                                        ${q.type === 'multiple_check_info' ? '<span class="text-[10px] font-black uppercase tracking-widest text-sky-500 bg-sky-100 dark:bg-sky-900/30 px-2 py-1 rounded-lg border border-sky-200 dark:border-sky-800">Selección Múltiple</span>' : ''}
                                    </div>
                                    <div class="flex flex-col gap-2">
                                        ${(q.options || []).map((opt, optIdx) => {
            let isSelected = false;
            if (q.type === 'multiple_check_info') {
                isSelected = Array.isArray(selectedValue) && selectedValue.includes(optIdx);
            } else {
                isSelected = selectedValue === optIdx;
            }

            const triggerSkip = opt.triggers_skip;
            const extra = {
                triggers_show: opt.triggers_show,
                triggers_skip_section: opt.triggers_skip_section
            };
            // Escape JSON for attribute
            const extraJson = JSON.stringify(extra).replace(/"/g, '&quot;');

            // Custom Text Input for "Otro"
            const showTextInput = isSelected && opt.placeholder;

            return `
                                                <div class="w-full">
                                                    <button onclick='actions.answerBusiness("${section.id}", "${q.id}", ${optIdx}, ${triggerSkip}, ${JSON.stringify(extra)})' class="w-full text-left p-4 rounded-xl text-sm font-medium transition-all duration-200 border-2 ${isSelected ? 'border-sky-500 bg-sky-500/10 text-zinc-900 dark:text-white shadow-[0_0_15px_rgba(14,165,233,0.1)]' : 'border-zinc-100 dark:border-zinc-800 bg-zinc-50 dark:bg-zinc-800/50 text-zinc-600 dark:text-zinc-400 hover:border-zinc-300 dark:hover:border-zinc-600 hover:bg-white dark:hover:bg-zinc-800 group'}">
                                                        <div class="flex items-center justify-between">
                                                            <span>${opt.text}</span>
                                                            ${isSelected ?
                    (q.type === 'multiple_check_info' ? '<i data-lucide="check-square" class="text-sky-500 w-5 h-5"></i>' : '<i data-lucide="check-circle-2" class="text-sky-500 w-5 h-5"></i>') :
                    (q.type === 'multiple_check_info' ? '<div class="w-5 h-5 rounded border-2 border-zinc-200 dark:border-zinc-700 group-hover:border-sky-500/50"></div>' : '<div class="w-5 h-5 rounded-full border-2 border-zinc-200 dark:border-zinc-700 group-hover:border-sky-500/50"></div>')}
                                                        </div>
                                                    </button>
                                                    ${showTextInput ? `
                                                        <div class="mt-2 pl-4 animate-fade-in">
                                                            <input type="text" 
                                                                value="${customTextValue}"
                                                                onchange="actions.answerBusinessText('${section.id}', '${q.id}', this.value)"
                                                                class="w-full bg-white dark:bg-zinc-800 border border-zinc-300 dark:border-zinc-700 rounded-lg p-3 text-sm focus:border-sky-500 focus:ring-1 focus:ring-sky-500 outline-none"
                                                                placeholder="${opt.placeholder}">
                                                        </div>
                                                    ` : ''}
                                                </div>
                                            `;
        }).join('')}
                                    </div>
                                </div>
                            `;
    }).join('')}
            </div>

            <div class="mt-10 flex justify-between items-center">
                <button onclick="actions.prevBusinessSection()" class="flex items-center gap-2 text-zinc-500 hover:text-zinc-800 dark:hover:text-white font-bold transition-colors ${sectionIndex === 0 ? 'invisible' : ''}">
                    <i data-lucide="arrow-left" width="20"></i> Anterior
                </button>
                <button type="button" onclick="actions.nextBusinessSection(this)" class="bg-sky-600 dark:bg-white text-white dark:text-black hover:bg-sky-500 dark:hover:bg-zinc-200 px-8 py-4 rounded-xl font-bold text-lg shadow-lg transition-all flex items-center gap-2 hover:translate-x-1">
                    ${sectionIndex < totalSections - 1 ? 'Siguiente Pilar' : 'Ver Resultados Empresariales'}
                    <i data-lucide="arrow-right" width="20"></i>
                </button>
            </div>
        </div>
    </main>
    </div>
    `;
};

// Connect legacy updateUI to store
// --- ACTIONS: DIAGNOSIS TOGGLE ---
actions.toggleDiagnosisDetails = (catId) => {
    if (!state.diagnosisExpanded) {
        state.diagnosisExpanded = {};
    }
    // Default is collapsed (false). So if undefined or false, current is false.
    const current = !!state.diagnosisExpanded[catId];
    state.diagnosisExpanded[catId] = !current;
    updateUI();
};

// --- ACTIONS: BUSINESS TOGGLE ---
actions.toggleBusinessDetails = (pillarId) => {
    if (!state.businessExpanded) {
        state.businessExpanded = {};
    }
    const current = !!state.businessExpanded[pillarId];
    state.businessExpanded[pillarId] = !current;
    updateUI();
};

actions.setClientCategory = (cat) => {
    if (cat === 'business' && !canAccessBusinessModule(state.user)) {
        state.clientCategory = 'personal';
        showToast('Tu plan es personal. El módulo de negocio no está disponible.', 'warning');
        updateUI();
        return;
    }
    state.clientCategory = cat;
    // Common tabs that exist in both categories
    const commonTabs = ['vision360', 'experts'];
    if (!commonTabs.includes(state.clientTab)) {
        state.clientTab = 'vision360';
    }
    updateUI();
};

actions.toggleStartModule = () => {
    state.startModuleExpanded = !state.startModuleExpanded;
    updateUI();
};

actions.toggleLimitedStartModule = () => {
    state.startModuleExpandedLimited = !state.startModuleExpandedLimited;
    updateUI();
};


// --- ACTIONS: CLIENT & PROVIDER MANAGEMENT ---
actions.addClient = async () => {
    if (!ensureBusinessEditAllowed()) return;
    const userId = await getUserIdFromSession();
    if (!userId) return;

    // Instead of creating empty row, open modal
    actions.showAddClientModal();
};

actions.saveClient = async (formData) => {
    if (!ensureBusinessEditAllowed()) return;
    const userId = await getUserIdFromSession();
    if (!userId) return;

    const payload = {
        user_id: userId,
        name: formData.name,
        phone: formData.phone || '',
        email: formData.email || '',
        city: formData.city || '',
        address: formData.address || '',
        payment_plan: formData.paymentPlan || '',
        profession: formData.profession || '',
        project: formData.project || '', // Proyecto/Servicio for Client
        start_date: formData.start_date || null,
        end_date: formData.end_date || null,
        notes: formData.notes || '',
        total_cost: 0,
        payments_amount: 0,
        payments_count: 0
    };

    const result = await persistBusinessEntity('CLIENTE', payload);
    actions.saveBusinessData();
    updateUI();

    // Clear form
    const form = document.getElementById('add-client-form');
    if (form) form.reset();

    let modal = document.getElementById('add-client-modal');
    if (modal) modal.close();

    if (result.error) {
        showToast('No se pudo conectar con el servidor; el cliente se guardó localmente.', 'warning');
    } else {
        showToast('Cliente agregado', 'success');
    }
};

actions.showAddClientModal = () => {
    if (!ensureBusinessEditAllowed()) return;
    let modal = document.getElementById('add-client-modal');
    if (modal) {
        modal.showModal();
        return;
    }

    // Create modal
    const html = `
    <dialog id="add-client-modal" class="modal bg-transparent p-0 w-full max-w-4xl backdrop:bg-black/50">
        <div class="bg-white dark:bg-zinc-900 rounded-3xl shadow-2xl border border-zinc-200 dark:border-zinc-700 p-8 w-full animate-zoom-in overflow-hidden">
            <div class="flex justify-between items-center mb-6 border-b border-zinc-100 dark:border-zinc-800 pb-4">
                <h3 class="text-2xl font-black text-brand-lime">Cliente</h3>
                <form method="dialog"><button class="text-zinc-400 hover:text-zinc-600 dark:hover:text-white transition-colors"><i data-lucide="x" width="24"></i></button></form>
            </div>
            
            <form id="add-client-form" onsubmit="event.preventDefault(); const fd = new FormData(this); const sel = fd.get('profession_select'); const cust = fd.get('profession_custom'); fd.append('profession', (sel === 'Otros' || sel === 'Otros Ingresos') && cust ? cust : sel); const data = Object.fromEntries(fd.entries()); actions.saveClient(data);">
                <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
                    <!-- Row 1 -->
                    <div class="col-span-1">
                         <label class="block text-xs font-bold text-zinc-500 mb-1 uppercase">CLIENTE</label>
                         <input type="text" name="name" required class="w-full bg-zinc-50 dark:bg-zinc-800 border border-zinc-200 dark:border-zinc-700 rounded-xl px-3 py-2 focus:outline-none focus:border-brand-lime transition-colors dark:text-white">
                    </div>
                    <div class="col-span-1">
                         <label class="block text-xs font-bold text-zinc-500 mb-1 uppercase">Telefono</label>
                         <input type="text" name="phone" class="w-full bg-zinc-50 dark:bg-zinc-800 border border-zinc-200 dark:border-zinc-700 rounded-xl px-3 py-2 focus:outline-none focus:border-brand-lime transition-colors dark:text-white">
                    </div>
                    <div class="col-span-1">
                         <label class="block text-xs font-bold text-zinc-500 mb-1 uppercase">Correo Electronico</label>
                         <input type="email" name="email" class="w-full bg-zinc-50 dark:bg-zinc-800 border border-zinc-200 dark:border-zinc-700 rounded-xl px-3 py-2 focus:outline-none focus:border-brand-lime transition-colors dark:text-white">
                    </div>
                    <div class="col-span-1">
                         <label class="block text-xs font-bold text-zinc-500 mb-1 uppercase">Ciudad</label>
                         <input type="text" name="city" class="w-full bg-zinc-50 dark:bg-zinc-800 border border-zinc-200 dark:border-zinc-700 rounded-xl px-3 py-2 focus:outline-none focus:border-brand-lime transition-colors dark:text-white">
                    </div>

                    <!-- Row 2 -->
                    <div class="col-span-1">
                         <label class="block text-xs font-bold text-zinc-500 mb-1 uppercase">Direccion</label>
                         <input type="text" name="address" class="w-full bg-zinc-50 dark:bg-zinc-800 border border-zinc-200 dark:border-zinc-700 rounded-xl px-3 py-2 focus:outline-none focus:border-brand-lime transition-colors dark:text-white">
                    </div>
                    <div class="col-span-1">
                         <label class="block text-xs font-bold text-zinc-500 mb-1 uppercase">Plan de Pago</label>
                         <input type="text" name="paymentPlan" class="w-full bg-zinc-50 dark:bg-zinc-800 border border-zinc-200 dark:border-zinc-700 rounded-xl px-3 py-2 focus:outline-none focus:border-brand-lime transition-colors dark:text-white">
                    </div>
                    <div class="col-span-1">
                         <label class="block text-xs font-bold text-zinc-500 mb-1 uppercase">Giro de Negocio / Profesion</label>
                         <select name="profession_select" 
                                 onchange="const val = this.value; const input = this.nextElementSibling; if(val === 'Otros' || val === 'Otros Ingresos'){ input.classList.remove('hidden'); input.focus(); } else { input.classList.add('hidden'); }"
                                 class="w-full bg-zinc-50 dark:bg-zinc-800 border border-zinc-200 dark:border-zinc-700 rounded-xl px-3 py-2 focus:outline-none focus:border-brand-lime transition-colors dark:text-white mb-2">
                             ${(state?.businessData?.config?.incomeCategories || ['Servicios', 'Productos']).map(c => `<option value="${c}">${c}</option>`).join('')}
                         </select>
                         <input type="text" name="profession_custom" placeholder="Especifique..." class="hidden w-full bg-white dark:bg-zinc-900 border border-brand-lime rounded-xl px-3 py-2 text-sm focus:outline-none animate-fade-in">
                    </div>
                    <div class="col-span-1">
                         <label class="block text-xs font-bold text-zinc-500 mb-1 uppercase">Proyecto/Servicio</label>
                         <input type="text" name="project" class="w-full bg-zinc-50 dark:bg-zinc-800 border border-zinc-200 dark:border-zinc-700 rounded-xl px-3 py-2 focus:outline-none focus:border-brand-lime transition-colors dark:text-white">
                    </div>

                    <!-- Row 3: Fechas -->
                    <div class="col-span-2">
                         <label class="block text-xs font-bold text-zinc-500 mb-1 uppercase">Fecha Inicial</label>
                         <input type="date" name="start_date" class="w-full bg-zinc-50 dark:bg-zinc-800 border border-zinc-200 dark:border-zinc-700 rounded-xl px-3 py-2 focus:outline-none focus:border-brand-lime transition-colors dark:text-white text-zinc-500">
                    </div>
                    <div class="col-span-2">
                         <label class="block text-xs font-bold text-zinc-500 mb-1 uppercase">Fecha Final</label>
                         <input type="date" name="end_date" class="w-full bg-zinc-50 dark:bg-zinc-800 border border-zinc-200 dark:border-zinc-700 rounded-xl px-3 py-2 focus:outline-none focus:border-brand-lime transition-colors dark:text-white text-zinc-500">
                    </div>

                    <!-- Row 4 -->
                    <div class="col-span-4">
                         <label class="block text-xs font-bold text-zinc-500 mb-1 uppercase">Notas</label>
                         <textarea name="notes" rows="2" class="w-full bg-zinc-50 dark:bg-zinc-800 border border-zinc-200 dark:border-zinc-700 rounded-xl px-3 py-2 focus:outline-none focus:border-brand-lime transition-colors dark:text-white"></textarea>
                    </div>
                </div>

                <div class="flex justify-end gap-4">
                     <form method="dialog"><button class="px-6 py-2 rounded-xl text-zinc-500 font-bold hover:bg-zinc-100 dark:hover:bg-zinc-800 transition-colors">Cancelar</button></form>
                     <button type="submit" class="px-8 py-2 rounded-xl bg-brand-lime text-black font-bold shadow-lg shadow-lime-500/20 hover:scale-105 transition-transform">Guardar Cliente</button>
                </div>
            </form>
        </div>
    </dialog>
    `;
    document.body.insertAdjacentHTML('beforeend', html);
    if (window.lucide) window.lucide.createIcons();
    document.getElementById('add-client-modal').showModal();
};

actions.updateClient = async (id, field, value) => {
    if (!ensureBusinessEditAllowed()) return;
    const userId = await getUserIdFromSession();
    if (!userId) return;

    const dbFields = {
        'name': 'name', 'project': 'project',
        'totalCost': 'total_cost', 'payments': 'payments_amount',
        'paymentsCount': 'payments_count', 'lastPaymentDate': 'last_payment_date',
        'phone': 'phone', 'email': 'email', 'city': 'city', 'address': 'address', 'paymentPlan': 'payment_plan', 'profession': 'profession', 'notes': 'notes',
        'isActive': 'is_active', 'startDate': 'start_date', 'endDate': 'end_date'
    };
    const column = dbFields[field] || field;

    const { error } = await supabaseClient
        .from('business_clients')
        .update({ [column]: value })
        .eq('id', id)
        .eq('user_id', userId);

    if (!error) {
        if (!state.businessData.clients) return;
        const item = state.businessData.clients.find(c => c.id == id);
        if (item) {
            item[field] = value;
            if (field === 'endDate') {
                item.isActive = value && value < new Date(Date.now() - new Date().getTimezoneOffset() * 60000).toISOString().split('T')[0] ? false : item.isActive;
            }
            updateUI(); // Optimistic update usually better, but here we confirm
        }
    }
};

actions.deleteClient = async (id) => {
    if (!ensureBusinessEditAllowed()) return;
    if (!confirm('¿Eliminar este cliente?')) return;
    const userId = await getUserIdFromSession();
    if (!userId) return;

    const { error } = await supabaseClient
        .from('business_clients')
        .delete()
        .eq('id', id)
        .eq('user_id', userId);

    if (!error) {
        state.businessData.clients = state.businessData.clients.filter(c => c.id != id);
        updateUI();
    }
};

actions.addProvider = async () => {
    if (!ensureBusinessEditAllowed()) return;
    const userId = await getUserIdFromSession();
    if (!userId) return;

    actions.showAddProviderModal();
};

actions.saveProvider = async (formData) => {
    if (!ensureBusinessEditAllowed()) return;
    const userId = await getUserIdFromSession();
    if (!userId) return;

    const payload = {
        user_id: userId,
        name: formData.name,
        phone: formData.phone || '',
        email: formData.email || '',
        city: formData.city || '',
        address: formData.address || '',
        payment_plan: formData.paymentPlan || '',
        profession: formData.profession || '',
        service: formData.service || '', // Service for Provider (legacy mapping used 'service', but plan said 'notes'? Plan said 'Service' exists. Image 3 has 'Notas' too)
        start_date: formData.start_date || null,
        end_date: formData.end_date || null,
        notes: formData.notes || '',
        total_cost: 0,
        paid_amount: 0,
        payments_count: 0
    };

    const result = await persistBusinessEntity('PROVEEDOR', payload);
    actions.saveBusinessData();
    updateUI();

    // Clear form
    const form = document.getElementById('add-provider-form');
    if (form) form.reset();

    let modal = document.getElementById('add-provider-modal');
    if (modal) modal.close();

    if (result.error) {
        showToast('No se pudo conectar con el servidor; el proveedor se guardó localmente.', 'warning');
    } else {
        showToast('Proveedor agregado', 'success');
    }
};

