actions.registerPayment = async (data) => {
    try {
        if (!ensureBusinessEditAllowed()) return;
        const amount = parseFloat(data.amount);
        if (!amount || amount <= 0) {
            alert('El monto debe ser mayor a 0');
            return;
        }

        const date = data.date || new Date(Date.now() - new Date().getTimezoneOffset() * 60000).toISOString().split('T')[0];

        // 1. Create Transaction
        // Assuming 'actions.addBusinessTransaction' handles the heavy lifting of saving to DB
        // We construct a payload similar to what the manual transaction form uses.

        const transactionPayload = {
            date: date,
            paymentDate: date,
            type: data.transactionType, // INCOME or EXPENSE
            category: data.category,
            amountMXN: amount, // Assuming MXN for now as per context
            amountUSD: 0,
            entityType: data.entityType,
            client: data.entityName,
            bank: data.bank || '',
            paymentMethod: data.method,
            status: 'Pagado',
            notes: data.notes || `Abono registrado manual para ${data.entityName}`
        };

        // We wrap this because addBusinessTransaction might be async and update UI heavily
        await actions.addBusinessTransaction(transactionPayload);

        // 2. Update Entity Balance
        let newTotal = 0;
        let newCount = 0;

        if (data.entityType === 'CLIENTE') {
            const client = state.businessData.clients.find(c => c.id === data.entityId);
            if (client) {
                const current = parseFloat(client.payments) || 0;
                newTotal = current + amount;
                newCount = (client.paymentsCount || 0) + 1;

                // Update Client in DB
                // actions.updateClient expects single field updates usually but let's see if we can chain or if we need custom logic
                // The current actions.updateClient is simple: update one field.
                // We should probably update 'payments' (payments_amount) and 'paymentsCount' and 'lastPaymentDate'.

                await actions.updateClient(data.entityId, 'payments', newTotal);
                await actions.updateClient(data.entityId, 'paymentsCount', newCount);
                await actions.updateClient(data.entityId, 'lastPaymentDate', date);
            }
        } else if (data.entityType === 'PROVEEDOR') {
            const provider = state.businessData.providers.find(p => p.id === data.entityId);
            if (provider) {
                const current = parseFloat(provider.paid) || 0;
                newTotal = current + amount;
                newCount = (provider.paymentsCount || 0) + 1;

                await actions.updateProvider(data.entityId, 'paid', newTotal);
                // Provider doesn't seem to have explicit 'paymentsCount' update exposed in UI but likely in DB logic?
                // The 'persistBusinessEntity' has 'payments_count' mapping.
                // But actions.updateProvider is same structure as updateClient.
                // We'll trust updateProvider handles the field if we pass the right key.
                // Looking at updateProvider (it's not fully shown in snippet but follows pattern)

                // We'll update 'paid' (mapped to paid_amount)
                // And let's assume we can update other fields if needed, or just stick to 'paid' for visual immediate fix. 
                // It's safer to update visual balance mostly.
            }
        }

        // Close Modal
        const modal = document.getElementById('add-payment-modal');
        if (modal) modal.close();

        showToast('Abono registrado y transacción creada exitosamente', 'success');

    } catch (error) {
        console.error('Error registering payment:', error);
        alert('Error al registrar el abono: ' + error.message);
    }
};

actions.updateProvider = async (id, field, value) => {
    if (!ensureBusinessEditAllowed()) return;
    const userId = await getUserIdFromSession();
    if (!userId) return;

    const dbFields = {
        'name': 'name', 'service': 'service',
        'totalCost': 'total_cost', 'paid': 'paid_amount',
        'paymentsCount': 'payments_count', 'lastPaymentDate': 'last_payment_date',
        'phone': 'phone', 'email': 'email', 'city': 'city', 'address': 'address', 'paymentPlan': 'payment_plan', 'profession': 'profession', 'notes': 'notes',
        'isActive': 'is_active', 'startDate': 'start_date', 'endDate': 'end_date'
    };
    const column = dbFields[field] || field;

    const { error } = await supabaseClient
        .from('business_providers')
        .update({ [column]: value })
        .eq('id', id)
        .eq('user_id', userId);

    if (!error) {
        if (!state.businessData.providers) return;
        const item = state.businessData.providers.find(p => p.id == id);
        if (item) {
            item[field] = value;
            if (field === 'endDate') {
                item.isActive = value && value < new Date(Date.now() - new Date().getTimezoneOffset() * 60000).toISOString().split('T')[0] ? false : item.isActive;
            }
            updateUI();
        }
    }
};

actions.deleteProvider = async (id) => {
    if (!ensureBusinessEditAllowed()) return;
    if (!confirm('¿Eliminar este proveedor?')) return;
    const userId = await getUserIdFromSession();
    if (!userId) return;

    const { error } = await supabaseClient
        .from('business_providers')
        .delete()
        .eq('id', id)
        .eq('user_id', userId);

    if (!error) {
        state.businessData.providers = state.businessData.providers.filter(p => p.id != id);
        updateUI();
    }
};

