actions.refreshTransactionEntityDatalist = (entityType = 'CLIENTE') => {
    const type = (entityType || 'CLIENTE').toUpperCase();
    const datalist = document.getElementById('entity-list');
    if (datalist) {
        datalist.innerHTML = buildBusinessEntityOptions(type);
    }
    const input = document.querySelector('#add-txn-modal input[name="client"]');
    if (input) {
        actions.handleTransactionEntityInput(input);
    }
};

actions.handleTransactionEntityInput = (inputElement) => {
    if (!inputElement) return;
    const rawValue = inputElement.value || '';
    const trimmedValue = rawValue.trim();
    const btn = document.getElementById('btn-add-entity');
    if (!btn) return;
    const typeSelect = document.getElementById('entity-type-select');
    const entityType = (typeSelect ? typeSelect.value : 'CLIENTE').toUpperCase();
    const exists = businessEntityExists(entityType, trimmedValue);
    btn.disabled = !trimmedValue || exists;
};

actions.transactionEntityExists = (entityType, name) => businessEntityExists(entityType, name);

actions.createTransactionEntity = async () => {
    if (!ensureBusinessEditAllowed()) return;
    const input = document.querySelector('#add-txn-modal input[name="client"]');
    if (!input) return;
    const rawValue = input.value.trim();
    if (!rawValue) {
        showToast('Ingresa un nombre válido.', 'warning');
        return;
    }
    const typeSelect = document.getElementById('entity-type-select');
    const entityType = (typeSelect ? typeSelect.value : 'CLIENTE').toUpperCase();
    if (businessEntityExists(entityType, rawValue)) {
        showToast(`${entityType === 'PROVEEDOR' ? 'Proveedor' : 'Cliente'} ya existe.`, 'info');
        actions.handleTransactionEntityInput(input);
        return;
    }
    const userId = await getUserIdFromSession();
    if (!userId) {
        showToast('Sesión expirada. Inicia sesión de nuevo.', 'warning');
        return;
    }

    const payload = {
        user_id: userId,
        name: rawValue,
        total_cost: 0,
        payments_count: 0
    };
    if (entityType === 'CLIENTE') {
        payload.project = '';
        payload.payments_amount = 0;
    } else {
        payload.service = '';
        payload.paid_amount = 0;
    }

    const result = await persistBusinessEntity(entityType, payload);
    actions.saveBusinessData();
    actions.refreshTransactionEntityDatalist(entityType);
    input.value = rawValue;
    input.focus();
    actions.handleTransactionEntityInput(input);

    if (result.error) {
        showToast(`No se pudo crear en el servidor; el ${entityType === 'PROVEEDOR' ? 'proveedor' : 'cliente'} se guardó localmente.`, 'warning');
    } else {
        showToast(`${entityType === 'PROVEEDOR' ? 'Proveedor' : 'Cliente'} guardado con éxito.`, 'success');
    }
};


// --- ACTIONS: PERSONAL TRANSACTIONS ---
actions.addPersonalTransaction = (transaction) => {
    if (state.coacheeViewMode === 'readonly') {
        showToast('Vista solo lectura para coachees.', 'warning');
        return;
    }
    // Validation
    if ((!transaction.amountMXN && !transaction.amountUSD) ||
        (Number(transaction.amountMXN) <= 0 && Number(transaction.amountUSD) <= 0)) {
        showToast('Debes ingresar un monto válido (MXN o USD)', 'warning');
        return;
    }
    if (!transaction.date) {
        showToast('La fecha es requerida', 'warning');
        return;
    }

    if (!state.transactions) state.transactions = [];

    const newTxn = {
        id: (typeof crypto !== 'undefined' && crypto.randomUUID) ? crypto.randomUUID() : 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) { var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8); return v.toString(16); }),
        ...transaction, // date, type, category, amountMXN, amountUSD, entityType, client, bank, paymentMethod, notes
        status: transaction.status || 'Pendiente',
        createdAt: new Date().toISOString()
    };

    state.transactions.push(newTxn);

    // Save to Supabase
    (async () => {
        const userId = await getUserIdFromSession();
        if (userId) {
            const { error } = await supabaseClient
                .from('personal_transactions')
                .insert({
                    id: newTxn.id,
                    user_id: userId,
                    date: newTxn.date || null,
                    ...(newTxn.paymentDate ? { payment_date: newTxn.paymentDate } : {}),
                    type: (newTxn.type === 'INCOME') ? 'INCOME' : 'EXPENSE',
                    category: newTxn.category,
                    amount_mxn: newTxn.amountMXN,
                    amount_usd: newTxn.amountUSD,
                    payment_method: newTxn.paymentMethod,
                    bank: newTxn.bank,
                    status: newTxn.status,
                    notes: newTxn.notes,
                    ...(newTxn.client ? { client: newTxn.client } : {}),
                    // Map subtypes to client_type
                    ...(
                        (newTxn.type !== 'INCOME' && newTxn.type !== 'EXPENSE')
                            ? { client_type: newTxn.type }
                            : (newTxn.clientType ? { client_type: newTxn.clientType } : {})
                    )
                });

            if (error) {
                console.error('Error saving transaction to Supabase:', error);
                showToast('Error al guardar en la nube (guardado localmente)', 'error');
            } else {
                console.log('Transaction saved to Supabase');
            }
        }
    })();

    updateUI();
    const modal = document.getElementById('add-personal-txn-modal');
    if (modal) modal.close();
    showToast('Transacción agregada', 'success');
};

actions.deletePersonalTransaction = async (id) => {
    if (state.coacheeViewMode === 'readonly') {
        showToast('Vista solo lectura para coachees.', 'warning');
        return;
    }
    if (!await actions.confirmDeleteTransaction('¿Estás seguro de eliminar esta transacción?')) return;

    // Optimistic update
    state.transactions = state.transactions.filter(t => t.id !== id);
    updateUI();

    const userId = await getUserIdFromSession();
    if (userId) {
        const { error } = await supabaseClient
            .from('personal_transactions')
            .delete()
            .eq('id', id)
            .eq('user_id', userId);

        if (error) {
            console.error('Error deleting transaction from Supabase:', error);
            showToast('Error al eliminar de la nube', 'error');
            // Optionally revert state change here
        }
    }
};



actions.updatePersonalTransactionStatus = async (id, newStatus) => {
    if (state.coacheeViewMode === 'readonly') {
        showToast('Vista solo lectura para coachees.', 'warning');
        return;
    }
    const txn = (state.transactions || []).find(t => t.id === id);
    if (!txn) return;

    const previous = txn.status || 'Pendiente';
    txn.status = newStatus || 'Pendiente';
    updateUI();

    const userId = await getUserIdFromSession();
    if (!userId) {
        showToast('Inicia sesión para actualizar transacciones.', 'warning');
        return;
    }

    try {
        const { error } = await supabaseClient
            .from('personal_transactions')
            .update({ status: txn.status })
            .eq('id', id)
            .eq('user_id', userId);

        if (error) throw error;
    } catch (error) {
        console.error('Error updating transaction status:', error);
        txn.status = previous;
        updateUI();
        showToast('No se pudo actualizar el estado.', 'warning');
    }
};

actions.handlePersonalTransactionSubmit = (event) => {
    event.preventDefault();
    if (state.coacheeViewMode === 'readonly') {
        showToast('Vista solo lectura para coachees.', 'warning');
        return;
    }
    const formData = new FormData(event.target);
    const rawCategory = formData.get('category');
    const customCategory = formData.get('customCategory');

    // Get amount and currency
    const amount = parseFloat(formData.get('amount') || 0);
    const currency = formData.get('currency') || 'MXN';

    // Convert to separate MXN and USD fields for backward compatibility
    const amountMXN = currency === 'MXN' ? amount : 0;
    const amountUSD = currency === 'USD' ? amount : 0;

    actions.addPersonalTransaction({
        date: formData.get('date'),
        paymentDate: formData.get('paymentDate'), // New
        type: formData.get('type'),
        category: rawCategory === 'Otros' && customCategory ? customCategory : rawCategory,
        amountMXN: amountMXN,
        amountUSD: amountUSD,
        currency: currency, // Store currency for reference
        paymentMethod: formData.get('paymentMethod'),
        paymentMethod: formData.get('paymentMethod'),
        bank: formData.get('bank') === 'Otro' ? formData.get('customBank') : formData.get('bank'),
        status: formData.get('status') || 'Pendiente',
        notes: formData.get('notes'),
        client: formData.get('client'), // New
        clientType: formData.get('clientType') // New
    });
};

