actions.fetchPersonalTransactions = async () => {
    const userId = await getEffectiveUserId();
    if (!userId) return;

    const { data, error } = await supabaseClient
        .from('personal_transactions')
        .select('*')
        .eq('user_id', userId)
        .order('date', { ascending: false });

    if (error) {
        console.error('Error fetching personal transactions:', error);
        state.transactions = [];
        return;
    }

    if (data) {
        state.transactions = data.map(t => ({
            id: t.id,
            date: t.date,
            paymentDate: t.payment_date,
            type: t.type,
            category: t.category,
            amountMXN: parseFloat(t.amount_mxn) || 0,
            amountUSD: parseFloat(t.amount_usd) || 0,
            paymentMethod: t.payment_method,
            bank: t.bank,
            status: t.status || 'Pendiente',
            notes: t.notes,
            client: t.client,
            clientType: t.client_type,
            createdAt: t.created_at
        }));
        updateUI();
    }
};

actions.loadPersonalTransactions = () => {
    // Forward to Supabase fetch
    if (actions.fetchPersonalTransactions) {
        actions.fetchPersonalTransactions();
    } else {
        console.warn('actions.fetchPersonalTransactions not found');
    }
};

