actions.updatePersonalTransactionCategories = (type) => {
    // Reuse CONST_BUDGET_CATEGORIES from legacy.js
    // incomes: [...], fixed: [...], variable: [...], debt: [...], savings: [...]
    let categories = [];
    const config = ensurePersonalConfig();
    const catConfig = config.categories || {};
    if (type === 'INCOME') {
        categories = catConfig.incomes || CONST_BUDGET_CATEGORIES.incomes || [];
    } else if (type === 'FIXED') {
        categories = catConfig.fixed || CONST_BUDGET_CATEGORIES.fixed || [];
    } else if (type === 'VARIABLE') {
        categories = catConfig.variable || CONST_BUDGET_CATEGORIES.variable || [];
    } else if (type === 'DEBT') {
        categories = catConfig.debt || CONST_BUDGET_CATEGORIES.debt || [];
    } else if (type === 'SAVINGS') {
        categories = catConfig.savings || CONST_BUDGET_CATEGORIES.savings || [];
    } else {
        // Fallback or default
        categories = [];
    }

    // Sort and Unique
    categories = [...new Set(categories)].sort();

    const select = document.getElementById('personal-cat-select');
    if (select) {
        select.innerHTML = categories.map(c => `<option value="${c}">${c}</option>`).join('');
        // Reset custom input visibility
        const customInput = document.getElementById('personal-cat-custom');
        if (customInput) customInput.classList.add('hidden');
    }
};

