actions.openEditPersonalTransaction = (id) => {
    if (state.coacheeViewMode === 'readonly') {
        showToast('Vista solo lectura para coachees.', 'warning');
        return;
    }
    const txn = (state.transactions || []).find(t => t.id === id);
    if (!txn) return;

    const modal = document.getElementById('edit-personal-txn-modal');
    if (!modal) return;
    const form = modal.querySelector('form');
    if (!form) return;

    // Fill basic fields
    form.querySelector('[name=id]').value = txn.id;
    form.querySelector('[name=date]').value = txn.date || '';
    form.querySelector('[name=paymentDate]').value = txn.paymentDate || '';

    // Determine display type (subtype stored in clientType)
    const displayType = txn.clientType || txn.type;
    const typeSelect = form.querySelector('[name=type]');
    if (typeSelect) typeSelect.value = displayType;

    // Populate category options then set current value
    actions.updateEditPersonalTransactionCategories(displayType, txn.category);

    // Amount + currency
    const amountInput = form.querySelector('[name=amount]');
    const currencyInput = form.querySelector('[name=currency]');
    const btnMXN = document.getElementById('edit-personal-btn-mxn');
    const btnUSD = document.getElementById('edit-personal-btn-usd');
    if (txn.amountUSD > 0 && !txn.amountMXN) {
        if (amountInput) amountInput.value = txn.amountUSD;
        if (currencyInput) currencyInput.value = 'USD';
        if (btnUSD) { btnUSD.classList.add('bg-white', 'dark:bg-zinc-900', 'shadow-sm'); btnUSD.classList.remove('text-zinc-400', 'dark:text-zinc-500'); }
        if (btnMXN) { btnMXN.classList.remove('bg-white', 'dark:bg-zinc-900', 'shadow-sm'); btnMXN.classList.add('text-zinc-400', 'dark:text-zinc-500'); }
    } else {
        if (amountInput) amountInput.value = txn.amountMXN || 0;
        if (currencyInput) currencyInput.value = 'MXN';
        if (btnMXN) { btnMXN.classList.add('bg-white', 'dark:bg-zinc-900', 'shadow-sm'); btnMXN.classList.remove('text-zinc-400', 'dark:text-zinc-500'); }
        if (btnUSD) { btnUSD.classList.remove('bg-white', 'dark:bg-zinc-900', 'shadow-sm'); btnUSD.classList.add('text-zinc-400', 'dark:text-zinc-500'); }
    }

    // Status
    const statusSelect = form.querySelector('[name=status]');
    if (statusSelect) statusSelect.value = txn.status || 'Pendiente';

    // Bank
    const bankSelect = form.querySelector('[name=bank]');
    const customBankInput = form.querySelector('[name=customBank]');
    if (bankSelect) {
        const config = ensurePersonalConfig();
        const knownBanks = normalizePersonalConfigList(config.banks, DEFAULT_PERSONAL_BANKS);
        const fallbackBank = knownBanks[0] || 'Otro';
        if (txn.bank && !knownBanks.includes(txn.bank)) {
            bankSelect.value = 'Otro';
            if (customBankInput) {
                customBankInput.classList.remove('hidden');
                customBankInput.value = txn.bank;
            }
        } else {
            bankSelect.value = txn.bank || fallbackBank;
            if (customBankInput) customBankInput.classList.add('hidden');
        }
    }

    // Payment method
    const pmSelect = form.querySelector('[name=paymentMethod]');
    if (pmSelect) pmSelect.value = txn.paymentMethod || 'Transferencia';

    // Notes
    const notesArea = form.querySelector('[name=notes]');
    if (notesArea) notesArea.value = txn.notes || '';

    modal.showModal();
};

actions.handlePersonalTransactionUpdate = async (event) => {
    event.preventDefault();
    if (state.coacheeViewMode === 'readonly') {
        showToast('Vista solo lectura para coachees.', 'warning');
        return;
    }
    const formData = new FormData(event.target);
    const id = formData.get('id');
    const txn = (state.transactions || []).find(t => t.id === id);
    if (!txn) return;

    const rawCategory = formData.get('category');
    const customCategory = formData.get('customCategory');
    const category = rawCategory === 'Otros' && customCategory ? customCategory : rawCategory;
    const amount = parseFloat(formData.get('amount') || 0);
    const currency = formData.get('currency') || 'MXN';
    const displayType = formData.get('type');
    const bankVal = formData.get('bank') === 'Otro' ? formData.get('customBank') : formData.get('bank');

    // Update local state
    txn.date = formData.get('date');
    txn.paymentDate = formData.get('paymentDate') || null;
    txn.category = category;
    txn.amountMXN = currency === 'MXN' ? amount : 0;
    txn.amountUSD = currency === 'USD' ? amount : 0;
    txn.status = formData.get('status') || 'Pendiente';
    txn.bank = bankVal;
    txn.paymentMethod = formData.get('paymentMethod');
    txn.notes = formData.get('notes') || '';
    // Handle type/subtype
    if (displayType === 'INCOME') {
        txn.type = 'INCOME';
        txn.clientType = null;
    } else {
        txn.type = 'EXPENSE';
        txn.clientType = displayType;
    }

    updateUI();
    document.getElementById('edit-personal-txn-modal').close();

    const userId = await getUserIdFromSession();
    if (!userId) { showToast('Inicia sesión para guardar cambios.', 'warning'); return; }

    try {
        const { error } = await supabaseClient
            .from('personal_transactions')
            .update({
                date: txn.date,
                payment_date: txn.paymentDate || null,
                type: txn.type,
                client_type: txn.clientType || null,
                category: txn.category,
                amount_mxn: txn.amountMXN,
                amount_usd: txn.amountUSD,
                payment_method: txn.paymentMethod,
                bank: txn.bank,
                status: txn.status,
                notes: txn.notes || null
            })
            .eq('id', id)
            .eq('user_id', userId);
        if (error) throw error;
        showToast('Transacción actualizada.', 'success');
    } catch (err) {
        console.error('Error updating personal transaction:', err);
        showToast('No se pudo sincronizar con el servidor.', 'warning');
    }
};

