actions.updateEditTransactionCategories = (type, selectedCategory) => {
    const { config } = state.businessData;
    if (!config) return;

    let categories = [];
    if (type === 'INCOME') categories = config.incomeCategories || [];
    else if (type === 'EXPENSE') categories = config.expenseCategories || [];
    else if (type === 'COST') categories = config.costCategories || [];

    // Include current category if not already in list
    const allCategories = selectedCategory && !categories.includes(selectedCategory)
        ? [...categories, selectedCategory]
        : categories;

    const select = document.getElementById('edit-cat-select');
    if (select) {
        select.innerHTML = allCategories.map(c => `<option value="${c}">${c}</option>`).join('');
        if (selectedCategory) select.value = selectedCategory;
    }
};

actions.refreshEditTransactionEntityDatalist = (entityType) => {
    const datalist = document.getElementById('edit-entity-list');
    if (datalist) datalist.innerHTML = buildBusinessEntityOptions(entityType);
};

actions.openEditBusinessTransaction = (id) => {
    if (!ensureBusinessEditAllowed()) return;
    const txn = state.businessData.transactions.find(t => t.id === id);
    if (!txn) return;

    const modal = document.getElementById('edit-txn-modal');
    if (!modal) return;
    const form = modal.querySelector('form');
    if (!form) return;

    form.querySelector('[name=id]').value = txn.id;
    form.querySelector('[name=date]').value = txn.date || '';
    form.querySelector('[name=paymentDate]').value = txn.paymentDate || '';

    const typeSelect = form.querySelector('[name=type]');
    if (typeSelect) typeSelect.value = txn.type || 'INCOME';

    // Populate categories for the current type and pre-select current category
    actions.updateEditTransactionCategories(txn.type || 'INCOME', txn.category);

    form.querySelector('[name=amountMXN]').value = txn.amountMXN || '';
    form.querySelector('[name=amountUSD]').value = txn.amountUSD || '';

    const entityTypeSelect = document.getElementById('edit-entity-type-select');
    if (entityTypeSelect) {
        entityTypeSelect.value = txn.entityType || 'CLIENTE';
        actions.refreshEditTransactionEntityDatalist(txn.entityType || 'CLIENTE');
    }
    form.querySelector('[name=client]').value = txn.client || '';

    const bankSelect = form.querySelector('[name=bank]');
    if (bankSelect) bankSelect.value = txn.bank || '';

    const pmSelect = form.querySelector('[name=paymentMethod]');
    if (pmSelect) pmSelect.value = txn.paymentMethod || '';

    const statusSelect = form.querySelector('[name=status]');
    if (statusSelect) statusSelect.value = txn.status || 'Pendiente';

    const notesArea = form.querySelector('[name=notes]');
    if (notesArea) notesArea.value = txn.notes || '';

    modal.showModal();
};

actions.handleBusinessTransactionUpdate = async (event) => {
    event.preventDefault();
    if (!ensureBusinessEditAllowed()) return;
    const formData = new FormData(event.target);
    const id = formData.get('id');
    const txn = state.businessData.transactions.find(t => t.id === id);
    if (!txn) return;

    const updates = {
        date: formData.get('date'),
        paymentDate: formData.get('paymentDate') || null,
        type: formData.get('type'),
        category: formData.get('category'),
        amountMXN: parseFloat(formData.get('amountMXN') || 0),
        amountUSD: parseFloat(formData.get('amountUSD') || 0),
        entityType: formData.get('entityType'),
        client: formData.get('client') || '',
        bank: formData.get('bank'),
        paymentMethod: formData.get('paymentMethod'),
        status: formData.get('status') || 'Pendiente',
        notes: formData.get('notes') || ''
    };

    // Apply updates to state
    Object.assign(txn, updates);
    actions.saveBusinessData();
    updateUI();
    document.getElementById('edit-txn-modal').close();

    const userId = await getUserIdFromSession();
    if (!userId) { showToast('Inicia sesión para guardar cambios.', 'warning'); return; }

    try {
        const { error } = await supabaseClient
            .from('business_transactions')
            .update({
                date: updates.date,
                payment_date: updates.paymentDate,
                type: updates.type,
                category: updates.category,
                amount_mxn: updates.amountMXN,
                amount_usd: updates.amountUSD,
                entity_type: updates.entityType,
                client_provider_name: updates.client,
                bank: updates.bank,
                payment_method: updates.paymentMethod,
                status: updates.status,
                notes: updates.notes || null
            })
            .eq('id', id)
            .eq('user_id', userId);
        if (error) throw error;
        showToast('Transacción actualizada.', 'success');
    } catch (err) {
        console.error('Error updating business transaction:', err);
        showToast('No se pudo sincronizar con el servidor.', 'warning');
    }
};

