actions.toggleAnnualCurrency = (currency) => {
    const isMXN = currency === 'MXN';

    // 1. Update Buttons
    const btnMXN = document.getElementById('btn-currency-mxn');
    const btnUSD = document.getElementById('btn-currency-usd');

    if (btnMXN && btnUSD) {
        if (isMXN) {
            btnMXN.className = "px-4 py-1 rounded-md text-sm font-bold bg-white dark:bg-zinc-700 shadow-sm text-zinc-900 dark:text-white transition-all";
            btnUSD.className = "px-4 py-1 rounded-md text-sm font-bold text-zinc-500 dark:text-zinc-400 hover:text-zinc-900 dark:hover:text-white transition-all";
        } else {
            btnMXN.className = "px-4 py-1 rounded-md text-sm font-bold text-zinc-500 dark:text-zinc-400 hover:text-zinc-900 dark:hover:text-white transition-all";
            btnUSD.className = "px-4 py-1 rounded-md text-sm font-bold bg-white dark:bg-zinc-700 shadow-sm text-zinc-900 dark:text-white transition-all";
        }
    }

    // 2. Toggle Columns
    const mxnCols = document.querySelectorAll('.col-mxn');
    const usdCols = document.querySelectorAll('.col-usd');
    const groupHeaders = document.querySelectorAll('.group-header');

    if (isMXN) {
        mxnCols.forEach(el => el.classList.remove('hidden'));
        usdCols.forEach(el => el.classList.add('hidden'));
        groupHeaders.forEach(el => el.setAttribute('colspan', '1'));
    } else {
        mxnCols.forEach(el => el.classList.add('hidden'));
        usdCols.forEach(el => el.classList.remove('hidden'));
        groupHeaders.forEach(el => el.setAttribute('colspan', '1'));
    }
};

