actions.fetchPlanningSettings = async () => {
    state.planningSettingsLoading = true;
    const user = state.user || (await actions.getAuthenticatedUser());
    if (!user) {
        state.planningSettingsLoading = false;
        return;
    }

    const roleKey = normalizeRoleValue(user?.role) || 'client';
    const isCoach = isCoachRole(roleKey);
    const fallbackCoachId = (state.originalUser && isCoachRole(state.originalUser.role)) ? state.originalUser.id : null;
    const planningOwnerId = isCoach ? user.id : (user.coach_id || user.coachId || fallbackCoachId || null);
    if (!planningOwnerId) {
        state.planningSettings = { columns: [], coach_id: null, missingCoach: true };
        state.planningSettingsLoading = false;
        updateUI();
        return;
    }

    let { data, error } = await supabaseClient
        .from('planning_settings')
        .select('*')
        .eq('coach_id', planningOwnerId)
        .single();

    const defaults = {
        coach_id: planningOwnerId,
        columns: [
            { id: 'todo', title: 'Por hacer' },
            { id: 'in_progress', title: 'En progreso' },
            { id: 'done', title: 'Hecho' }
        ]
    };

    if (!data) {
        if (isCoach) {
            // Try to insert defaults
            const res = await supabaseClient.from('planning_settings').insert(defaults).select().single();
            if (res.data) data = res.data;
            else data = defaults;
        } else {
            data = defaults;
        }
    }
    state.planningSettings = data;
    state.planningSettingsLoading = false;
    if (state.planningRecovering) state.planningRecovering = false;
    updateUI();
};

actions.fetchPlanningTasks = async () => {
    state.planningTasksLoading = true;
    const user = state.user || (await actions.getAuthenticatedUser());
    if (!user) {
        state.planningTasksLoading = false;
        return;
    }

    const roleKey = normalizeRoleValue(user?.role) || 'client';
    const isCoach = isCoachRole(roleKey);
    const fallbackCoachId = (state.originalUser && isCoachRole(state.originalUser.role)) ? state.originalUser.id : null;
    const planningOwnerId = isCoach ? user.id : (user.coach_id || user.coachId || fallbackCoachId || null);
    if (!planningOwnerId) {
        state.planningTasks = [];
        state.planningTasksLoading = false;
        updateUI();
        return;
    }

    const { data, error } = await supabaseClient
        .from('planning_tasks')
        .select('*')
        .eq('coach_id', planningOwnerId)
        .order('created_at', { ascending: false });

    if (error) console.error("Error fetching tasks:", error);
    const visibleTasks = isCoach ? (data || []) : filterPlanningTasksForUser((data || []), user);
    state.planningTasks = visibleTasks.map(task => ({
        ...task,
        subtasks: normalizePlanningChecklists(task)
    }));
    state.planningTasksLoading = false;
    if (state.planningRecovering) state.planningRecovering = false;
    updateUI();
};

actions.openTaskModal = (colId) => {
    state.currentColumnId = colId;
    const modal = ensureTaskModal();
    if (modal) {
        // Reset form
        const form = modal.querySelector('form');
        if (form) form.reset();

        // Load coachees for the select
        const select = modal.querySelector('select[name="clientId"]');
        if (select) {
            select.innerHTML = '<option value="">(Opcional) Asignar a Cliente...</option>';
            (state.coachees || []).forEach(c => {
                const option = document.createElement('option');
                option.value = c.id;
                option.textContent = c.name;
                select.appendChild(option);
            });
        }

        modal.showModal();
    }
};

