// --- NEW ACTION: LOAD BUSINESS DATA FOR VISION 360 ---
actions.loadBusinessData = async () => {
    if (state.businessData.loading || state.businessData.loaded) return;

    console.log("Loading Business Data for Vision 360...");
    state.businessData.loading = true;

    try {
        const userId = await getEffectiveUserId();
        if (!userId) return;

        // Fetch Transactions
        const { data: transactions, error } = await supabaseClient
            .from('business_transactions')
            .select('*')
            .eq('user_id', userId)
            .order('date', { ascending: false });

        if (error) {
            console.error("Error loading business transactions:", error);
            // If table doesn't exist, we might be using 'transactions' with a type filter?
            // But let's assume business_transactions based on module separation.
            throw error;
        }

        console.log("Business Data Loaded. Count:", transactions ? transactions.length : 0);

        if (transactions) {
            // MAP DATA CORRECTLY
            state.businessData.transactions = transactions.map(t => ({
                id: t.id,
                date: t.date,
                paymentDate: t.payment_date,
                type: t.type,
                category: t.category,
                amountMXN: parseFloat(t.amount_mxn || 0),
                amountUSD: parseFloat(t.amount_usd || 0),
                entityType: t.entity_type,
                client: t.client_provider_name,
                // Fix for missing UI labels
                clientName: t.client_provider_name,
                providerName: t.client_provider_name,
                description: t.notes || t.client_provider_name || t.category || 'Movimiento registrado',
                bank: t.bank,
                paymentMethod: t.payment_method,
                status: t.status || 'Pendiente',
                notes: t.notes
            }));

            if (state.businessData.transactions.length > 0) {
                console.log("Mapped First Transaction:", state.businessData.transactions[0]);
            }
        }

        state.businessData.loaded = true;
        updateUI();

    } catch (e) {
        console.error("Exception loading business data:", e);
    } finally {
        state.businessData.loading = false;
    }
};

