actions.submitAssignCoach = async (form) => {
    const submitBtn = form.querySelector('button[type="submit"]');
    const originalText = submitBtn.innerHTML;
    submitBtn.innerHTML = '<i data-lucide="loader-2" class="w-4 h-4 animate-spin"></i> Enviando...';
    submitBtn.disabled = true;

    try {
        const coachEmail = form.coachEmail.value.trim().toLowerCase();

        const { data: profiles, error: profileError } = await supabaseClient
            .from('profiles')
            .select('id, role')
            .eq('email', coachEmail);

        if (profileError) {
            console.error("Error finding coach:", profileError);
            showToast("Ocurrió un error al buscar al coach.", "error");
            return;
        }

        const coach = profiles.find(p => p.role === 'coach');
        if (!coach) {
            showToast("No se encontró ningún coach registrado con ese correo.", "error");
            return;
        }

        const userId = await getEffectiveUserId();
        if (!userId) return;

        const relationshipData = {
            coach_id: coach.id,
            coachee_id: userId,
            status: 'pending',
            updated_at: new Date().toISOString()
        };
        const { error: relError } = await supabaseClient
            .from('coaching_relationships')
            .upsert(relationshipData, { onConflict: 'coach_id,coachee_id' });

        if (relError) {
            console.error("Error upserting relationship:", relError);
            showToast("Hubo un error al enviar la solicitud.", "error");
            return;
        }

        if (state.user) {
            state.user.hasPendingCoach = true;
        }

        document.getElementById('assign-coach-modal').close();
        showToast("Solicitud enviada al coach exitosamente.", "success");
        updateUI();

    } catch (error) {
        console.error("Unexpected error in submitAssignCoach:", error);
        showToast("Hubo un error inesperado.", "error");
    } finally {
        submitBtn.innerHTML = originalText;
        submitBtn.disabled = false;
        if (window.lucide) window.lucide.createIcons();
    }
};

actions.removeCoach = async () => {
    const confirmed = await actions.confirmAdminAction('¿Estás seguro que deseas eliminar a tu coach actual? No podrás deshacer esta acción.');
    if (!confirmed) return;

    try {
        const userId = await getEffectiveUserId();
        if (!userId) return;

        const { error } = await supabaseClient
            .from('coaching_relationships')
            .delete()
            .eq('coachee_id', userId);

        if (error) {
            console.error("Error removing coach:", error);
            showToast("Ocurrió un error al eliminar a tu coach.", "error");
            return;
        }

        if (state.user) {
            state.user.hasActiveCoach = false;
        }

        showToast("Coach eliminado exitosamente.", "success");
        updateUI();
    } catch (e) {
        console.error("Exception removing coach:", e);
        showToast("Error inesperado al eliminar coach.", "error");
    }
};

